window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["TN"] = {"code":"TN","name":"Tennessee","agency":"Tennessee DOS","agencyShort":"DOS","handbook":"https://www.tn.gov/safety/driver-services/commercial-driver-license.html","links":{},"en":[{"q":"On Tennessee's federal and state highway system, what is the maximum legal width of a vehicle including its load, without a permit?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Tennessee law allows a vehicle or load up to 8 feet 6 inches (102 inches) wide on the federal and state highway system; 'regular' roads are limited to 8 feet. Source: T.C.A. Section 55-7-202 (Maximum width and height).","handbook":"","hbref":""},{"q":"What is the maximum legal height, including any part of the load, for a vehicle on Tennessee highways without a permit?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"answer":1,"explanation":"Tennessee sets the maximum vehicle height (including load) at 13 feet 6 inches. A taller load requires an over-height permit. Source: T.C.A. Section 55-7-202 (Maximum width and height).","handbook":"","hbref":""},{"q":"What is the maximum legal gross vehicle weight allowed on Tennessee highways without a special permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"answer":1,"explanation":"Tennessee's maximum legal gross weight is 80,000 pounds, consistent with the federal limit for the Interstate system. Loads above this need an overweight permit. Source: T.C.A. Section 55-7-203 (Maximum weight per axle or group of axles).","handbook":"","hbref":""},{"q":"What is the maximum weight a single axle may legally carry on Tennessee highways without a permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","23,000 pounds"],"answer":1,"explanation":"Tennessee limits a single axle to 20,000 pounds. The 23,000-pound figure applies only under a special overweight permit, not legally without one. Source: T.C.A. Section 55-7-203.","handbook":"","hbref":""},{"q":"What is the maximum weight a tandem axle group may legally carry on Tennessee highways without a permit?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"answer":1,"explanation":"Tennessee limits a tandem axle group to 34,000 pounds without a permit. The 46,000-pound figure applies only under a special overweight permit. Source: T.C.A. Section 55-7-203.","handbook":"","hbref":""},{"q":"What is the maximum legal width of a vehicle, including its load, on a 'regular' (non-federal/state-system) road in Tennessee?","options":["8 feet 0 inches","8 feet 6 inches","7 feet 6 inches","9 feet 0 inches"],"answer":0,"explanation":"On regular roads, Tennessee caps width at 8 feet (4 feet each side of the centerline); the 8-foot-6-inch allowance applies only on the federal and state highway system. Source: T.C.A. Section 55-7-202.","handbook":"","hbref":""},{"q":"Besides the per-axle and gross limits, what method does Tennessee use to determine the maximum allowable weight based on axle spacing?","options":["The federal bridge formula (weight-to-length table)","The state tonnage tax schedule","A flat 80,000-pound cap regardless of spacing","The manufacturer's gross combination weight rating"],"answer":0,"explanation":"Tennessee applies the federal bridge formula (Formula B), which relates allowable gross weight to the number of axles and the distance between them, in addition to the single/tandem/gross caps. Source: T.C.A. Section 55-7-203; FHWA bridge formula adopted by TDOT.","handbook":"","hbref":""},{"q":"Under a Tennessee special overweight permit for a nondivisible load, what is the maximum weight allowed on a single axle?","options":["20,000 pounds","21,500 pounds","23,000 pounds","26,000 pounds"],"answer":2,"explanation":"Tennessee permits up to 23,000 pounds on a single axle for nondivisible overweight loads moved under permit (vs. the 20,000-pound legal limit). Source: T.C.A. Section 55-7-205 and TDOT OS/OW permit rules.","handbook":"","hbref":""},{"q":"Under a Tennessee special overweight permit, what is the maximum weight allowed on a tandem axle group?","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"answer":2,"explanation":"Tennessee permits up to 46,000 pounds on a tandem axle group for nondivisible overweight loads under permit (vs. the 34,000-pound legal limit). Source: T.C.A. Section 55-7-205 and TDOT OS/OW permit rules.","handbook":"","hbref":""},{"q":"Under a Tennessee overweight permit, what is the maximum weight allowed on a tridem (three-axle) group?","options":["42,000 pounds","50,000 pounds","60,000 pounds","68,000 pounds"],"answer":2,"explanation":"Tennessee permits up to 60,000 pounds on a tridem (three-axle) group for nondivisible overweight loads moved under permit. Source: T.C.A. Section 55-7-205 and TDOT OS/OW permit rules.","handbook":"","hbref":""},{"q":"In Tennessee, a special oversize or overweight permit is generally required only for loads that are:","options":["Carrying any hazardous material","Nondivisible and cannot reasonably be reduced to legal limits","Traveling more than 100 miles in the state","Registered out of state"],"answer":1,"explanation":"TDOT issues OS/OW permits for nondivisible articles or commodities that cannot reasonably be dismantled or split to meet legal size/weight limits. A load that can simply be divided must be brought within legal limits instead. Source: TDOT Oversize/Overweight Permit Office; T.C.A. Section 55-7-205.","handbook":"","hbref":""},{"q":"How long is a standard Tennessee single-trip oversize/overweight permit valid?","options":["3 days","10 days","30 days","1 year"],"answer":1,"explanation":"A Tennessee single-trip OS/OW permit is valid for 10 days (mobile home permits are valid for 6 days). Source: TDOT Oversize/Overweight Permit Office FAQs and rules.","handbook":"","hbref":""},{"q":"How does a carrier apply for an oversize/overweight permit in Tennessee?","options":["By phone call to the local sheriff","Electronically through the TDOT TNTRIPS online system","By mailing a paper form to each county","Only at a weigh station in person"],"answer":1,"explanation":"Tennessee OS/OW permits are obtained electronically through TDOT's TNTRIPS online permitting system; phone and email orders are not accepted. Source: TDOT Oversize/Overweight Permit Office (TNTRIPS).","handbook":"","hbref":""},{"q":"A towed semitrailer on Tennessee's federal and state highway system generally may not exceed what length from its point of attachment to the tractor?","options":["48 feet","52 feet","57 feet","60 feet"],"answer":1,"explanation":"Tennessee allows a towed semitrailer/trailer up to 52 feet measured from the point of attachment to the tractor on the federal and state highway system. Source: T.C.A. Section 55-7-201 (Maximum length of vehicles).","handbook":"","hbref":""},{"q":"On Tennessee's non-Interstate state highways, certain commodity haulers (such as logging, coal, sand, and farm trucks) are given a weight 'margin of error' of how much?","options":["5 percent","10 percent","15 percent","No margin is allowed"],"answer":1,"explanation":"Tennessee allows a 10 percent margin of error on true gross or axle weight for logging, sand, coal, clay, shale, phosphate, solid waste, recovered materials, and farm/machinery trucks on state highways, excluding the Interstate system. Source: T.C.A. Section 55-7-203(b).","handbook":"","hbref":""},{"q":"Does the 10 percent weight tolerance for logging, farm, and similar commodity trucks in Tennessee apply on the Interstate highway system?","options":["Yes, on all highways including Interstates","No, it excludes the Interstate system","Only at night","Only with a permit"],"answer":1,"explanation":"The 10 percent commodity weight tolerance applies on Tennessee state highways but specifically excludes the Interstate (federal-aid Interstate) system, where federal 80,000/20,000/34,000 limits are strictly enforced. Source: T.C.A. Section 55-7-203(b).","handbook":"","hbref":""},{"q":"Under Tennessee law, moving certain farm machinery for farm purposes may be done WITHOUT a permit when it is moved during daylight hours, off the Interstate, and within what distance of its point of origin?","options":["25 miles","50 miles","75 miles","100 miles"],"answer":1,"explanation":"Tennessee permits over-dimension/over-weight farm machinery to be moved for farm purposes without a permit during daylight hours, not on Interstates, within 50 miles of the point of origin. Source: T.C.A. Section 55-7-205.","handbook":"","hbref":""},{"q":"When a permitted load in Tennessee exceeds 10 feet in width, what is specifically required on the vehicle?","options":["A pilot/escort vehicle on both ends at all times","An 'Oversize Load' banner on the front and rear","A police escort","Travel only between midnight and 5 a.m."],"answer":1,"explanation":"Tennessee requires an 'Oversize Load' banner displayed on the front and rear of any load exceeding 10 feet in width. Escort and other requirements scale up with width. Source: TDOT Oversize/Overweight Permit rules.","handbook":"","hbref":""},{"q":"What is the approximate cost of a Tennessee annual overweight permit for a vehicle up to 100,000 pounds gross weight?","options":["$50","$150","$750","$3,500"],"answer":2,"explanation":"TDOT's annual overweight permit fee is $750 for vehicles up to 100,000 pounds GVW, with higher tiered fees for greater weights (e.g., up to 120,000 lb at a higher rate). Source: TDOT Oversize/Overweight Permit Office fee schedule.","handbook":"","hbref":""},{"q":"In Tennessee, the movement of superloads, houseboats, and mobile homes under permit is generally restricted to what travel times?","options":["Daylight hours only","Nighttime hours only","Weekends only","Any time, 24 hours a day"],"answer":0,"explanation":"Tennessee restricts movements of superloads, houseboats, and mobile homes to daylight hours only, and escorted loads must also observe metropolitan rush-hour curfews. Source: TDOT Oversize/Overweight Permit rules.","handbook":"","hbref":""},{"q":"In Tennessee, which CDL class is required to operate a combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, where the vehicle being towed is over 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Tennessee defines a Class A CDL as required to operate a combination vehicle with a GCWR over 26,000 lbs where the towed unit exceeds 10,000 lbs GVWR. Source: Tenn. Comp. R. & Regs. 1340-01-13-.03; Tennessee CDL Manual.","handbook":"","hbref":""},{"q":"Which Tennessee CDL class is required to operate a single vehicle with a Gross Vehicle Weight Rating (GVWR) of 26,001 pounds or more, or such a vehicle towing a trailer not over 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"Tennessee defines a Class B CDL as required for a single vehicle over 26,000 lbs GVWR, or such a vehicle towing a unit not exceeding 10,000 lbs GVWR. Source: Tenn. Comp. R. & Regs. 1340-01-13-.03; Tennessee CDL Manual.","handbook":"","hbref":""},{"q":"A Tennessee driver operates a single vehicle under 26,001 pounds GVWR that is placarded for hazardous materials or designed to carry 16 or more passengers including the driver. Which CDL class applies?","options":["Class A","Class B","Class C","Class D"],"answer":2,"explanation":"Tennessee's Class C CDL covers single vehicles not over 26,000 lbs GVWR that must be placarded for hazardous materials, are designed to transport more than 15 passengers (16+ including the driver), or are used as a school bus. Source: Tenn. Comp. R. & Regs. 1340-01-13-.03.","handbook":"","hbref":""},{"q":"In Tennessee, what is the minimum age to obtain a CDL restricted to intrastate (within-state) commercial driving only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Tennessee allows applicants who are at least 18 to obtain a CDL for intrastate operation only. Source: Tennessee CDL Manual; Tennessee Department of Safety and Homeland Security, Driver Services.","handbook":"","hbref":""},{"q":"In Tennessee, what is the minimum age required to drive a commercial vehicle in interstate commerce or to transport hazardous materials?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"Tennessee requires a driver to be at least 21 to operate in interstate commerce or to transport hazardous materials; drivers 18-20 are limited to intrastate operation. Source: Tennessee CDL Manual; 49 CFR 383.3 as applied in Tennessee.","handbook":"","hbref":""},{"q":"Which endorsement is required in Tennessee to operate a commercial vehicle transporting hazardous materials in quantities that require placarding?","options":["N endorsement","H endorsement","T endorsement","P endorsement"],"answer":1,"explanation":"Tennessee requires the H (Hazardous Materials) endorsement to drive a CMV carrying placardable amounts of hazardous materials. Source: Tennessee CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Before Tennessee can add a Hazardous Materials (H) endorsement to a CDL, federal law requires the applicant to complete which additional step?","options":["A TSA security threat assessment with fingerprint-based background check","A 40-hour classroom HazMat course in Tennessee","A vision exam at a Tennessee DOT weigh station","A drug and alcohol test administered by the county clerk"],"answer":0,"explanation":"Tennessee may not issue a HazMat endorsement until the applicant passes a TSA-administered security threat assessment, which includes a fingerprint-based background check, under the USA PATRIOT Act. Source: Tennessee Department of Safety and Homeland Security, HazMat Endorsement page; 49 CFR 1572.","handbook":"","hbref":""},{"q":"Which endorsement does Tennessee require to drive a tank vehicle designed to haul a liquid or gas in a permanently mounted tank rated to carry 1,000 gallons or more?","options":["H endorsement","N endorsement","T endorsement","S endorsement"],"answer":1,"explanation":"Tennessee requires the N (Tanker) endorsement for tank vehicles designed to transport liquids or gases in a tank rated at 1,000 gallons or more. Source: Tennessee CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which endorsement is required in Tennessee to pull double or triple trailers, and to which CDL class is it limited?","options":["T endorsement, available on Class A only","T endorsement, available on Class B only","N endorsement, available on any class","P endorsement, available on Class C only"],"answer":0,"explanation":"Tennessee requires the T (Doubles/Triples) endorsement to pull more than one trailer, and because such combinations require a Class A license, the endorsement is available on Class A only. Source: Tennessee CDL Manual; Tenn. Comp. R. & Regs. 1340-01-13.","handbook":"","hbref":""},{"q":"Which endorsement does Tennessee require to drive a commercial vehicle designed to transport 16 or more passengers, including the driver?","options":["S endorsement","P endorsement","N endorsement","H endorsement"],"answer":1,"explanation":"Tennessee requires the P (Passenger) endorsement to operate a vehicle designed to carry 16 or more people including the driver. Source: Tennessee CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In Tennessee, the School Bus (S) endorsement requires the driver to first hold which other endorsement?","options":["The H (HazMat) endorsement","The N (Tanker) endorsement","The P (Passenger) endorsement","The T (Doubles/Triples) endorsement"],"answer":2,"explanation":"In Tennessee, the S (School Bus) endorsement requires the P (Passenger) endorsement as a prerequisite, since a school bus is a passenger-carrying vehicle. Source: Tennessee CDL Manual; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Under the federal rule applied in Tennessee, how long after a Commercial Learner Permit (CLP) is initially issued must the holder wait before being eligible to take the CDL skills test?","options":["7 days","14 days","30 days","60 days"],"answer":1,"explanation":"A CLP holder is not eligible to take the CDL skills test in the first 14 days after the CLP is initially issued. Source: 49 CFR 383.25 as applied by Tennessee Driver Services; Tennessee CDL Manual.","handbook":"","hbref":""},{"q":"Under federal standards followed in Tennessee, a Commercial Learner Permit (CLP) is valid for no more than how long from its initial date of issuance without retaking the knowledge tests?","options":["30 days","90 days","6 months","1 year"],"answer":3,"explanation":"A CLP must be valid for no more than one year from the initial date of issuance without requiring the holder to retake the knowledge tests; states typically issue it for up to 180 days with one renewal. Source: 49 CFR 383.25; Tennessee Driver Services.","handbook":"","hbref":""},{"q":"While operating a commercial vehicle under a Tennessee Commercial Learner Permit (CLP), what supervision is required?","options":["A CDL holder with the proper class and endorsements must be seated next to the CLP holder","No supervision is required if the driver is over 21","A law enforcement officer must follow in a separate vehicle","Any licensed Class D driver may ride in the back seat"],"answer":0,"explanation":"A CLP holder may only drive when accompanied by a CDL holder who has the appropriate class and endorsements and who is seated in the front seat beside the permit holder. Source: 49 CFR 383.25; Tennessee CDL Manual.","handbook":"","hbref":""},{"q":"When applying for a CDL or CLP in Tennessee, how many proofs of Tennessee residence must an applicant provide?","options":["One proof of residence","Two proofs of residence","Three proofs of residence","No proof of residence is required"],"answer":1,"explanation":"Tennessee requires applicants to present two (2) proofs of Tennessee residence, along with proof of identity/lawful presence and a Social Security number. Source: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL.","handbook":"","hbref":""},{"q":"Which set of documents must a Tennessee CDL applicant provide to establish eligibility?","options":["Proof of identity/lawful presence, proof of Social Security number, and two proofs of Tennessee residence","Only a Tennessee voter registration card","A passport and a single utility bill only","A birth certificate and a vehicle title"],"answer":0,"explanation":"Tennessee requires proof of identity and lawful presence (U.S. citizenship or lawful permanent resident status), proof of Social Security number, and two proofs of Tennessee residence. Source: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL.","handbook":"","hbref":""},{"q":"What training must new Tennessee applicants complete before taking the CDL skills test for a Class A or Class B license, or before adding certain endorsements?","options":["Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry","A defensive driving course at a Tennessee community college","A four-year apprenticeship logged with the county","A Tennessee Highway Patrol ride-along program"],"answer":0,"explanation":"Tennessee requires new applicants to complete Entry-Level Driver Training (ELDT) provided by a school listed on the FMCSA Training Provider Registry before the skills test for a Class A/B or for the H, P, or S endorsements. Source: 49 CFR Part 380 Subpart F; Tennessee Driver Services CDL page.","handbook":"","hbref":""},{"q":"When self-certifying for a Tennessee CDL, which category describes a driver who operates in interstate commerce and must meet the federal DOT medical examiner's certificate requirement?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"answer":1,"explanation":"A driver who self-certifies as Non-Excepted Interstate operates in interstate commerce and must maintain a valid federal DOT medical examiner's certificate. Source: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"How many self-certification categories must a Tennessee CDL applicant choose from regarding the type of commercial driving they perform?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"Tennessee CDL holders must self-certify into one of four categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. Source: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Tennessee driver self-certifies as Non-Excepted Interstate. To keep the CDL valid, what must the driver keep on file with the state?","options":["A current federal medical examiner's certificate from a certified examiner","A notarized letter from their employer","A copy of their high school diploma","An annual vehicle inspection sticker"],"answer":0,"explanation":"Non-excepted drivers must obtain and maintain a current federal medical examiner's certificate from a certified medical examiner on the FMCSA National Registry and keep it on file with the state. Source: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 391.45.","handbook":"","hbref":""},{"q":"In Tennessee, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"Tennessee follows the federal standard: operating a CMV with a BAC of 0.04 or higher is a major offense. This is half the 0.08 limit for non-commercial drivers. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1; T.C.A. 55-50-405.","handbook":"","hbref":""},{"q":"A driver is convicted for the first time of operating a CMV with a BAC of 0.04 or higher while NOT carrying hazardous materials. For how long is the CDL disqualified?","options":["60 days","6 months","1 year","3 years"],"answer":2,"explanation":"A first major offense (including BAC of 0.04 or higher in a CMV) results in a minimum 1-year CDL disqualification in Tennessee. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A driver commits a first major alcohol offense while operating a CMV that was placarded for hazardous materials. What is the disqualification period?","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"When a first major offense occurs while the CMV is transporting placarded hazardous materials, the Tennessee disqualification increases from 1 year to 3 years. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Under Tennessee's implied consent law, what is the consequence for a CDL holder who refuses a required chemical/blood alcohol test for the first time?","options":["A warning only","Loss of the CDL for 60 days","Loss of the CDL for 1 year","Loss of the CDL for 90 days"],"answer":2,"explanation":"Refusing to submit to alcohol testing is treated as a major offense in Tennessee, resulting in a minimum 1-year CDL disqualification, the same as a first conviction for driving over the BAC limit. Source: Tennessee CDL Manual (Disqualifications); T.C.A. 55-50-405; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CDL holder is convicted of a SECOND major offense (for example, a second BAC-0.04 violation) during their driving career. What is the disqualification period in Tennessee?","options":["3 years","10 years","Lifetime","5 years"],"answer":2,"explanation":"A second major offense results in a lifetime CDL disqualification. Tennessee has not adopted the optional 10-year reinstatement provision, so the lifetime ban is permanent. Source: Tennessee CDL Manual (Disqualifications); TN Dept. of Safety CDL serious-offenses guidance; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Using a commercial motor vehicle to commit a felony involving the manufacturing, distributing, or dispensing of a controlled substance results in what Tennessee disqualification?","options":["1 year","3 years","Lifetime, with no reinstatement","5 years"],"answer":2,"explanation":"Using a CMV in the commission of a felony involving controlled substances carries a lifetime disqualification with no possibility of reinstatement in Tennessee. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"How many serious traffic violations must a CDL driver commit within a 3-year period before the FIRST disqualification is triggered in Tennessee?","options":["1 violation","2 violations","3 violations","4 violations"],"answer":1,"explanation":"A single serious traffic violation does not cause a disqualification. The first disqualification (60 days) is triggered by a SECOND serious violation within 3 years. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"A CDL driver is convicted of TWO serious traffic violations within a 3-year period. What is the disqualification period?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a 60-day CDL disqualification in Tennessee. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"A CDL driver accumulates THREE serious traffic violations within a 3-year period. What is the disqualification period?","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three serious traffic violations within 3 years result in a 120-day CDL disqualification in Tennessee. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"At what speed over the posted limit does excessive speeding count as a 'serious traffic violation' for a Tennessee CDL holder?","options":["10 mph or more over","15 mph or more over","20 mph or more over","25 mph or more over"],"answer":1,"explanation":"Speeding 15 mph or more above the posted speed limit is classified as a serious traffic violation. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation rather than a major offense for a Tennessee CDL driver?","options":["Driving a CMV with a BAC of 0.04 or higher","Reckless driving / following too closely","Leaving the scene of an accident","Using the CMV to commit a felony"],"answer":1,"explanation":"Reckless driving, following too closely, and improper/erratic lane changes are serious traffic violations. The other options listed are major offenses carrying a 1-year (or lifetime) disqualification. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Tables 1 and 2.","handbook":"","hbref":""},{"q":"Texting while driving a CMV is classified under Tennessee CDL rules as which of the following?","options":["A major offense (1-year disqualification)","A serious traffic violation","An out-of-service order violation","A non-disqualifying infraction"],"answer":1,"explanation":"Both texting and using a hand-held mobile telephone while driving a CMV are serious traffic violations, which can count toward the 60-day/120-day disqualifications. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2; FMCSA 392.80/392.82.","handbook":"","hbref":""},{"q":"A CDL driver receives a SECOND conviction for using a hand-held cell phone while driving a CMV, the second occurring within 3 years of the first. What disqualification applies?","options":["No disqualification","60 days","120 days","1 year"],"answer":1,"explanation":"Hand-held phone use is a serious traffic violation. A second serious violation within 3 years triggers a 60-day disqualification. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the disqualification period for a FIRST conviction of a railroad-highway grade crossing violation by a Tennessee CDL driver?","options":["No less than 30 days","No less than 60 days","No less than 120 days","No less than 1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation carries a disqualification of not less than 60 days. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A Tennessee CDL driver is convicted of a SECOND railroad-highway grade crossing violation within a 3-year period. What is the minimum disqualification?","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"A second railroad-grade-crossing violation within 3 years results in a disqualification of not less than 120 days. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A Tennessee CDL driver is convicted of a THIRD railroad-highway grade crossing violation within a 3-year period. What is the minimum disqualification?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third railroad-grade-crossing violation within 3 years results in a disqualification of not less than 1 year. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum disqualification period for a FIRST violation of an out-of-service order (in a CMV not carrying hazmat or passengers) for a Tennessee CDL driver?","options":["30 days","90 days","180 days","1 year"],"answer":2,"explanation":"A first out-of-service order violation results in a disqualification of not less than 180 days (up to 1 year). Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"In addition to disqualification, what is the minimum civil penalty a Tennessee driver faces for a FIRST out-of-service order violation?","options":["$1,000","$2,500","$5,000","$10,000"],"answer":1,"explanation":"A first out-of-service order violation carries a minimum civil penalty of $2,500 in addition to the 180-day disqualification; a second carries a minimum of $5,000. Source: Tennessee CDL Manual / TN Dept. of Safety; 49 CFR 383.53.","handbook":"","hbref":""},{"q":"A Tennessee CDL driver commits a SECOND out-of-service order violation within a 10-year period (non-hazmat). What is the minimum disqualification?","options":["180 days","1 year","2 years","5 years"],"answer":2,"explanation":"A second out-of-service order violation within 10 years results in a disqualification of not less than 2 years (and a minimum $5,000 civil penalty). Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A driver violates an out-of-service order for the first time while the CMV is transporting placarded hazardous materials. What is the disqualification period?","options":["Not less than 60 days","Not less than 180 days, up to 2 years","Exactly 1 year","Lifetime"],"answer":1,"explanation":"A first out-of-service order violation while transporting placarded hazmat (or carrying 16+ passengers) carries a heightened disqualification of not less than 180 days and up to 2 years. Source: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"On a Tennessee highway with at least four lanes, the Move Over law requires an approaching driver passing a stopped emergency vehicle that is displaying flashing lights to do what when it is safe?","options":["Change into a lane not adjacent to the stopped vehicle","Come to a complete stop until the emergency vehicle leaves","Move onto the right shoulder and continue past","Sound the horn and maintain the posted speed"],"answer":0,"explanation":"Tennessee's Move Over law (T.C.A. 55-8-132) requires drivers on a highway of four or more lanes to yield by moving into a lane that is NOT adjacent to the stopped vehicle when it is safe; only if changing lanes is impossible or unsafe may the driver instead slow to a safe speed. Source: T.C.A. 55-8-132.","handbook":"","hbref":""},{"q":"Under Tennessee's Move Over law, if a CMV driver cannot safely change lanes when passing a stopped utility or maintenance vehicle with flashing lights, what must the driver do instead?","options":["Stop completely on the roadway","Reduce speed to a safe speed for road conditions","Reduce speed to exactly 25 mph below the limit","Pull onto the opposite shoulder"],"answer":1,"explanation":"T.C.A. 55-8-132 covers police, fire, ambulance, utility, tow, and highway maintenance vehicles. If a lane change is impossible or unsafe, the driver must reduce to a safe speed for road conditions; the statute does not fix a numeric reduction. Source: T.C.A. 55-8-132.","handbook":"","hbref":""},{"q":"Violating Tennessee's Move Over law (failing to move over or slow down for a stopped emergency vehicle) is classified as what?","options":["A non-moving civil infraction","A Class C felony","A Class B misdemeanor","A simple warning only"],"answer":2,"explanation":"A violation of Tennessee's Move Over law is a Class B misdemeanor, punishable by a fine of up to $500 (and possible jail in aggravated cases). Source: T.C.A. 55-8-132.","handbook":"","hbref":""},{"q":"What is the maximum posted speed limit allowed on Tennessee interstate highways?","options":["65 mph","70 mph","75 mph","80 mph"],"answer":1,"explanation":"Tennessee sets a statutory maximum of 70 mph on interstate highways. Source: T.C.A. 55-8-152.","handbook":"","hbref":""},{"q":"Under Tennessee law, on highways that are NOT interstates or four-lane controlled-access routes, what is the general maximum speed for a truck (1.5-ton rated capacity or more)?","options":["45 mph","55 mph","60 mph","65 mph"],"answer":1,"explanation":"T.C.A. 55-8-152 limits trucks (1.5-ton rated capacity or more) to 55 mph on highways other than interstates and four-lane controlled-access highways, where the limit is 65 mph. Source: T.C.A. 55-8-152.","handbook":"","hbref":""},{"q":"In Tennessee, what is the minimum lawful speed for a vehicle operating in the left-hand (passing) lane of a controlled-access highway with four or more lanes?","options":["40 mph","45 mph","55 mph","65 mph"],"answer":2,"explanation":"Tennessee makes it unlawful to operate below 55 mph in the left-hand lane of a controlled-access highway with four or more lanes. Source: T.C.A. 55-8-152.","handbook":"","hbref":""},{"q":"When a Tennessee CMV driver is required to stop at a railroad crossing, where must the vehicle stop relative to the nearest rail?","options":["Within 50 feet but not less than 15 feet","Within 25 feet but not less than 5 feet","Within 100 feet but not less than 50 feet","Exactly 10 feet from the rail"],"answer":0,"explanation":"A driver required to stop must stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen before proceeding. Source: Tennessee CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"Which of the following must ALWAYS stop at a railroad crossing in Tennessee, even when no train is visible?","options":["Any empty flatbed trailer","A bus carrying passengers and a placarded hazardous-materials vehicle","Any three-axle straight truck","Any vehicle over 26,001 pounds"],"answer":1,"explanation":"The CMVs that must stop at railroad crossings are buses carrying passengers and vehicles displaying hazardous-materials placards; most other CMVs are not required to stop unless signals require it. Source: Tennessee CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"While any part of a Tennessee CMV is on the railroad tracks during a crossing, the driver must NOT do which of the following?","options":["Keep both hands on the wheel","Look both ways down the track","Shift gears","Maintain a steady speed"],"answer":2,"explanation":"Drivers must not stop, change gears, or change lanes while any part of the vehicle is crossing the tracks, because a missed shift could leave the vehicle stalled on the rails. Source: Tennessee CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"On a Tennessee two-lane road with traffic in both directions, what must a driver do when a school bus stops and activates its red flashing lights to load or unload children?","options":["Only the vehicles behind the bus must stop","Vehicles in both directions must stop","Slow to 15 mph and pass with caution","Pass the bus on the left if no children are visible"],"answer":1,"explanation":"On an undivided roadway, drivers in BOTH directions must stop for a school bus displaying flashing red lights and a stop arm until it is withdrawn. Source: T.C.A. 55-8-151.","handbook":"","hbref":""},{"q":"In Tennessee, a driver meeting a stopped school bus from the opposite direction is exempt from stopping only when the roadways are separated by what?","options":["A painted center line","A two-way left-turn (suicide) lane","An intervening space or physical barrier not suitable for vehicular traffic (separate roadways)","At least three lanes of travel"],"answer":2,"explanation":"Tennessee's exception applies only on a highway with separate roadways, meaning the directions are divided by an intervening space or barrier not suitable for vehicular traffic. A mere painted line or center turn lane does NOT qualify, so drivers must still stop. Source: T.C.A. 55-8-151.","handbook":"","hbref":""},{"q":"A first offense of illegally passing a stopped school bus in Tennessee is classified as what?","options":["A non-moving violation","A Class A misdemeanor","A Class C misdemeanor","A civil penalty only"],"answer":1,"explanation":"Illegally passing a stopped school bus is a Class A misdemeanor in Tennessee, with a fine of not less than $250 nor more than $1,000 for a first offense. Source: T.C.A. 55-8-151.","handbook":"","hbref":""},{"q":"In Tennessee, when a driver illegally passes a stopped school bus and strikes and kills a person, the offense rises to what level?","options":["A Class A misdemeanor","A Class E felony","A Class C felony","A Class B misdemeanor"],"answer":2,"explanation":"Striking a person while illegally passing a stopped school bus is a Class E felony; if the strike results in death, it is a Class C felony. Source: T.C.A. 55-8-151.","handbook":"","hbref":""},{"q":"Tennessee authorizes TDOT to restrict truck tractors and semitrailers to specific lanes on interstate and multilane divided highways having how many lanes in each direction?","options":["One or more","Two or more","Three or more","Five or more"],"answer":2,"explanation":"T.C.A. 55-8-195 authorizes TDOT to direct truck tractors and semitrailers to specific lanes on interstate and multilane divided highways with three or more lanes in each direction; violation is a Class C misdemeanor (fine up to $50). Source: T.C.A. 55-8-195.","handbook":"","hbref":""},{"q":"Under Tennessee's left-lane (Slow Poke) law, when may a driver lawfully travel in the far-left passing lane of an interstate or multilane divided highway?","options":["Whenever traffic is light","Only when overtaking or passing a vehicle in a non-passing lane","At any time as long as the speed limit is obeyed","Only between sunset and sunrise"],"answer":1,"explanation":"Tennessee's left-lane law (T.C.A. 55-8-204) restricts the passing lane to overtaking or passing a vehicle in a non-passing lane; lingering there otherwise is prohibited. Source: T.C.A. 55-8-204.","handbook":"","hbref":""},{"q":"When a CMV is stopped on a Tennessee shoulder, where must the rearmost warning triangle be placed for a normal two-lane, two-way road?","options":["10 feet behind the vehicle","40 feet behind the vehicle","100 feet behind the vehicle","200 feet behind the vehicle"],"answer":2,"explanation":"Warning devices must be set out within 10 minutes: one about 10 feet behind on the traffic side, one about 100 feet behind, and one about 100 feet in front (in the direction of approaching traffic). Source: Tennessee CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"How soon after stopping must a Tennessee CMV driver place the required emergency warning devices (triangles)?","options":["Within 10 minutes","Within 30 minutes","Immediately, before exiting the cab","Within 1 hour"],"answer":0,"explanation":"A stopped CMV driver must place the three warning triangles within 10 minutes of stopping. Source: Tennessee CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Without a special permit, what is the maximum legal width of a commercial vehicle and load in Tennessee?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 6 inches","10 feet 0 inches"],"answer":1,"explanation":"Tennessee's legal maximum width without an oversize permit is 8 feet 6 inches; legal height is 13 feet 6 inches. Exceeding these requires a TDOT special permit. Source: TDOT oversize/overweight permit rules; T.C.A. Title 55, Ch. 7.","handbook":"","hbref":""},{"q":"Tennessee oversize-load permits generally restrict movement to which time window?","options":["Daylight hours only (about a half-hour before sunrise to a half-hour after sunset)","Nighttime only, to avoid traffic","Any 24-hour period including Sundays","Only between 9:00 a.m. and 4:00 p.m."],"answer":0,"explanation":"Tennessee oversize permits generally allow travel during daylight (about a half-hour before sunrise to a half-hour after sunset), Monday through Saturday, with no movement on Sundays or major holidays and rush-hour curfews in large counties. Source: TDOT oversize/overweight permit rules.","handbook":"","hbref":""},{"q":"On the steep eastbound descent of Monteagle Mountain on I-24 in Tennessee, what safety feature is provided for trucks that lose their brakes?","options":["A mandatory toll plaza","Gravel-filled runaway truck ramps","A required ferry crossing","A reversible express lane"],"answer":1,"explanation":"The I-24 descent of Monteagle Mountain (about a 6% grade) is equipped with gravel-filled runaway truck escape ramps, and commercial trucks are directed to use the inspection/brake-check station before descending. Source: TDOT; Tennessee CDL Manual mountain-driving guidance.","handbook":"","hbref":""},{"q":"Which state agency is responsible for issuing Commercial Driver Licenses (CDLs) in Tennessee?","options":["The Tennessee Department of Safety and Homeland Security","The Tennessee Department of Transportation (TDOT)","The Tennessee Department of Motor Vehicles","The Tennessee Public Service Commission"],"answer":0,"explanation":"CDLs in Tennessee are issued by the Tennessee Department of Safety and Homeland Security (TDOSHS) through its Driver Services centers. Tennessee has no separate 'Department of Motor Vehicles'; TDOT handles highways, not licensing. Source: Tennessee CDL Manual; tn.gov/safety Driver Services.","handbook":"","hbref":""},{"q":"Where does a Tennessee applicant take the CDL general knowledge test and any endorsement knowledge tests?","options":["At a full-service Driver Services Center operated by the Department of Safety","At any FMCSA-registered truck driving school","At a Tennessee Department of Transportation district office","Online through the e-Services portal from home"],"answer":0,"explanation":"Tennessee's full-service Driver Services Centers administer the CDL general knowledge test and the knowledge tests for any endorsement. Schools provide training (ELDT), not the state knowledge test. Source: Tennessee CDL Manual; tn.gov/safety Driver Services 'How do I obtain a CDL'.","handbook":"","hbref":""},{"q":"Before being issued a Commercial Learner Permit (CLP), what must a Tennessee applicant first do?","options":["Pass the CDL general knowledge test","Pass the three-part skills test","Complete behind-the-wheel ELDT range training","Hold the CLP for at least 14 days"],"answer":0,"explanation":"To obtain the CLP a Tennessee applicant must have taken and passed the CDL general knowledge test (plus required endorsement tests). The skills test and the 14-day hold come after the CLP is issued. Source: Tennessee CDL Manual; tn.gov/safety Driver Services.","handbook":"","hbref":""},{"q":"Which set of documents must a Tennessee CDL applicant present at the Driver Services Center?","options":["Proof of identity, Social Security number, U.S. citizenship/lawful presence, and Tennessee residency","Only a valid passport and a major credit card","A high school diploma and two employer reference letters","A vehicle title and current vehicle registration only"],"answer":0,"explanation":"Tennessee requires proof of identity, proof of Social Security number, proof of U.S. citizenship or lawful permanent resident status, and two documents proving Tennessee domicile/residency. Source: Tennessee CDL Manual; tn.gov/safety Driver Services document requirements.","handbook":"","hbref":""},{"q":"How many distinct commerce categories must a Tennessee CDL applicant choose from when completing the self-certification affidavit?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"The Tennessee Self-Certification Affidavit (SF-1480) lists four options: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. The driver initials exactly one. Source: Tennessee SF-1480 Self-Certification Affidavit; tn.gov/safety.","handbook":"","hbref":""},{"q":"Which self-certification category requires a Tennessee CDL holder to provide a current federal DOT medical examiner's certificate?","options":["Non-excepted interstate","Excepted interstate","Excepted intrastate","Excepted interstate transporting only farm supplies"],"answer":0,"explanation":"A driver who self-certifies as non-excepted interstate is subject to 49 CFR 391.45 and must provide a current medical examiner's certificate. Excepted categories are not required to submit a federal medical card. Source: Tennessee SF-1480; tn.gov/safety Medical Certification Requirements.","handbook":"","hbref":""},{"q":"In Tennessee, what is the common name for the federal DOT medical examiner's certificate that non-excepted interstate CDL holders must keep current?","options":["The medical card (DOT card)","The hazardous materials endorsement card","The Selective Service certificate","The TWIC card"],"answer":0,"explanation":"The medical examiner's certificate (Form MCSA-5876) under 49 CFR 391.45 is commonly called the 'medical card' or 'DOT card.' A TWIC and HazMat endorsement are separate items. Source: Tennessee Medical Certification Requirements; tn.gov/safety.","handbook":"","hbref":""},{"q":"How may a Tennessee CDL holder submit a new Self-Certification Affidavit and updated medical certification to the state?","options":["By uploading through the Department of Safety e-Services portal or visiting a Driver Services Center","By mailing it directly to the FMCSA National Registry","By emailing it to the Tennessee Department of Transportation","By giving it to the medical examiner, who files it with the county clerk"],"answer":0,"explanation":"Tennessee CDL holders submit the Self-Certification Affidavit (and medical certification when required) by uploading via the Department of Safety e-Services portal or in person at a Driver Services Center. Source: tn.gov/safety Medical Certification Requirements.","handbook":"","hbref":""},{"q":"A Tennessee CDL holder must submit updated medical certification to keep status current at what point relative to the medical card's expiration?","options":["At least five business days prior to the expiration of the current medical certificate","Within 30 days after the certificate has already expired","Only once every eight years at license renewal","Within one year after the certificate expires"],"answer":0,"explanation":"Tennessee directs CDL holders to submit updated self-certification/medical documents at least five (5) business days before the current medical certificate expires to avoid a downgrade. Source: tn.gov/safety Medical Certification Requirements.","handbook":"","hbref":""},{"q":"When must ALL new Tennessee CDL applicants complete Entry-Level Driver Training (ELDT)?","options":["Before taking the CDL skills test","Only after the CDL has already been issued","Within one year after passing the skills test","Only if applying for a HazMat endorsement"],"answer":0,"explanation":"Since February 7, 2022, ELDT from a provider listed on the FMCSA Training Provider Registry must be completed before a first-time Class A/B applicant (and certain endorsement applicants) can take the skills/knowledge test. Source: tn.gov/safety ELDT page; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Where must a Tennessee CDL applicant's ELDT provider be listed for the training to count?","options":["On the FMCSA Training Provider Registry (TPR)","On the Tennessee Department of Transportation contractor list","On the Tennessee Secretary of State business registry","On the National Highway Traffic Safety Administration vendor list"],"answer":0,"explanation":"ELDT must be provided by an entity listed on the Federal Motor Carrier Safety Administration's Training Provider Registry (TPR). Training from an unlisted provider does not satisfy the requirement. Source: tn.gov/safety ELDT; FMCSA TPR.","handbook":"","hbref":""},{"q":"After a Tennessee CLP is issued, how long must the holder wait before being allowed to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Federal and Tennessee rules require the CLP to be held for a minimum of 14 days before the holder may take the CDL skills test. Source: Tennessee CDL Manual; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Tennessee CDL skills test consists of which three parts, in order?","options":["Pre-trip vehicle inspection, basic vehicle control skills, and on-road driving","Vision screening, knowledge exam, and parallel parking","Air-brake test, HazMat test, and night driving","Written test, drug screen, and on-road driving"],"answer":0,"explanation":"The Tennessee CDL skills test has three parts: the pre-trip vehicle inspection, the basic vehicle control skills test, and the on-road driving test, all in that order. Source: Tennessee CDL Manual.","handbook":"","hbref":""},{"q":"A Tennessee applicant takes the CDL skills test in a vehicle that represents what?","options":["The class and type of vehicle the applicant intends to be licensed to drive","Any passenger car provided by the state","A vehicle one class smaller than the license sought","Only a Class C straight truck regardless of license sought"],"answer":0,"explanation":"The skills test must be taken in a representative vehicle of the class and configuration for which the CDL is sought; the vehicle used can restrict the license class issued. Source: Tennessee CDL Manual; 49 CFR 383.71/383.133.","handbook":"","hbref":""},{"q":"Under the federal standard Tennessee follows, how long is a Commercial Learner Permit (CLP) valid before it must be renewed or the knowledge tests retaken?","options":["180 days, renewable once for an additional 180 days","30 days, with no renewal allowed","Five years, matching a regular license","90 days, renewable up to three times"],"answer":0,"explanation":"Per 49 CFR 383.25, which Tennessee applies, a CLP is valid for 180 days and may be renewed once for an additional 180 days without retaking the general knowledge test. Source: Tennessee CDL Manual; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"If a Tennessee applicant's CLP expires before the CDL is obtained, what happens to the completed tests?","options":["The knowledge and skills tests become invalid and must be retaken","Only the skills test is lost; knowledge results stay valid for five years","Nothing; results are permanent once passed","The tests remain valid for one additional year automatically"],"answer":0,"explanation":"If the CLP expires before the full CDL is issued, the applicant loses credit and must retake the knowledge and skills tests. Source: Tennessee CDL Manual; Tennessee Driver Services.","handbook":"","hbref":""},{"q":"What is the standard expiration cycle for a Tennessee Commercial Driver License issued to an adult?","options":["Eight years","Four years","Ten years","Two years"],"answer":0,"explanation":"Tennessee driver licenses, including CDLs, are generally valid for eight years (per Tenn. Code Ann. 55-50-337), after which they must be renewed. Source: Tenn. Code Ann. 55-50-337; tn.gov/safety Renewing Your License.","handbook":"","hbref":""},{"q":"How are Tennessee CDL renewals generally handled?","options":["In person at a Driver Services Center, with current medical certification provided","Entirely online with no documents required","Automatically by mail with no action by the driver","By phone through the Department of Transportation"],"answer":0,"explanation":"CDL renewals in Tennessee are done in person at a Driver Services Center, and the holder must have current medical certification on file at renewal. Source: tn.gov/safety Renewing Your License; Medical Certification Requirements.","handbook":"","hbref":""},{"q":"A 19-year-old who qualifies for a Tennessee CDL is subject to what operating restriction?","options":["Restricted to intrastate (within Tennessee) operation only","Restricted to vehicles under 26,001 pounds only","No restriction; full interstate privileges are granted","Restricted to daytime driving only"],"answer":0,"explanation":"Tennessee CDL applicants must be at least 18; those under 21 are restricted to intrastate operation only. Interstate operation (and HazMat) requires age 21. Source: Tennessee CDL Manual; tn.gov/safety Driver Services.","handbook":"","hbref":""},{"q":"Regarding Tennessee CDL application and testing fees, which statement is most accurate for a study guide?","options":["Fees are set by the Department of Safety and are subject to change, so applicants should confirm current amounts before applying","Tennessee charges no fees of any kind for a CDL","The fee is fixed permanently by federal law and never changes","Fees are collected only by the applicant's employer, never by the state"],"answer":0,"explanation":"CDL-related fees in Tennessee are established by the Department of Safety and can change over time; applicants should verify the current schedule at a Driver Services Center rather than rely on a fixed amount. Source: tn.gov/safety Driver Services fee schedule.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина транспортного средства вместе с грузом без специального разрешения на федеральной и штатной системе автомагистралей Теннесси?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Закон Теннесси разрешает ширину транспортного средства или груза до 8 feet 6 inches (102 inches) на федеральной и штатной системе автомагистралей; на «обычных» дорогах ширина ограничена 8 feet. Источник: T.C.A. Section 55-7-202 (Максимальная ширина и высота)."},"1":{"q":"Какова максимальная разрешённая высота, включая любую часть груза, для транспортного средства на автомагистралях Теннесси без специального разрешения?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"Теннесси устанавливает максимальную высоту транспортного средства (включая груз) в 13 feet 6 inches. Более высокий груз требует разрешения на превышение высоты. Источник: T.C.A. Section 55-7-202 (Максимальная ширина и высота)."},"2":{"q":"Какова максимальная разрешённая полная масса транспортного средства, допустимая на автомагистралях Теннесси без специального разрешения?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"Максимальная разрешённая полная масса в Теннесси составляет 80,000 pounds, что соответствует федеральному лимиту для системы межштатных автомагистралей. Грузы выше этого предела требуют разрешения на превышение веса. Источник: T.C.A. Section 55-7-203 (Максимальный вес на ось или группу осей)."},"3":{"q":"Какой максимальный вес может законно приходиться на одиночную ось на автомагистралях Теннесси без специального разрешения?","options":["18,000 pounds","20,000 pounds","22,400 pounds","23,000 pounds"],"explanation":"Теннесси ограничивает нагрузку на одиночную ось до 20,000 pounds. Значение в 23,000 pounds применяется только при наличии специального разрешения на превышение веса, а не законно без него. Источник: T.C.A. Section 55-7-203."},"4":{"q":"Какой максимальный вес может законно приходиться на сдвоенную группу осей на автомагистралях Теннесси без специального разрешения?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"explanation":"Теннесси ограничивает нагрузку на сдвоенную группу осей до 34,000 pounds без специального разрешения. Значение в 46,000 pounds применяется только при наличии специального разрешения на превышение веса. Источник: T.C.A. Section 55-7-203."},"5":{"q":"Какова максимальная разрешённая ширина транспортного средства, включая груз, на «обычной» дороге (не входящей в федеральную/штатную систему) в Теннесси?","options":["8 feet 0 inches","8 feet 6 inches","7 feet 6 inches","9 feet 0 inches"],"explanation":"На обычных дорогах Теннесси ограничивает ширину до 8 feet (4 feet с каждой стороны от осевой линии); допуск в 8 feet 6 inches применяется только на федеральной и штатной системе автомагистралей. Источник: T.C.A. Section 55-7-202."},"6":{"q":"Помимо пределов на ось и полной массы, какой метод использует Теннесси для определения максимально допустимого веса в зависимости от расстояния между осями?","options":["Федеральная мостовая формула (таблица соотношения веса и длины)","Графики тоннажного налога штата","Фиксированный предел в 80,000 pounds независимо от расстояния между осями","Полная масса автопоезда, заявленная производителем (GCWR)"],"explanation":"Теннесси применяет федеральную мостовую формулу (Formula B), которая связывает допустимую полную массу с числом осей и расстоянием между ними, в дополнение к пределам на одиночную/сдвоенную ось и полную массу. Источник: T.C.A. Section 55-7-203; мостовая формула FHWA, принятая TDOT."},"7":{"q":"При наличии специального разрешения Теннесси на превышение веса для неделимого груза какой максимальный вес допускается на одиночную ось?","options":["20,000 pounds","21,500 pounds","23,000 pounds","26,000 pounds"],"explanation":"Теннесси разрешает до 23,000 pounds на одиночную ось для неделимых тяжеловесных грузов, перевозимых по разрешению (по сравнению с законным пределом в 20,000 pounds). Источник: T.C.A. Section 55-7-205 и правила выдачи разрешений OS/OW TDOT."},"8":{"q":"При наличии специального разрешения Теннесси на превышение веса какой максимальный вес допускается на сдвоенную группу осей?","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"explanation":"Теннесси разрешает до 46,000 pounds на сдвоенную группу осей для неделимых тяжеловесных грузов по разрешению (по сравнению с законным пределом в 34,000 pounds). Источник: T.C.A. Section 55-7-205 и правила выдачи разрешений OS/OW TDOT."},"9":{"q":"При наличии разрешения Теннесси на превышение веса какой максимальный вес допускается на строенную (трёхосную) группу осей?","options":["42,000 pounds","50,000 pounds","60,000 pounds","68,000 pounds"],"explanation":"Теннесси разрешает до 60,000 pounds на строенную (трёхосную) группу осей для неделимых тяжеловесных грузов, перевозимых по разрешению. Источник: T.C.A. Section 55-7-205 и правила выдачи разрешений OS/OW TDOT."},"10":{"q":"В Теннесси специальное разрешение на негабаритный или тяжеловесный груз, как правило, требуется только для грузов, которые:","options":["Перевозят любой опасный материал","Являются неделимыми и не могут быть разумно приведены к законным пределам","Перемещаются более чем на 100 миль в пределах штата","Зарегистрированы за пределами штата"],"explanation":"TDOT выдаёт разрешения OS/OW для неделимых предметов или товаров, которые невозможно разумно разобрать или разделить, чтобы уложиться в законные пределы по габаритам/весу. Груз, который можно просто разделить, вместо этого должен быть приведён к законным пределам. Источник: TDOT Oversize/Overweight Permit Office; T.C.A. Section 55-7-205."},"11":{"q":"Как долго действует стандартное одноразовое разрешение Теннесси на негабаритный/тяжеловесный груз (на одну поездку)?","options":["3 days","10 days","30 days","1 year"],"explanation":"Одноразовое разрешение OS/OW Теннесси действует 10 days (разрешения для мобильных домов действительны 6 days). Источник: часто задаваемые вопросы и правила TDOT Oversize/Overweight Permit Office."},"12":{"q":"Как перевозчик подаёт заявку на разрешение для негабаритного/тяжеловесного груза в Теннесси?","options":["По телефонному звонку местному шерифу","В электронном виде через онлайн-систему TDOT TNTRIPS","Отправив бумажную форму почтой в каждый округ","Только лично на весовой станции"],"explanation":"Разрешения OS/OW в Теннесси оформляются в электронном виде через онлайн-систему выдачи разрешений TDOT TNTRIPS; заказы по телефону и электронной почте не принимаются. Источник: TDOT Oversize/Overweight Permit Office (TNTRIPS)."},"13":{"q":"Буксируемый полуприцеп на федеральной и штатной системе автомагистралей Теннесси, как правило, не может превышать какую длину, измеряемую от точки сцепки с тягачом?","options":["48 feet","52 feet","57 feet","60 feet"],"explanation":"Теннесси разрешает буксируемый полуприцеп/прицеп длиной до 52 feet, измеряемой от точки сцепки с тягачом, на федеральной и штатной системе автомагистралей. Источник: T.C.A. Section 55-7-201 (Максимальная длина транспортных средств)."},"14":{"q":"На штатных автомагистралях Теннесси, не относящихся к межштатным, определённым перевозчикам товаров (например, лесовозам, угольным, песковозам и сельскохозяйственным грузовикам) предоставляется «допуск погрешности» по весу в каком размере?","options":["5 percent","10 percent","15 percent","Никакой допуск не предусмотрен"],"explanation":"Теннесси допускает погрешность в 10 percent от истинной полной массы или нагрузки на ось для лесовозов, песковозов, угольных, глиняных, сланцевых, фосфатных грузовиков, грузовиков с твёрдыми отходами, переработанными материалами, а также сельскохозяйственных грузовиков и грузовиков для перевозки техники на штатных автомагистралях, за исключением системы межштатных автомагистралей. Источник: T.C.A. Section 55-7-203(b)."},"15":{"q":"Применяется ли допуск по весу в 10 percent для лесовозов, сельскохозяйственных и аналогичных грузовиков, перевозящих товары, в Теннесси на системе межштатных автомагистралей?","options":["Да, на всех автомагистралях, включая межштатные","Нет, он не распространяется на систему межштатных автомагистралей","Только ночью","Только при наличии разрешения"],"explanation":"Допуск по весу для товаров в 10 percent применяется на штатных автомагистралях Теннесси, но конкретно не распространяется на систему межштатных автомагистралей (федеральных межштатных дорог), где строго соблюдаются федеральные пределы 80,000/20,000/34,000. Источник: T.C.A. Section 55-7-203(b)."},"16":{"q":"Согласно закону Теннесси, перемещение определённой сельскохозяйственной техники для сельскохозяйственных целей может осуществляться БЕЗ разрешения, если оно происходит в светлое время суток, вне межштатных автомагистралей и в пределах какого расстояния от точки отправления?","options":["25 miles","50 miles","75 miles","100 miles"],"explanation":"Теннесси разрешает перемещать негабаритную/тяжеловесную сельскохозяйственную технику для сельскохозяйственных целей без разрешения в светлое время суток, не по межштатным автомагистралям, в пределах 50 miles от точки отправления. Источник: T.C.A. Section 55-7-205."},"17":{"q":"Когда груз, перевозимый по разрешению в Теннесси, превышает 10 feet в ширину, что конкретно требуется на транспортном средстве?","options":["Сопровождающий/эскортный автомобиль с обоих концов в любое время","Транспарант «Oversize Load» спереди и сзади","Полицейское сопровождение","Движение только с полуночи до 5 a.m."],"explanation":"Теннесси требует размещения транспаранта «Oversize Load» спереди и сзади любого груза, превышающего 10 feet в ширину. Требования к сопровождению и прочие требования возрастают с увеличением ширины. Источник: правила выдачи разрешений TDOT Oversize/Overweight Permit."},"18":{"q":"Какова приблизительная стоимость годового разрешения Теннесси на превышение веса для транспортного средства с полной массой до 100,000 pounds?","options":["$50","$150","$750","$3,500"],"explanation":"Плата за годовое разрешение на превышение веса TDOT составляет $750 для транспортных средств с полной массой до 100,000 pounds, с более высокими ступенчатыми сборами для больших весов (например, до 120,000 lb по более высокой ставке). Источник: тарифная сетка TDOT Oversize/Overweight Permit Office."},"19":{"q":"В Теннесси перемещение сверхтяжёлых грузов, плавучих домов и мобильных домов по разрешению, как правило, ограничено каким временем движения?","options":["Только светлое время суток","Только ночное время","Только выходные дни","В любое время, 24 часа в сутки"],"explanation":"Теннесси ограничивает перемещение сверхтяжёлых грузов, плавучих домов и мобильных домов только светлым временем суток, а сопровождаемые грузы также должны соблюдать комендантские ограничения в часы пик в мегаполисах. Источник: правила выдачи разрешений TDOT Oversize/Overweight Permit."},"20":{"q":"В Теннесси какой класс CDL требуется для управления составом транспортных средств с полной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемое транспортное средство имеет GVWR более 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Теннесси определяет CDL класса Class A как требуемый для управления составом транспортных средств с GCWR более 26,000 lbs, где буксируемая единица превышает 10,000 lbs GVWR. Источник: Tenn. Comp. R. & Regs. 1340-01-13-.03; Tennessee CDL Manual."},"21":{"q":"Какой класс CDL в Теннесси требуется для управления одиночным транспортным средством с полной массой (GVWR) 26,001 pounds или более либо таким транспортным средством, буксирующим прицеп с GVWR не более 10,000 pounds?","options":["Class A","Class B","Class C","Class M"],"explanation":"Теннесси определяет CDL класса Class B как требуемый для одиночного транспортного средства с GVWR более 26,000 lbs либо такого транспортного средства, буксирующего единицу с GVWR не более 10,000 lbs. Источник: Tenn. Comp. R. & Regs. 1340-01-13-.03; Tennessee CDL Manual."},"22":{"q":"Водитель в Теннесси управляет одиночным транспортным средством с GVWR менее 26,001 pounds, на котором установлены таблички (placard) для опасных материалов или которое предназначено для перевозки 16 или более пассажиров, включая водителя. Какой класс CDL применяется?","options":["Class A","Class B","Class C","Class D"],"explanation":"CDL класса Class C в Теннесси охватывает одиночные транспортные средства с GVWR не более 26,000 lbs, которые должны иметь таблички для опасных материалов, предназначены для перевозки более 15 пассажиров (16+ включая водителя) или используются в качестве школьного автобуса. Источник: Tenn. Comp. R. & Regs. 1340-01-13-.03."},"23":{"q":"В Теннесси каков минимальный возраст для получения CDL, ограниченного только внутриштатной (в пределах штата) коммерческой ездой?","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"Теннесси разрешает заявителям в возрасте не менее 18 лет получать CDL только для внутриштатной эксплуатации. Источник: Tennessee CDL Manual; Tennessee Department of Safety and Homeland Security, Driver Services."},"24":{"q":"В Теннесси каков минимальный возраст, необходимый для управления коммерческим транспортным средством в межштатной торговле или для перевозки опасных материалов?","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"Теннесси требует, чтобы водителю было не менее 21 года для работы в межштатной торговле или для перевозки опасных материалов; водители в возрасте 18-20 лет ограничены внутриштатной эксплуатацией. Источник: Tennessee CDL Manual; 49 CFR 383.3 в применении в Теннесси."},"25":{"q":"Какая отметка (endorsement) требуется в Теннесси для управления коммерческим транспортным средством, перевозящим опасные материалы в количествах, требующих установки табличек (placard)?","options":["Отметка N","Отметка H","Отметка T","Отметка P"],"explanation":"Теннесси требует отметку H (Hazardous Materials) для управления CMV, перевозящим количества опасных материалов, требующие установки табличек. Источник: Tennessee CDL Manual; 49 CFR 383.93."},"26":{"q":"Прежде чем Теннесси сможет добавить отметку об опасных материалах (H) в CDL, федеральный закон требует, чтобы заявитель выполнил какой дополнительный шаг?","options":["Оценку угрозы безопасности TSA с проверкой биографических данных на основе отпечатков пальцев","40-часовой аудиторный курс по HazMat в Теннесси","Проверку зрения на весовой станции Tennessee DOT","Тест на наркотики и алкоголь, проводимый клерком округа"],"explanation":"Теннесси не может выдать отметку HazMat, пока заявитель не пройдёт проводимую TSA оценку угрозы безопасности, которая включает проверку биографических данных на основе отпечатков пальцев, в соответствии с законом USA PATRIOT Act. Источник: Tennessee Department of Safety and Homeland Security, страница HazMat Endorsement; 49 CFR 1572."},"27":{"q":"Какую отметку требует Теннесси для управления цистерной, предназначенной для перевозки жидкости или газа в стационарно установленной цистерне ёмкостью 1,000 gallons или более?","options":["Отметка H","Отметка N","Отметка T","Отметка S"],"explanation":"Теннесси требует отметку N (Tanker) для цистерн, предназначенных для перевозки жидкостей или газов в цистерне ёмкостью 1,000 gallons или более. Источник: Tennessee CDL Manual; 49 CFR 383.93."},"28":{"q":"Какая отметка требуется в Теннесси для буксировки двойных или тройных прицепов, и к какому классу CDL она привязана?","options":["Отметка T, доступна только на Class A","Отметка T, доступна только на Class B","Отметка N, доступна на любом классе","Отметка P, доступна только на Class C"],"explanation":"Теннесси требует отметку T (Doubles/Triples) для буксировки более одного прицепа, и поскольку такие составы требуют лицензии Class A, эта отметка доступна только на Class A. Источник: Tennessee CDL Manual; Tenn. Comp. R. & Regs. 1340-01-13."},"29":{"q":"Какую отметку требует Теннесси для управления коммерческим транспортным средством, предназначенным для перевозки 16 или более пассажиров, включая водителя?","options":["Отметка S","Отметка P","Отметка N","Отметка H"],"explanation":"Теннесси требует отметку P (Passenger) для управления транспортным средством, предназначенным для перевозки 16 или более человек, включая водителя. Источник: Tennessee CDL Manual; 49 CFR 383.93."},"30":{"q":"В Теннесси отметка о школьном автобусе (S) требует, чтобы водитель сначала имел какую другую отметку?","options":["Отметку H (HazMat)","Отметку N (Tanker)","Отметку P (Passenger)","Отметку T (Doubles/Triples)"],"explanation":"В Теннесси отметка S (School Bus) требует наличия отметки P (Passenger) в качестве предварительного условия, поскольку школьный автобус является транспортным средством для перевозки пассажиров. Источник: Tennessee CDL Manual; 49 CFR 383.93."},"31":{"q":"Согласно федеральному правилу, применяемому в Теннесси, сколько времени после первоначальной выдачи разрешения на обучение коммерческому вождению (CLP) его обладатель должен ждать, прежде чем получит право сдавать экзамен на навыки CDL?","options":["7 days","14 days","30 days","60 days"],"explanation":"Обладатель CLP не имеет права сдавать экзамен на навыки CDL в течение первых 14 days после первоначальной выдачи CLP. Источник: 49 CFR 383.25 в применении Tennessee Driver Services; Tennessee CDL Manual."},"32":{"q":"Согласно федеральным стандартам, соблюдаемым в Теннесси, разрешение на обучение коммерческому вождению (CLP) действительно не более какого срока с первоначальной даты выдачи без повторной сдачи теоретических экзаменов?","options":["30 days","90 days","6 months","1 year"],"explanation":"CLP должно быть действительно не более одного года (1 year) с первоначальной даты выдачи без требования к обладателю повторно сдавать теоретические экзамены; штаты обычно выдают его на срок до 180 days с одним продлением. Источник: 49 CFR 383.25; Tennessee Driver Services."},"33":{"q":"При управлении коммерческим транспортным средством по разрешению на обучение коммерческому вождению (CLP) Теннесси, какой надзор требуется?","options":["Обладатель CDL соответствующего класса и с соответствующими отметками должен сидеть рядом с обладателем CLP","Надзор не требуется, если водителю больше 21 года","Сотрудник правоохранительных органов должен следовать за ним на отдельном автомобиле","Любой лицензированный водитель Class D может ехать на заднем сиденье"],"explanation":"Обладатель CLP может управлять транспортным средством только в сопровождении обладателя CDL, который имеет соответствующий класс и отметки и сидит на переднем сиденье рядом с обладателем разрешения. Источник: 49 CFR 383.25; Tennessee CDL Manual."},"34":{"q":"При подаче заявления на CDL или CLP в Теннесси, сколько подтверждений проживания в Теннесси должен предоставить заявитель?","options":["Одно подтверждение проживания","Два подтверждения проживания","Три подтверждения проживания","Подтверждение проживания не требуется"],"explanation":"Теннесси требует от заявителей предоставить два (2) подтверждения проживания в Теннесси, наряду с подтверждением личности/законного пребывания и номером социального страхования. Источник: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL."},"35":{"q":"Какой набор документов должен предоставить заявитель на CDL в Теннесси для подтверждения права на получение?","options":["Подтверждение личности/законного пребывания, подтверждение номера социального страхования и два подтверждения проживания в Теннесси","Только карту регистрации избирателя в Теннесси","Только паспорт и один счёт за коммунальные услуги","Свидетельство о рождении и право собственности на транспортное средство"],"explanation":"Теннесси требует подтверждение личности и законного пребывания (гражданство США или статус законного постоянного резидента), подтверждение номера социального страхования и два подтверждения проживания в Теннесси. Источник: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL."},"36":{"q":"Какое обучение должны пройти новые заявители в Теннесси, прежде чем сдавать экзамен на навыки CDL для лицензии Class A или Class B либо перед добавлением определённых отметок?","options":["Обучение водителей начального уровня (ELDT) у поставщика из реестра поставщиков обучения FMCSA (Training Provider Registry)","Курс безопасного вождения в общественном колледже Теннесси","Четырёхлетнее ученичество, зарегистрированное в округе","Программу совместных поездок с Tennessee Highway Patrol"],"explanation":"Теннесси требует, чтобы новые заявители прошли обучение водителей начального уровня (ELDT) у школы, включённой в реестр поставщиков обучения FMCSA, перед экзаменом на навыки для Class A/B или для отметок H, P или S. Источник: 49 CFR Part 380 Subpart F; Tennessee Driver Services, страница CDL."},"37":{"q":"При самосертификации для CDL в Теннесси, какая категория описывает водителя, который работает в межштатной торговле и должен соответствовать требованию о наличии справки медицинского эксперта федерального DOT?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Водитель, который самосертифицируется как Non-Excepted Interstate, работает в межштатной торговле и должен иметь действующую справку медицинского эксперта федерального DOT. Источник: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71."},"38":{"q":"Из скольких категорий самосертификации должен выбирать заявитель на CDL в Теннесси относительно типа коммерческого вождения, которым он занимается?","options":["Из двух","Из трёх","Из четырёх","Из пяти"],"explanation":"Обладатели CDL в Теннесси должны самосертифицироваться в одну из четырёх категорий: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate. Источник: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71."},"39":{"q":"Водитель в Теннесси самосертифицируется как Non-Excepted Interstate. Чтобы сохранить CDL действительным, что водитель должен держать в деле у штата?","options":["Действующую справку медицинского эксперта федерального уровня от сертифицированного эксперта","Нотариально заверенное письмо от своего работодателя","Копию своего диплома об окончании средней школы","Стикер ежегодного технического осмотра транспортного средства"],"explanation":"Водители категории non-excepted должны получить и поддерживать действующую справку медицинского эксперта федерального уровня от сертифицированного медицинского эксперта из национального реестра FMCSA (National Registry) и держать её в деле у штата. Источник: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 391.45."},"40":{"q":"В Теннесси какова максимальная концентрация алкоголя в крови (BAC), при которой человек может законно управлять коммерческим транспортным средством (CMV)?","options":["0.02","0.04","0.08","0.10"],"explanation":"Теннесси следует федеральному стандарту: управление CMV с BAC 0.04 или выше является серьёзным (major) нарушением. Это половина предела 0.08 для некоммерческих водителей. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1; T.C.A. 55-50-405."},"41":{"q":"Водитель впервые осуждён за управление CMV с BAC 0.04 или выше, НЕ перевозя при этом опасные материалы. На какой срок дисквалифицируется CDL?","options":["60 days","6 months","1 year","3 years"],"explanation":"Первое серьёзное (major) нарушение (включая BAC 0.04 или выше в CMV) приводит к дисквалификации CDL не менее чем на 1 year в Теннесси. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1."},"42":{"q":"Водитель совершает первое серьёзное алкогольное нарушение, управляя CMV, на котором были установлены таблички (placard) для опасных материалов. Каков срок дисквалификации?","options":["1 year","2 years","3 years","5 years"],"explanation":"Когда первое серьёзное (major) нарушение происходит во время перевозки CMV опасных материалов с табличками, срок дисквалификации в Теннесси увеличивается с 1 year до 3 years. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1."},"43":{"q":"Согласно закону Теннесси о подразумеваемом согласии (implied consent), каковы последствия для обладателя CDL, который впервые отказывается от обязательного химического анализа/анализа крови на алкоголь?","options":["Только предупреждение","Лишение CDL на 60 days","Лишение CDL на 1 year","Лишение CDL на 90 days"],"explanation":"Отказ от прохождения теста на алкоголь рассматривается в Теннесси как серьёзное (major) нарушение, приводящее к дисквалификации CDL не менее чем на 1 year, как и при первом осуждении за вождение с превышением предела BAC. Источник: Tennessee CDL Manual (Disqualifications); T.C.A. 55-50-405; 49 CFR 383.51."},"44":{"q":"Обладатель CDL осуждён за ВТОРОЕ серьёзное (major) нарушение (например, второе нарушение BAC-0.04) за свою водительскую карьеру. Каков срок дисквалификации в Теннесси?","options":["3 years","10 years","Пожизненно","5 years"],"explanation":"Второе серьёзное (major) нарушение приводит к пожизненной дисквалификации CDL. Теннесси не принял факультативное положение о восстановлении через 10 years, поэтому пожизненный запрет является постоянным. Источник: Tennessee CDL Manual (Disqualifications); руководство TN Dept. of Safety по серьёзным нарушениям CDL; 49 CFR 383.51 Table 1."},"45":{"q":"Использование коммерческого транспортного средства для совершения тяжкого преступления (felony), связанного с изготовлением, распространением или сбытом контролируемого вещества, влечёт за собой какую дисквалификацию в Теннесси?","options":["1 year","3 years","Пожизненно, без восстановления","5 years"],"explanation":"Использование CMV при совершении тяжкого преступления (felony), связанного с контролируемыми веществами, влечёт пожизненную дисквалификацию без возможности восстановления в Теннесси. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1."},"46":{"q":"Сколько серьёзных нарушений правил дорожного движения (serious traffic violations) должен совершить водитель CDL в течение 3-летнего периода, прежде чем в Теннесси будет применена ПЕРВАЯ дисквалификация?","options":["1 нарушение","2 нарушения","3 нарушения","4 нарушения"],"explanation":"Одно серьёзное нарушение правил дорожного движения не вызывает дисквалификацию. Первая дисквалификация (60 days) применяется при ВТОРОМ серьёзном нарушении в течение 3 лет. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"47":{"q":"Водитель CDL осуждён за ДВА серьёзных нарушения правил дорожного движения в течение 3-летнего периода. Каков срок дисквалификации?","options":["30 days","60 days","120 days","1 year"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 лет приводят к дисквалификации CDL на 60 days в Теннесси. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"48":{"q":"Водитель CDL накапливает ТРИ серьёзных нарушения правил дорожного движения в течение 3-летнего периода. Каков срок дисквалификации?","options":["60 days","90 days","120 days","180 days"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение 3 лет приводят к дисквалификации CDL на 120 days в Теннесси. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"49":{"q":"При каком превышении установленного ограничения превышение скорости считается «серьёзным нарушением правил дорожного движения» для обладателя CDL в Теннесси?","options":["10 mph или более сверх лимита","15 mph или более сверх лимита","20 mph или более сверх лимита","25 mph или более сверх лимита"],"explanation":"Превышение скорости на 15 mph или более сверх установленного ограничения скорости классифицируется как серьёзное нарушение правил дорожного движения. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"50":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение правил дорожного движения, а не как серьёзное (major) нарушение для водителя CDL в Теннесси?","options":["Управление CMV с BAC 0.04 или выше","Неосторожное вождение / слишком короткая дистанция","Оставление места происшествия","Использование CMV для совершения тяжкого преступления (felony)"],"explanation":"Неосторожное вождение, слишком короткая дистанция и неправильная/беспорядочная смена полос являются серьёзными нарушениями правил дорожного движения. Остальные перечисленные варианты являются серьёзными (major) нарушениями, влекущими дисквалификацию на 1 year (или пожизненно). Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Tables 1 and 2."},"51":{"q":"Отправка текстовых сообщений во время управления CMV классифицируется по правилам CDL Теннесси как что из перечисленного?","options":["Серьёзное (major) нарушение (дисквалификация на 1 year)","Серьёзное нарушение правил дорожного движения","Нарушение предписания о выводе из эксплуатации (out-of-service order)","Нарушение, не влекущее дисквалификации"],"explanation":"Как отправка текстовых сообщений, так и использование ручного мобильного телефона во время управления CMV являются серьёзными нарушениями правил дорожного движения, которые могут учитываться при дисквалификации на 60 days/120 days. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2; FMCSA 392.80/392.82."},"52":{"q":"Водитель CDL получает ВТОРОЕ осуждение за использование ручного мобильного телефона во время управления CMV, причём второе происходит в течение 3 лет после первого. Какая дисквалификация применяется?","options":["Дисквалификация отсутствует","60 days","120 days","1 year"],"explanation":"Использование ручного телефона является серьёзным нарушением правил дорожного движения. Второе серьёзное нарушение в течение 3 лет влечёт дисквалификацию на 60 days. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"53":{"q":"Каков срок дисквалификации за ПЕРВОЕ осуждение за нарушение правил пересечения железнодорожного переезда водителем CDL в Теннесси?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 year"],"explanation":"Первое нарушение правил пересечения железнодорожного переезда влечёт дисквалификацию не менее чем на 60 days. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3."},"54":{"q":"Водитель CDL в Теннесси осуждён за ВТОРОЕ нарушение правил пересечения железнодорожного переезда в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["60 days","90 days","120 days","180 days"],"explanation":"Второе нарушение правил пересечения железнодорожного переезда в течение 3 лет приводит к дисквалификации не менее чем на 120 days. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3."},"55":{"q":"Водитель CDL в Теннесси осуждён за ТРЕТЬЕ нарушение правил пересечения железнодорожного переезда в течение 3-летнего периода. Какова минимальная дисквалификация?","options":["120 days","180 days","1 year","3 years"],"explanation":"Третье нарушение правил пересечения железнодорожного переезда в течение 3 лет приводит к дисквалификации не менее чем на 1 year. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3."},"56":{"q":"Каков минимальный срок дисквалификации за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) (в CMV, не перевозящем опасные материалы или пассажиров) для водителя CDL в Теннесси?","options":["30 days","90 days","180 days","1 year"],"explanation":"Первое нарушение предписания о выводе из эксплуатации приводит к дисквалификации не менее чем на 180 days (до 1 year). Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4."},"57":{"q":"Помимо дисквалификации, какой минимальный гражданский штраф грозит водителю в Теннесси за ПЕРВОЕ нарушение предписания о выводе из эксплуатации (out-of-service order)?","options":["$1,000","$2,500","$5,000","$10,000"],"explanation":"Первое нарушение предписания о выводе из эксплуатации влечёт минимальный гражданский штраф в размере $2,500 в дополнение к дисквалификации на 180 days; второе влечёт минимум $5,000. Источник: Tennessee CDL Manual / TN Dept. of Safety; 49 CFR 383.53."},"58":{"q":"Водитель CDL в Теннесси совершает ВТОРОЕ нарушение предписания о выводе из эксплуатации (out-of-service order) в течение 10-летнего периода (без опасных материалов). Какова минимальная дисквалификация?","options":["180 days","1 year","2 years","5 years"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет приводит к дисквалификации не менее чем на 2 years (и минимальному гражданскому штрафу в размере $5,000). Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4."},"59":{"q":"Водитель впервые нарушает предписание о выводе из эксплуатации (out-of-service order) во время перевозки CMV опасных материалов с табличками (placard). Каков срок дисквалификации?","options":["Не менее 60 days","Не менее 180 days, до 2 years","Ровно 1 year","Пожизненно"],"explanation":"Первое нарушение предписания о выводе из эксплуатации во время перевозки опасных материалов с табличками (или при перевозке 16+ пассажиров) влечёт повышенную дисквалификацию не менее чем на 180 days и до 2 years. Источник: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4."},"60":{"q":"На автомагистрали в Теннесси, имеющей не менее четырёх полос, закон «Уступи дорогу» (Move Over) требует, чтобы приближающийся водитель, проезжающий мимо остановившегося аварийного транспортного средства с включёнными проблесковыми маячками, сделал что, когда это безопасно?","options":["Перестроился в полосу, не примыкающую к остановившемуся транспортному средству","Полностью остановился до тех пор, пока аварийное транспортное средство не уедет","Съехал на правую обочину и продолжил движение мимо","Подал звуковой сигнал и сохранял установленную скорость"],"explanation":"Закон Теннесси «Уступи дорогу» (T.C.A. 55-8-132) требует, чтобы водители на автомагистрали с четырьмя или более полосами уступали дорогу, перестраиваясь в полосу, которая НЕ примыкает к остановившемуся транспортному средству, когда это безопасно; только если перестроение невозможно или небезопасно, водитель может вместо этого снизить скорость до безопасной. Источник: T.C.A. 55-8-132."},"61":{"q":"Согласно закону Теннесси «Уступи дорогу» (Move Over), если водитель CMV не может безопасно перестроиться, проезжая мимо остановившегося коммунального или ремонтного транспортного средства с включёнными проблесковыми маячками, что водитель должен сделать вместо этого?","options":["Полностью остановиться на проезжей части","Снизить скорость до безопасной с учётом дорожных условий","Снизить скорость ровно на 25 mph ниже ограничения","Съехать на противоположную обочину"],"explanation":"T.C.A. 55-8-132 распространяется на полицейские, пожарные машины, машины скорой помощи, коммунальные, эвакуаторы и машины дорожного обслуживания. Если перестроение невозможно или небезопасно, водитель должен снизить скорость до безопасной с учётом дорожных условий; закон не устанавливает конкретного числового снижения. Источник: T.C.A. 55-8-132."},"62":{"q":"Нарушение закона Теннесси «Уступи дорогу» (непринятие мер по перестроению или снижению скорости перед остановившимся аварийным транспортным средством) классифицируется как что?","options":["Гражданское правонарушение, не связанное с движением","Фелония класса C (Class C felony)","Мисдиминор класса B (Class B misdemeanor)","Только простое предупреждение"],"explanation":"Нарушение закона Теннесси «Уступи дорогу» является мисдиминором класса B (Class B misdemeanor), наказуемым штрафом до $500 (и возможным тюремным заключением в отягчающих случаях). Источник: T.C.A. 55-8-132."},"63":{"q":"Каково максимальное установленное ограничение скорости, разрешённое на межштатных автомагистралях Теннесси?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Теннесси устанавливает законодательный максимум 70 mph на межштатных автомагистралях. Источник: T.C.A. 55-8-152."},"64":{"q":"Согласно законодательству Теннесси, на автомагистралях, которые НЕ являются межштатными или четырёхполосными дорогами с контролируемым доступом, какова общая максимальная скорость для грузовика (с номинальной грузоподъёмностью 1.5-ton или более)?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"T.C.A. 55-8-152 ограничивает скорость грузовиков (с номинальной грузоподъёмностью 1.5-ton или более) до 55 mph на автомагистралях, кроме межштатных и четырёхполосных дорог с контролируемым доступом, где ограничение составляет 65 mph. Источник: T.C.A. 55-8-152."},"65":{"q":"В Теннесси какова минимальная законная скорость для транспортного средства, движущегося по левой (обгонной) полосе автомагистрали с контролируемым доступом, имеющей четыре или более полос?","options":["40 mph","45 mph","55 mph","65 mph"],"explanation":"В Теннесси запрещается движение со скоростью ниже 55 mph по левой полосе автомагистрали с контролируемым доступом, имеющей четыре или более полос. Источник: T.C.A. 55-8-152."},"66":{"q":"Когда водитель CMV в Теннесси обязан остановиться на железнодорожном переезде, где должно остановиться транспортное средство относительно ближайшего рельса?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 25 feet, но не ближе 5 feet","В пределах 100 feet, но не ближе 50 feet","Ровно в 10 feet от рельса"],"explanation":"Водитель, обязанный остановиться, должен остановиться в пределах 50 feet, но не ближе 15 feet от ближайшего рельса, затем посмотреть и прислушаться перед продолжением движения. Источник: Tennessee CDL Manual; 49 CFR 392.10."},"67":{"q":"Какое из перечисленных транспортных средств ВСЕГДА должно останавливаться на железнодорожном переезде в Теннесси, даже когда поезд не виден?","options":["Любой пустой бортовой прицеп","Автобус с пассажирами и транспортное средство с табличками опасных грузов","Любой трёхосный грузовик с цельной рамой","Любое транспортное средство тяжелее 26,001 pounds"],"explanation":"К CMV, которые должны останавливаться на железнодорожных переездах, относятся автобусы с пассажирами и транспортные средства с табличками опасных грузов; большинство других CMV не обязаны останавливаться, если этого не требуют сигналы. Источник: Tennessee CDL Manual; 49 CFR 392.10."},"68":{"q":"Пока какая-либо часть CMV в Теннесси находится на железнодорожных путях во время проезда переезда, водитель НЕ должен делать что из перечисленного?","options":["Держать обе руки на руле","Смотреть в обе стороны вдоль пути","Переключать передачи","Поддерживать равномерную скорость"],"explanation":"Водители не должны останавливаться, переключать передачи или менять полосу, пока какая-либо часть транспортного средства пересекает пути, поскольку неудачное переключение может оставить транспортное средство заглохшим на рельсах. Источник: Tennessee CDL Manual; 49 CFR 392.10."},"69":{"q":"На двухполосной дороге в Теннесси с движением в обоих направлениях, что должен сделать водитель, когда школьный автобус останавливается и включает красные проблесковые маячки для посадки или высадки детей?","options":["Остановиться должны только транспортные средства позади автобуса","Остановиться должны транспортные средства в обоих направлениях","Снизить скорость до 15 mph и проехать с осторожностью","Объехать автобус слева, если детей не видно"],"explanation":"На дороге без разделения водители в ОБОИХ направлениях должны остановиться перед школьным автобусом с включёнными красными проблесковыми маячками и выдвинутым знаком «Стоп» до тех пор, пока он не будет убран. Источник: T.C.A. 55-8-151."},"70":{"q":"В Теннесси водитель, встречающий остановившийся школьный автобус со встречного направления, освобождается от обязанности остановиться только тогда, когда проезжие части разделены чем?","options":["Нарисованной центральной линией","Полосой для левого поворота в обоих направлениях («полоса самоубийц»)","Промежутком или физическим барьером, не пригодным для движения транспорта (раздельные проезжие части)","Не менее чем тремя полосами движения"],"explanation":"Исключение в Теннесси применяется только на автомагистрали с раздельными проезжими частями, то есть когда направления разделены промежутком или барьером, не пригодным для движения транспорта. Просто нарисованная линия или центральная полоса для поворота НЕ подходят, поэтому водители всё равно должны остановиться. Источник: T.C.A. 55-8-151."},"71":{"q":"Первое нарушение, связанное с незаконным объездом остановившегося школьного автобуса в Теннесси, классифицируется как что?","options":["Нарушение, не связанное с движением","Мисдиминор класса A (Class A misdemeanor)","Мисдиминор класса C (Class C misdemeanor)","Только гражданский штраф"],"explanation":"Незаконный объезд остановившегося школьного автобуса является мисдиминором класса A (Class A misdemeanor) в Теннесси, со штрафом не менее $250 и не более $1,000 за первое нарушение. Источник: T.C.A. 55-8-151."},"72":{"q":"В Теннесси, когда водитель незаконно объезжает остановившийся школьный автобус, сбивает человека и причиняет ему смерть, до какого уровня повышается тяжесть правонарушения?","options":["Мисдиминор класса A (Class A misdemeanor)","Фелония класса E (Class E felony)","Фелония класса C (Class C felony)","Мисдиминор класса B (Class B misdemeanor)"],"explanation":"Наезд на человека при незаконном объезде остановившегося школьного автобуса является фелонией класса E (Class E felony); если наезд приводит к смерти, это фелония класса C (Class C felony). Источник: T.C.A. 55-8-151."},"73":{"q":"Теннесси уполномочивает TDOT ограничивать движение седельных тягачей и полуприцепов определёнными полосами на межштатных и многополосных разделённых автомагистралях, имеющих сколько полос в каждом направлении?","options":["Одну или более","Две или более","Три или более","Пять или более"],"explanation":"T.C.A. 55-8-195 уполномочивает TDOT направлять седельные тягачи и полуприцепы на определённые полосы на межштатных и многополосных разделённых автомагистралях с тремя или более полосами в каждом направлении; нарушение является мисдиминором класса C (Class C misdemeanor) (штраф до $50). Источник: T.C.A. 55-8-195."},"74":{"q":"Согласно закону Теннесси о левой полосе (Slow Poke), когда водитель может законно двигаться по крайней левой обгонной полосе межштатной или многополосной разделённой автомагистрали?","options":["Когда движение неинтенсивное","Только при обгоне или объезде транспортного средства в необгонной полосе","В любое время, пока соблюдается ограничение скорости","Только в период от заката до восхода солнца"],"explanation":"Закон Теннесси о левой полосе (T.C.A. 55-8-204) ограничивает использование обгонной полосы обгоном или объездом транспортного средства в необгонной полосе; задержка на ней в иных случаях запрещена. Источник: T.C.A. 55-8-204."},"75":{"q":"Когда CMV остановлен на обочине в Теннесси, где должен быть размещён самый дальний предупреждающий треугольник для обычной двухполосной двусторонней дороги?","options":["В 10 feet позади транспортного средства","В 40 feet позади транспортного средства","В 100 feet позади транспортного средства","В 200 feet позади транспортного средства"],"explanation":"Предупреждающие устройства должны быть выставлены в течение 10 минут: одно примерно в 10 feet позади со стороны движения, одно примерно в 100 feet позади, и одно примерно в 100 feet впереди (в направлении приближающегося транспорта). Источник: Tennessee CDL Manual; 49 CFR 392.22."},"76":{"q":"Как скоро после остановки водитель CMV в Теннесси должен разместить требуемые аварийные предупреждающие устройства (треугольники)?","options":["В течение 10 минут","В течение 30 минут","Немедленно, до выхода из кабины","В течение 1 часа"],"explanation":"Водитель остановившегося CMV должен разместить три предупреждающих треугольника в течение 10 минут после остановки. Источник: Tennessee CDL Manual; 49 CFR 392.22."},"77":{"q":"Без специального разрешения, какова максимальная законная ширина коммерческого транспортного средства с грузом в Теннесси?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 6 inches","10 feet 0 inches"],"explanation":"Законный максимум ширины в Теннесси без разрешения на негабаритный груз составляет 8 feet 6 inches; законная высота — 13 feet 6 inches. Превышение этих значений требует специального разрешения TDOT. Источник: правила TDOT по разрешениям на негабаритные/тяжеловесные грузы; T.C.A. Title 55, Ch. 7."},"78":{"q":"Разрешения Теннесси на негабаритные грузы, как правило, ограничивают движение каким временным интервалом?","options":["Только светлое время суток (примерно за полчаса до восхода и до получаса после заката)","Только ночное время, чтобы избежать пробок","Любой 24-часовой период, включая воскресенья","Только с 9:00 a.m. до 4:00 p.m."],"explanation":"Разрешения Теннесси на негабаритные грузы, как правило, допускают движение в светлое время суток (примерно за полчаса до восхода и до получаса после заката), с понедельника по субботу, без движения по воскресеньям и крупным праздникам, с комендантскими ограничениями в часы пик в крупных округах. Источник: правила TDOT по разрешениям на негабаритные/тяжеловесные грузы."},"79":{"q":"На крутом спуске в восточном направлении горы Монтигл (Monteagle Mountain) на I-24 в Теннесси, какое средство безопасности предусмотрено для грузовиков, потерявших тормоза?","options":["Обязательный пункт оплаты проезда","Аварийные съезды для грузовиков, заполненные гравием","Обязательная паромная переправа","Реверсивная экспресс-полоса"],"explanation":"Спуск с горы Монтигл (Monteagle Mountain) на I-24 (уклон около 6%) оборудован аварийными съездами для грузовиков, заполненными гравием, а коммерческие грузовики направляются к станции инспекции/проверки тормозов перед спуском. Источник: TDOT; рекомендации Tennessee CDL Manual по вождению в горах."},"80":{"q":"Какое государственное ведомство отвечает за выдачу коммерческих водительских удостоверений (CDL) в Теннесси?","options":["Tennessee Department of Safety and Homeland Security","Tennessee Department of Transportation (TDOT)","Tennessee Department of Motor Vehicles","Tennessee Public Service Commission"],"explanation":"CDL в Теннесси выдаются Tennessee Department of Safety and Homeland Security (TDOSHS) через её центры обслуживания водителей (Driver Services). В Теннесси нет отдельного «Department of Motor Vehicles»; TDOT занимается автомагистралями, а не выдачей удостоверений. Источник: Tennessee CDL Manual; tn.gov/safety Driver Services."},"81":{"q":"Где заявитель в Теннесси сдаёт общий теоретический экзамен на CDL и любые теоретические экзамены на специальные допуски (endorsements)?","options":["В центре обслуживания водителей полного цикла (Driver Services Center), управляемом Department of Safety","В любой автошколе для водителей грузовиков, зарегистрированной FMCSA","В окружном офисе Tennessee Department of Transportation","Онлайн через портал e-Services из дома"],"explanation":"Центры обслуживания водителей полного цикла Теннесси (Driver Services Centers) проводят общий теоретический экзамен на CDL и теоретические экзамены на любые специальные допуски. Школы обеспечивают обучение (ELDT), а не государственный теоретический экзамен. Источник: Tennessee CDL Manual; tn.gov/safety Driver Services «How do I obtain a CDL»."},"82":{"q":"Прежде чем получить ученическое коммерческое разрешение (CLP), что заявитель в Теннесси должен сделать в первую очередь?","options":["Сдать общий теоретический экзамен на CDL","Сдать трёхчастный экзамен по навыкам","Пройти практическое обучение ELDT на учебной площадке","Удерживать CLP не менее 14 дней"],"explanation":"Чтобы получить CLP, заявитель в Теннесси должен сдать общий теоретический экзамен на CDL (плюс необходимые экзамены на специальные допуски). Экзамен по навыкам и 14-дневное ожидание следуют после выдачи CLP. Источник: Tennessee CDL Manual; tn.gov/safety Driver Services."},"83":{"q":"Какой набор документов заявитель на CDL в Теннесси должен предъявить в центре обслуживания водителей (Driver Services Center)?","options":["Подтверждение личности, номер социального страхования, гражданство США/законное пребывание и проживание в Теннесси","Только действующий паспорт и крупную кредитную карту","Аттестат об окончании средней школы и два рекомендательных письма от работодателей","Только право собственности на транспортное средство и его текущую регистрацию"],"explanation":"Теннесси требует подтверждение личности, подтверждение номера социального страхования, подтверждение гражданства США или статуса законного постоянного резидента, а также два документа, подтверждающих проживание/место жительства в Теннесси. Источник: Tennessee CDL Manual; tn.gov/safety Driver Services требования к документам."},"84":{"q":"Из скольких отдельных категорий коммерческой деятельности должен выбрать заявитель на CDL в Теннесси при заполнении аффидевита о самосертификации?","options":["Четыре","Две","Три","Пять"],"explanation":"Аффидевит о самосертификации Теннесси (SF-1480) перечисляет четыре варианта: межштатные неисключённые, межштатные исключённые, внутриштатные неисключённые и внутриштатные исключённые перевозки. Водитель ставит инициалы ровно напротив одного. Источник: Tennessee SF-1480 Self-Certification Affidavit; tn.gov/safety."},"85":{"q":"Какая категория самосертификации требует, чтобы держатель CDL в Теннесси предоставил действующий федеральный медицинский сертификат DOT?","options":["Межштатные неисключённые (non-excepted interstate)","Межштатные исключённые (excepted interstate)","Внутриштатные исключённые (excepted intrastate)","Межштатные исключённые, перевозящие только сельскохозяйственные материалы"],"explanation":"Водитель, который самосертифицируется как межштатный неисключённый (non-excepted interstate), подпадает под действие 49 CFR 391.45 и должен предоставить действующий медицинский сертификат. Исключённые категории не обязаны предоставлять федеральную медицинскую карту. Источник: Tennessee SF-1480; tn.gov/safety Medical Certification Requirements."},"86":{"q":"В Теннесси, как обычно называется федеральный медицинский сертификат DOT, который держатели CDL категории межштатных неисключённых перевозок должны поддерживать действующим?","options":["Медицинская карта (DOT card)","Карта допуска на опасные материалы (HazMat)","Сертификат Selective Service","Карта TWIC"],"explanation":"Медицинский сертификат (форма MCSA-5876) согласно 49 CFR 391.45 обычно называют «медицинской картой» или «DOT card». TWIC и допуск HazMat — это отдельные документы. Источник: Tennessee Medical Certification Requirements; tn.gov/safety."},"87":{"q":"Как держатель CDL в Теннесси может подать новый аффидевит о самосертификации и обновлённый медицинский сертификат в штат?","options":["Загрузив через портал e-Services Department of Safety или посетив центр обслуживания водителей (Driver Services Center)","Отправив его напрямую почтой в FMCSA National Registry","Отправив его по электронной почте в Tennessee Department of Transportation","Передав его медицинскому эксперту, который подаёт его секретарю округа"],"explanation":"Держатели CDL в Теннесси подают аффидевит о самосертификации (и медицинский сертификат, когда это требуется) путём загрузки через портал e-Services Department of Safety или лично в центре обслуживания водителей. Источник: tn.gov/safety Medical Certification Requirements."},"88":{"q":"Держатель CDL в Теннесси должен подать обновлённый медицинский сертификат для поддержания актуального статуса в какой момент относительно срока истечения медицинской карты?","options":["Не менее чем за пять рабочих дней до истечения срока действия текущего медицинского сертификата","В течение 30 дней после того, как сертификат уже истёк","Только раз в восемь лет при продлении удостоверения","В течение одного года после истечения срока действия сертификата"],"explanation":"Теннесси предписывает держателям CDL подавать обновлённые документы по самосертификации/медицинские документы не менее чем за пять (5) рабочих дней до истечения срока действия текущего медицинского сертификата, чтобы избежать понижения категории. Источник: tn.gov/safety Medical Certification Requirements."},"89":{"q":"Когда ВСЕ новые заявители на CDL в Теннесси должны пройти обучение водителей начального уровня (ELDT)?","options":["Перед сдачей экзамена по навыкам на CDL","Только после того, как CDL уже выдано","В течение одного года после сдачи экзамена по навыкам","Только при подаче заявления на допуск HazMat"],"explanation":"С 7 февраля 2022 года ELDT от поставщика, внесённого в FMCSA Training Provider Registry, должно быть пройдено до того, как впервые подающий заявление на категорию Class A/B (и некоторые заявители на специальные допуски) сможет сдать экзамен по навыкам/теоретический экзамен. Источник: tn.gov/safety страница ELDT; 49 CFR Part 380."},"90":{"q":"Где должен быть зарегистрирован поставщик ELDT заявителя на CDL в Теннесси, чтобы обучение засчиталось?","options":["В FMCSA Training Provider Registry (TPR)","В списке подрядчиков Tennessee Department of Transportation","В реестре предприятий Tennessee Secretary of State","В списке поставщиков National Highway Traffic Safety Administration"],"explanation":"ELDT должно проводиться организацией, внесённой в Training Provider Registry (TPR) Федеральной администрации безопасности автоперевозчиков (FMCSA). Обучение у поставщика, не внесённого в реестр, не удовлетворяет требованию. Источник: tn.gov/safety ELDT; FMCSA TPR."},"91":{"q":"После выдачи CLP в Теннесси, как долго держатель должен ждать, прежде чем ему будет разрешено сдавать экзамен по навыкам на CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Федеральные правила и правила Теннесси требуют, чтобы CLP удерживалось минимум 14 дней, прежде чем держатель сможет сдать экзамен по навыкам на CDL. Источник: Tennessee CDL Manual; 49 CFR 383.25."},"92":{"q":"Из каких трёх частей состоит экзамен по навыкам на CDL в Теннесси, в каком порядке?","options":["Предрейсовый осмотр транспортного средства, базовые навыки управления транспортным средством и вождение на дороге","Проверка зрения, теоретический экзамен и параллельная парковка","Экзамен по пневматическим тормозам, экзамен HazMat и вождение ночью","Письменный экзамен, тест на наркотики и вождение на дороге"],"explanation":"Экзамен по навыкам на CDL в Теннесси состоит из трёх частей: предрейсовый осмотр транспортного средства, экзамен по базовым навыкам управления транспортным средством и экзамен по вождению на дороге — именно в таком порядке. Источник: Tennessee CDL Manual."},"93":{"q":"Заявитель в Теннесси сдаёт экзамен по навыкам на CDL на транспортном средстве, которое представляет что?","options":["Класс и тип транспортного средства, на управление которым заявитель намерен получить право","Любой легковой автомобиль, предоставленный штатом","Транспортное средство на один класс меньше запрашиваемой категории","Только грузовик с цельной рамой класса C, независимо от запрашиваемой категории"],"explanation":"Экзамен по навыкам должен сдаваться на репрезентативном транспортном средстве того класса и конфигурации, для которых запрашивается CDL; используемое транспортное средство может ограничить выдаваемый класс удостоверения. Источник: Tennessee CDL Manual; 49 CFR 383.71/383.133."},"94":{"q":"Согласно федеральному стандарту, которому следует Теннесси, как долго действует ученическое коммерческое разрешение (CLP), прежде чем его необходимо продлить или повторно сдать теоретические экзамены?","options":["180 дней, с возможностью однократного продления ещё на 180 дней","30 дней, без возможности продления","Пять лет, как у обычного удостоверения","90 дней, с возможностью продления до трёх раз"],"explanation":"Согласно 49 CFR 383.25, который применяет Теннесси, CLP действует 180 дней и может быть однократно продлено ещё на 180 дней без повторной сдачи общего теоретического экзамена. Источник: Tennessee CDL Manual; 49 CFR 383.25."},"95":{"q":"Если CLP заявителя в Теннесси истекает до получения CDL, что происходит со сданными экзаменами?","options":["Теоретический экзамен и экзамен по навыкам становятся недействительными и должны быть пересданы","Теряется только экзамен по навыкам; результаты теоретического экзамена остаются действительными в течение пяти лет","Ничего; результаты постоянны после успешной сдачи","Экзамены автоматически остаются действительными ещё на один год"],"explanation":"Если CLP истекает до выдачи полного CDL, заявитель теряет зачёт и должен пересдать теоретический экзамен и экзамен по навыкам. Источник: Tennessee CDL Manual; Tennessee Driver Services."},"96":{"q":"Каков стандартный цикл истечения срока действия коммерческого водительского удостоверения Теннесси, выданного взрослому?","options":["Восемь лет","Четыре года","Десять лет","Два года"],"explanation":"Водительские удостоверения Теннесси, включая CDL, как правило, действительны в течение восьми лет (согласно Tenn. Code Ann. 55-50-337), после чего их необходимо продлить. Источник: Tenn. Code Ann. 55-50-337; tn.gov/safety Renewing Your License."},"97":{"q":"Как обычно осуществляется продление CDL в Теннесси?","options":["Лично в центре обслуживания водителей (Driver Services Center), с предоставлением действующего медицинского сертификата","Полностью онлайн без каких-либо документов","Автоматически по почте без каких-либо действий со стороны водителя","По телефону через Department of Transportation"],"explanation":"Продление CDL в Теннесси осуществляется лично в центре обслуживания водителей (Driver Services Center), и держатель должен иметь действующий медицинский сертификат в деле на момент продления. Источник: tn.gov/safety Renewing Your License; Medical Certification Requirements."},"98":{"q":"19-летний человек, имеющий право на получение CDL в Теннесси, подпадает под какое ограничение в эксплуатации?","options":["Ограничен только внутриштатными перевозками (в пределах Теннесси)","Ограничен только транспортными средствами легче 26,001 pounds","Без ограничений; предоставляются полные права на межштатные перевозки","Ограничен только вождением в дневное время"],"explanation":"Заявители на CDL в Теннесси должны быть не моложе 18 лет; лица младше 21 года ограничены только внутриштатными перевозками. Межштатные перевозки (и HazMat) требуют возраста 21 год. Источник: Tennessee CDL Manual; tn.gov/safety Driver Services."},"99":{"q":"Что касается сборов за подачу заявления и сдачу экзаменов на CDL в Теннесси, какое утверждение наиболее точно для учебного пособия?","options":["Сборы устанавливаются Department of Safety и могут меняться, поэтому заявителям следует уточнить актуальные суммы перед подачей заявления","Теннесси не взимает никаких сборов за CDL","Сбор навсегда фиксирован федеральным законом и никогда не меняется","Сборы взимаются только работодателем заявителя, но никогда штатом"],"explanation":"Сборы, связанные с CDL, в Теннесси устанавливаются Department of Safety и могут меняться со временем; заявителям следует уточнять актуальный перечень в центре обслуживания водителей, а не полагаться на фиксированную сумму. Источник: tn.gov/safety Driver Services перечень сборов."}},"tr":{"0":{"q":"Tennessee'nin federal ve eyalet karayolu ağında, bir aracın yükü dahil olmak üzere izinsiz (permitsiz) yasal azami genişliği nedir?","options":["8 fit 0 inç","8 fit 6 inç","9 fit 0 inç","10 fit 0 inç"],"explanation":"Tennessee yasaları, federal ve eyalet karayolu ağında bir aracın veya yükün 8 fit 6 inç (102 inç) genişliğe kadar olmasına izin verir; 'normal' yollar 8 fit ile sınırlıdır. Kaynak: T.C.A. Section 55-7-202 (Azami genişlik ve yükseklik)."},"1":{"q":"Tennessee karayollarında izinsiz (permitsiz) bir araç için, yükün herhangi bir kısmı dahil olmak üzere yasal azami yükseklik nedir?","options":["13 fit 0 inç","13 fit 6 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"Tennessee, azami araç yüksekliğini (yük dahil) 13 fit 6 inç olarak belirler. Daha yüksek bir yük, aşırı yükseklik izni (over-height permit) gerektirir. Kaynak: T.C.A. Section 55-7-202 (Azami genişlik ve yükseklik)."},"2":{"q":"Tennessee karayollarında özel izin olmadan izin verilen yasal azami brüt araç ağırlığı nedir?","options":["73,280 pound","80,000 pound","88,000 pound","100,000 pound"],"explanation":"Tennessee'nin yasal azami brüt ağırlığı, Interstate sistemi için federal sınırla uyumlu olarak 80,000 pounddur. Bunun üzerindeki yükler bir aşırı ağırlık izni (overweight permit) gerektirir. Kaynak: T.C.A. Section 55-7-203 (Aks veya aks grubu başına azami ağırlık)."},"3":{"q":"Tennessee karayollarında izinsiz (permitsiz) tek bir aksın yasal olarak taşıyabileceği azami ağırlık nedir?","options":["18,000 pound","20,000 pound","22,400 pound","23,000 pound"],"explanation":"Tennessee, tek bir aksı 20,000 pound ile sınırlar. 23,000 poundluk değer yalnızca özel bir aşırı ağırlık izni (overweight permit) kapsamında geçerlidir, izinsiz olarak yasal değildir. Kaynak: T.C.A. Section 55-7-203."},"4":{"q":"Tennessee karayollarında izinsiz (permitsiz) bir ikiz aks (tandem) grubunun yasal olarak taşıyabileceği azami ağırlık nedir?","options":["32,000 pound","34,000 pound","40,000 pound","46,000 pound"],"explanation":"Tennessee, izinsiz olarak bir ikiz aks (tandem) grubunu 34,000 pound ile sınırlar. 46,000 poundluk değer yalnızca özel bir aşırı ağırlık izni (overweight permit) kapsamında geçerlidir. Kaynak: T.C.A. Section 55-7-203."},"5":{"q":"Tennessee'de 'normal' (federal/eyalet sistemi dışı) bir yolda, bir aracın yükü dahil olmak üzere yasal azami genişliği nedir?","options":["8 fit 0 inç","8 fit 6 inç","7 fit 6 inç","9 fit 0 inç"],"explanation":"Normal yollarda Tennessee genişliği 8 fit ile sınırlar (orta hattın her iki yanında 4'er fit); 8 fit 6 inçlik izin yalnızca federal ve eyalet karayolu ağında geçerlidir. Kaynak: T.C.A. Section 55-7-202."},"6":{"q":"Aks başına ve brüt sınırların yanı sıra, Tennessee aks aralığına dayalı azami izin verilen ağırlığı belirlemek için hangi yöntemi kullanır?","options":["Federal köprü formülü (ağırlık-uzunluk tablosu)","Eyalet tonaj vergisi cetveli","Aralıktan bağımsız sabit 80,000 poundluk üst sınır","Üreticinin brüt kombinasyon ağırlık değeri"],"explanation":"Tennessee, tek/ikiz/brüt üst sınırlara ek olarak, izin verilen brüt ağırlığı aks sayısı ve aralarındaki mesafe ile ilişkilendiren federal köprü formülünü (Formül B) uygular. Kaynak: T.C.A. Section 55-7-203; TDOT tarafından benimsenen FHWA köprü formülü."},"7":{"q":"Bölünemez bir yük için Tennessee özel aşırı ağırlık izni (overweight permit) kapsamında, tek bir aksta izin verilen azami ağırlık nedir?","options":["20,000 pound","21,500 pound","23,000 pound","26,000 pound"],"explanation":"Tennessee, izin kapsamında taşınan bölünemez aşırı ağırlıklı yükler için tek bir aksta 23,000 pounda kadar izin verir (20,000 poundluk yasal sınıra kıyasla). Kaynak: T.C.A. Section 55-7-205 ve TDOT OS/OW izin kuralları."},"8":{"q":"Tennessee özel aşırı ağırlık izni (overweight permit) kapsamında, bir ikiz aks (tandem) grubunda izin verilen azami ağırlık nedir?","options":["34,000 pound","40,000 pound","46,000 pound","50,000 pound"],"explanation":"Tennessee, izin kapsamındaki bölünemez aşırı ağırlıklı yükler için bir ikiz aks (tandem) grubunda 46,000 pounda kadar izin verir (34,000 poundluk yasal sınıra kıyasla). Kaynak: T.C.A. Section 55-7-205 ve TDOT OS/OW izin kuralları."},"9":{"q":"Tennessee aşırı ağırlık izni (overweight permit) kapsamında, bir tridem (üç akslı) grupta izin verilen azami ağırlık nedir?","options":["42,000 pound","50,000 pound","60,000 pound","68,000 pound"],"explanation":"Tennessee, izin kapsamında taşınan bölünemez aşırı ağırlıklı yükler için bir tridem (üç akslı) grupta 60,000 pounda kadar izin verir. Kaynak: T.C.A. Section 55-7-205 ve TDOT OS/OW izin kuralları."},"10":{"q":"Tennessee'de özel bir aşırı boyut veya aşırı ağırlık izni (oversize/overweight permit) genellikle yalnızca şu nitelikteki yükler için gereklidir:","options":["Herhangi bir tehlikeli madde taşıyan","Bölünemez olan ve makul ölçüde yasal sınırlara indirilemeyen","Eyalet içinde 100 milden fazla seyahat eden","Eyalet dışında kayıtlı olan"],"explanation":"TDOT, yasal boyut/ağırlık sınırlarını karşılamak için makul ölçüde sökülemeyen veya ayrılamayan bölünemez parçalar ya da emtialar için OS/OW izinleri verir. Basitçe bölünebilen bir yük yerine yasal sınırlar içine getirilmelidir. Kaynak: TDOT Oversize/Overweight Permit Office; T.C.A. Section 55-7-205."},"11":{"q":"Standart bir Tennessee tek seferlik aşırı boyut/aşırı ağırlık izni (oversize/overweight permit) ne kadar süre geçerlidir?","options":["3 gün","10 gün","30 gün","1 yıl"],"explanation":"Bir Tennessee tek seferlik OS/OW izni 10 gün geçerlidir (mobil ev izinleri 6 gün geçerlidir). Kaynak: TDOT Oversize/Overweight Permit Office SSS ve kuralları."},"12":{"q":"Tennessee'de bir taşıyıcı aşırı boyut/aşırı ağırlık iznine (oversize/overweight permit) nasıl başvurur?","options":["Yerel şerifi telefonla arayarak","TDOT TNTRIPS çevrimiçi sistemi üzerinden elektronik olarak","Her ilçeye kağıt form posta ile göndererek","Yalnızca bir tartı istasyonunda şahsen"],"explanation":"Tennessee OS/OW izinleri TDOT'un TNTRIPS çevrimiçi izin sistemi üzerinden elektronik olarak alınır; telefon ve e-posta ile sipariş kabul edilmez. Kaynak: TDOT Oversize/Overweight Permit Office (TNTRIPS)."},"13":{"q":"Tennessee'nin federal ve eyalet karayolu ağında çekilen bir yarı römork genellikle çekiciye bağlantı noktasından itibaren hangi uzunluğu aşamaz?","options":["48 fit","52 fit","57 fit","60 fit"],"explanation":"Tennessee, federal ve eyalet karayolu ağında çekiciye bağlantı noktasından ölçülen, çekilen bir yarı römork/römork için 52 fite kadar izin verir. Kaynak: T.C.A. Section 55-7-201 (Araçların azami uzunluğu)."},"14":{"q":"Tennessee'nin Interstate dışı eyalet karayollarında, belirli emtia taşıyıcılarına (tomruk, kömür, kum ve çiftlik kamyonları gibi) ne kadar ağırlık 'hata payı' (margin of error) tanınır?","options":["Yüzde 5","Yüzde 10","Yüzde 15","Hiçbir pay tanınmaz"],"explanation":"Tennessee, Interstate sistemi hariç olmak üzere eyalet karayollarında tomruk, kum, kömür, kil, şist, fosfat, katı atık, geri kazanılmış malzeme ve çiftlik/makine kamyonları için gerçek brüt veya aks ağırlığında yüzde 10 hata payına izin verir. Kaynak: T.C.A. Section 55-7-203(b)."},"15":{"q":"Tennessee'de tomruk, çiftlik ve benzeri emtia kamyonları için yüzde 10 ağırlık toleransı Interstate karayolu sisteminde geçerli midir?","options":["Evet, Interstate'ler dahil tüm karayollarında","Hayır, Interstate sistemini hariç tutar","Yalnızca geceleyin","Yalnızca izinle"],"explanation":"Yüzde 10'luk emtia ağırlık toleransı Tennessee eyalet karayollarında geçerlidir ancak özellikle, federal 80,000/20,000/34,000 sınırlarının katı şekilde uygulandığı Interstate (federal yardımlı Interstate) sistemini hariç tutar. Kaynak: T.C.A. Section 55-7-203(b)."},"16":{"q":"Tennessee yasalarına göre, belirli çiftlik makinelerinin çiftlik amaçlı taşınması, gündüz saatlerinde, Interstate dışında ve çıkış noktasından hangi mesafe içinde yapıldığında İZİN OLMADAN yapılabilir?","options":["25 mil","50 mil","75 mil","100 mil"],"explanation":"Tennessee, aşırı boyutlu/aşırı ağırlıklı çiftlik makinelerinin çiftlik amaçlı olarak gündüz saatlerinde, Interstate'ler üzerinde olmamak kaydıyla ve çıkış noktasının 50 mil yakınında izinsiz taşınmasına olanak tanır. Kaynak: T.C.A. Section 55-7-205."},"17":{"q":"Tennessee'de izinli bir yük 10 fit genişliği aştığında, araçta özellikle ne gereklidir?","options":["Her zaman her iki uçta bir kılavuz/eskort aracı","Önde ve arkada bir 'Oversize Load' afişi","Bir polis eskortu","Yalnızca gece yarısı ile sabah 5 arasında seyahat"],"explanation":"Tennessee, 10 fit genişliği aşan herhangi bir yükün önünde ve arkasında bir 'Oversize Load' afişinin sergilenmesini gerektirir. Eskort ve diğer gereklilikler genişlikle birlikte artar. Kaynak: TDOT Oversize/Overweight Permit kuralları."},"18":{"q":"100,000 pound brüt ağırlığa kadar bir araç için Tennessee yıllık aşırı ağırlık izninin (overweight permit) yaklaşık maliyeti nedir?","options":["$50","$150","$750","$3,500"],"explanation":"TDOT'un yıllık aşırı ağırlık izni ücreti, 100,000 pound GVW'ye kadar olan araçlar için $750'dır ve daha fazla ağırlıklar için kademeli olarak daha yüksek ücretler uygulanır (örneğin, 120,000 lb'ye kadar daha yüksek bir oranda). Kaynak: TDOT Oversize/Overweight Permit Office ücret cetveli."},"19":{"q":"Tennessee'de izin kapsamında süper yüklerin (superloads), tekne evlerin (houseboats) ve mobil evlerin (mobile homes) taşınması genellikle hangi seyahat saatleriyle sınırlandırılır?","options":["Yalnızca gündüz saatleri","Yalnızca gece saatleri","Yalnızca hafta sonları","Her zaman, günde 24 saat"],"explanation":"Tennessee, süper yüklerin, tekne evlerin ve mobil evlerin taşınmasını yalnızca gündüz saatleriyle sınırlar ve eskortlu yükler ayrıca büyükşehir sıkışık saat (rush-hour) yasaklarına da uymalıdır. Kaynak: TDOT Oversize/Overweight Permit kuralları."},"20":{"q":"Tennessee'de, çekilen aracın 10,000 pound GVWR'nin üzerinde olduğu ve Brüt Kombinasyon Ağırlık Değeri'nin (GCWR) 26,001 pound veya daha fazla olduğu bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Tennessee, çekilen birimin 10,000 lbs GVWR'yi aştığı, GCWR'si 26,000 lbs'nin üzerinde olan bir kombinasyon aracını kullanmak için Sınıf A CDL gerektiğini tanımlar. Kaynak: Tenn. Comp. R. & Regs. 1340-01-13-.03; Tennessee CDL Manual."},"21":{"q":"Brüt Araç Ağırlık Değeri (GVWR) 26,001 pound veya daha fazla olan tek bir aracı ya da 10,000 pound GVWR'yi aşmayan bir römork çeken böyle bir aracı kullanmak için hangi Tennessee CDL sınıfı gereklidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf M"],"explanation":"Tennessee, 26,000 lbs GVWR'nin üzerindeki tek bir araç için ya da 10,000 lbs GVWR'yi aşmayan bir birimi çeken böyle bir araç için Sınıf B CDL gerektiğini tanımlar. Kaynak: Tenn. Comp. R. & Regs. 1340-01-13-.03; Tennessee CDL Manual."},"22":{"q":"Bir Tennessee sürücüsü, tehlikeli maddeler için plakart (placard) taşıyan ya da sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış, 26,001 pound GVWR'nin altındaki tek bir aracı kullanıyor. Hangi CDL sınıfı geçerlidir?","options":["Sınıf A","Sınıf B","Sınıf C","Sınıf D"],"explanation":"Tennessee'nin Sınıf C CDL'si, tehlikeli maddeler için plakart taşınması gereken, 15'ten fazla yolcu (sürücü dahil 16+) taşımak üzere tasarlanmış ya da okul otobüsü olarak kullanılan, 26,000 lbs GVWR'yi aşmayan tek araçları kapsar. Kaynak: Tenn. Comp. R. & Regs. 1340-01-13-.03."},"23":{"q":"Tennessee'de, yalnızca eyalet içi (intrastate) ticari sürüşle sınırlı bir CDL almak için asgari yaş nedir?","options":["16 yaşında","17 yaşında","18 yaşında","21 yaşında"],"explanation":"Tennessee, en az 18 yaşında olan başvuru sahiplerinin yalnızca eyalet içi (intrastate) operasyon için bir CDL almasına izin verir. Kaynak: Tennessee CDL Manual; Tennessee Department of Safety and Homeland Security, Driver Services."},"24":{"q":"Tennessee'de, eyaletler arası (interstate) ticarette ticari bir araç kullanmak ya da tehlikeli maddeler taşımak için gereken asgari yaş nedir?","options":["18 yaşında","19 yaşında","21 yaşında","25 yaşında"],"explanation":"Tennessee, bir sürücünün eyaletler arası (interstate) ticarette çalışması ya da tehlikeli maddeler taşıması için en az 21 yaşında olmasını gerektirir; 18-20 yaş arası sürücüler yalnızca eyalet içi (intrastate) operasyonla sınırlıdır. Kaynak: Tennessee CDL Manual; Tennessee'de uygulandığı şekliyle 49 CFR 383.3."},"25":{"q":"Tennessee'de, plakart (placard) gerektiren miktarlarda tehlikeli madde taşıyan ticari bir aracı kullanmak için hangi onay (endorsement) gereklidir?","options":["N onayı","H onayı","T onayı","P onayı"],"explanation":"Tennessee, plakart gerektiren miktarlarda tehlikeli madde taşıyan bir CMV kullanmak için H (Hazardous Materials) onayını gerektirir. Kaynak: Tennessee CDL Manual; 49 CFR 383.93."},"26":{"q":"Tennessee bir CDL'ye Tehlikeli Maddeler (H) onayı ekleyebilmeden önce, federal yasa başvuru sahibinin hangi ek adımı tamamlamasını gerektirir?","options":["Parmak izine dayalı geçmiş kontrolü içeren bir TSA güvenlik tehdidi değerlendirmesi","Tennessee'de 40 saatlik bir sınıf içi HazMat kursu","Bir Tennessee DOT tartı istasyonunda göz muayenesi","İlçe kâtibi tarafından uygulanan bir uyuşturucu ve alkol testi"],"explanation":"Tennessee, USA PATRIOT Act kapsamında, başvuru sahibi parmak izine dayalı geçmiş kontrolünü içeren TSA tarafından uygulanan bir güvenlik tehdidi değerlendirmesini geçene kadar HazMat onayını veremez. Kaynak: Tennessee Department of Safety and Homeland Security, HazMat Endorsement sayfası; 49 CFR 1572."},"27":{"q":"Tennessee, 1,000 galon veya daha fazla taşımak üzere derecelendirilmiş kalıcı olarak monte edilmiş bir tankta sıvı veya gaz taşımak üzere tasarlanmış bir tank aracını kullanmak için hangi onayı (endorsement) gerektirir?","options":["H onayı","N onayı","T onayı","S onayı"],"explanation":"Tennessee, 1,000 galon veya daha fazla taşımak üzere derecelendirilmiş bir tankta sıvı veya gaz taşımak için tasarlanmış tank araçları için N (Tanker) onayını gerektirir. Kaynak: Tennessee CDL Manual; 49 CFR 383.93."},"28":{"q":"Tennessee'de çift veya üç römork çekmek için hangi onay (endorsement) gereklidir ve hangi CDL sınıfıyla sınırlıdır?","options":["T onayı, yalnızca Sınıf A'da mevcut","T onayı, yalnızca Sınıf B'de mevcut","N onayı, herhangi bir sınıfta mevcut","P onayı, yalnızca Sınıf C'de mevcut"],"explanation":"Tennessee, birden fazla römork çekmek için T (Doubles/Triples) onayını gerektirir ve bu tür kombinasyonlar bir Sınıf A ehliyeti gerektirdiğinden, onay yalnızca Sınıf A'da mevcuttur. Kaynak: Tennessee CDL Manual; Tenn. Comp. R. & Regs. 1340-01-13."},"29":{"q":"Tennessee, sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış ticari bir aracı kullanmak için hangi onayı (endorsement) gerektirir?","options":["S onayı","P onayı","N onayı","H onayı"],"explanation":"Tennessee, sürücü dahil 16 veya daha fazla kişi taşımak üzere tasarlanmış bir aracı kullanmak için P (Passenger) onayını gerektirir. Kaynak: Tennessee CDL Manual; 49 CFR 383.93."},"30":{"q":"Tennessee'de Okul Otobüsü (S) onayı, sürücünün önce hangi başka onaya sahip olmasını gerektirir?","options":["H (HazMat) onayı","N (Tanker) onayı","P (Passenger) onayı","T (Doubles/Triples) onayı"],"explanation":"Tennessee'de, okul otobüsü yolcu taşıyan bir araç olduğundan, S (School Bus) onayı bir ön koşul olarak P (Passenger) onayını gerektirir. Kaynak: Tennessee CDL Manual; 49 CFR 383.93."},"31":{"q":"Tennessee'de uygulanan federal kurala göre, bir Ticari Öğrenci İzni (CLP) ilk verildikten sonra sahibi CDL beceri testine girmeye hak kazanmadan önce ne kadar beklemelidir?","options":["7 gün","14 gün","30 gün","60 gün"],"explanation":"Bir CLP sahibi, CLP ilk verildikten sonraki ilk 14 gün içinde CDL beceri testine girmeye hak kazanmaz. Kaynak: Tennessee Driver Services tarafından uygulandığı şekliyle 49 CFR 383.25; Tennessee CDL Manual."},"32":{"q":"Tennessee'de izlenen federal standartlara göre, bir Ticari Öğrenci İzni (CLP), bilgi testlerinin yeniden alınması gerekmeksizin ilk veriliş tarihinden itibaren en fazla ne kadar süre geçerlidir?","options":["30 gün","90 gün","6 ay","1 yıl"],"explanation":"Bir CLP, sahibinin bilgi testlerini yeniden almasını gerektirmeden ilk veriliş tarihinden itibaren en fazla bir yıl geçerli olmalıdır; eyaletler genellikle bunu bir kez yenilemeli olarak 180 güne kadar verir. Kaynak: 49 CFR 383.25; Tennessee Driver Services."},"33":{"q":"Bir Tennessee Ticari Öğrenci İzni (CLP) kapsamında ticari bir araç kullanırken hangi gözetim gereklidir?","options":["Uygun sınıf ve onaylara sahip bir CDL sahibi, CLP sahibinin yanında oturmalıdır","Sürücü 21 yaşından büyükse gözetim gerekmez","Bir kolluk görevlisi ayrı bir araçla takip etmelidir","Herhangi bir lisanslı Sınıf D sürücüsü arka koltukta oturabilir"],"explanation":"Bir CLP sahibi yalnızca, uygun sınıf ve onaylara sahip olan ve izin sahibinin yanındaki ön koltukta oturan bir CDL sahibi eşliğinde araç kullanabilir. Kaynak: 49 CFR 383.25; Tennessee CDL Manual."},"34":{"q":"Tennessee'de bir CDL veya CLP için başvururken, bir başvuru sahibinin kaç adet Tennessee ikamet belgesi sunması gerekir?","options":["Bir ikamet belgesi","İki ikamet belgesi","Üç ikamet belgesi","İkamet belgesi gerekmez"],"explanation":"Tennessee, başvuru sahiplerinin kimlik/yasal mevcudiyet kanıtı ve Sosyal Güvenlik numarasının yanı sıra iki (2) adet Tennessee ikamet belgesi sunmasını gerektirir. Kaynak: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL."},"35":{"q":"Bir Tennessee CDL başvuru sahibinin uygunluğunu kanıtlamak için hangi belge setini sunması gerekir?","options":["Kimlik/yasal mevcudiyet kanıtı, Sosyal Güvenlik numarası kanıtı ve iki adet Tennessee ikamet belgesi","Yalnızca bir Tennessee seçmen kayıt kartı","Yalnızca bir pasaport ve tek bir fatura","Bir doğum belgesi ve bir araç ruhsatı"],"explanation":"Tennessee, kimlik ve yasal mevcudiyet kanıtı (ABD vatandaşlığı veya yasal daimi ikamet statüsü), Sosyal Güvenlik numarası kanıtı ve iki adet Tennessee ikamet belgesi gerektirir. Kaynak: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL."},"36":{"q":"Yeni Tennessee başvuru sahipleri, bir Sınıf A veya Sınıf B ehliyeti için CDL beceri testine girmeden önce ya da belirli onayları eklemeden önce hangi eğitimi tamamlamalıdır?","options":["FMCSA Training Provider Registry'de yer alan bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT)","Bir Tennessee toplum kolejinde savunmacı sürüş kursu","İlçeye kaydedilmiş dört yıllık bir çıraklık","Bir Tennessee Highway Patrol araç eşliği (ride-along) programı"],"explanation":"Tennessee, yeni başvuru sahiplerinin Sınıf A/B beceri testinden ya da H, P veya S onaylarından önce, FMCSA Training Provider Registry'de listelenmiş bir okul tarafından sağlanan Giriş Düzeyi Sürücü Eğitimi'ni (ELDT) tamamlamasını gerektirir. Kaynak: 49 CFR Part 380 Subpart F; Tennessee Driver Services CDL sayfası."},"37":{"q":"Bir Tennessee CDL için kendi kendine sertifikasyon (self-certifying) yaparken, hangi kategori eyaletler arası (interstate) ticarette çalışan ve federal DOT tıbbi muayene belgesi gerekliliğini karşılaması gereken bir sürücüyü tanımlar?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Non-Excepted Interstate olarak kendi kendine sertifikasyon yapan bir sürücü, eyaletler arası (interstate) ticarette çalışır ve geçerli bir federal DOT tıbbi muayene belgesi bulundurmalıdır. Kaynak: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71."},"38":{"q":"Bir Tennessee CDL başvuru sahibinin, yaptıkları ticari sürüş türüyle ilgili kaç kendi kendine sertifikasyon (self-certification) kategorisinden seçim yapması gerekir?","options":["İki","Üç","Dört","Beş"],"explanation":"Tennessee CDL sahipleri dört kategoriden birine kendi kendine sertifikasyon yapmalıdır: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate ve Excepted Intrastate. Kaynak: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71."},"39":{"q":"Bir Tennessee sürücüsü Non-Excepted Interstate olarak kendi kendine sertifikasyon yapar. CDL'yi geçerli tutmak için sürücünün eyalette dosyada ne bulundurması gerekir?","options":["Sertifikalı bir muayene uzmanından güncel bir federal tıbbi muayene belgesi","İşvereninden noter onaylı bir mektup","Lise diplomasının bir kopyası","Yıllık bir araç muayene etiketi"],"explanation":"Muaf olmayan (non-excepted) sürücüler, FMCSA National Registry'deki sertifikalı bir tıbbi muayene uzmanından güncel bir federal tıbbi muayene belgesi almalı ve bunu sürekli olarak bulundurmalı ve eyalette dosyada tutmalıdır. Kaynak: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 391.45."},"40":{"q":"Tennessee'de, bir kişinin yasal olarak ticari bir motorlu araç (CMV) kullanabileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.02","0.04","0.08","0.10"],"explanation":"Tennessee federal standardı izler: 0.04 veya daha yüksek bir BAC ile bir CMV kullanmak büyük (major) bir suçtur. Bu, ticari olmayan sürücüler için olan 0.08 sınırının yarısıdır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1; T.C.A. 55-50-405."},"41":{"q":"Bir sürücü, tehlikeli madde taşımazken bir CMV'yi 0.04 veya daha yüksek bir BAC ile kullanmaktan ilk kez mahkûm edilir. CDL ne kadar süreyle iptal edilir (disqualified)?","options":["60 gün","6 ay","1 yıl","3 yıl"],"explanation":"İlk büyük (major) suç (bir CMV'de 0.04 veya daha yüksek BAC dahil), Tennessee'de asgari 1 yıllık CDL iptaliyle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1."},"42":{"q":"Bir sürücü, tehlikeli maddeler için plakart (placard) taşıyan bir CMV kullanırken ilk büyük (major) alkol suçunu işler. İptal (disqualification) süresi nedir?","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"İlk büyük (major) suç, CMV plakartlı tehlikeli madde taşırken işlendiğinde, Tennessee iptali (disqualification) 1 yıldan 3 yıla yükselir. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1."},"43":{"q":"Tennessee'nin zımni rıza (implied consent) yasası kapsamında, ilk kez gerekli bir kimyasal/kan alkol testini reddeden bir CDL sahibi için sonuç nedir?","options":["Yalnızca bir uyarı","60 gün CDL kaybı","1 yıl CDL kaybı","90 gün CDL kaybı"],"explanation":"Alkol testine girmeyi reddetmek Tennessee'de büyük (major) bir suç olarak değerlendirilir ve BAC sınırının üzerinde araç kullanmaktan ilk mahkûmiyet ile aynı şekilde asgari 1 yıllık CDL iptaliyle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); T.C.A. 55-50-405; 49 CFR 383.51."},"44":{"q":"Bir CDL sahibi, sürücülük kariyeri boyunca İKİNCİ bir büyük (major) suçtan (örneğin, ikinci bir BAC-0.04 ihlali) mahkûm edilir. Tennessee'deki iptal (disqualification) süresi nedir?","options":["3 yıl","10 yıl","Ömür boyu","5 yıl"],"explanation":"İkinci bir büyük (major) suç, ömür boyu CDL iptaliyle (disqualification) sonuçlanır. Tennessee, isteğe bağlı 10 yıllık yeniden ehliyetlendirme (reinstatement) hükmünü benimsememiştir, bu nedenle ömür boyu yasak kalıcıdır. Kaynak: Tennessee CDL Manual (Disqualifications); TN Dept. of Safety CDL serious-offenses guidance; 49 CFR 383.51 Table 1."},"45":{"q":"Kontrollü bir maddenin üretimi, dağıtımı veya temini ile ilgili bir suçu (felony) işlemek için ticari bir motorlu araç kullanmak, Tennessee'de hangi iptalle (disqualification) sonuçlanır?","options":["1 yıl","3 yıl","Yeniden ehliyetlendirme olmaksızın ömür boyu","5 yıl"],"explanation":"Kontrollü maddelerle ilgili bir suçun (felony) işlenmesinde bir CMV kullanmak, Tennessee'de yeniden ehliyetlendirme (reinstatement) olasılığı olmaksızın ömür boyu iptal (disqualification) taşır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 1."},"46":{"q":"Tennessee'de İLK iptal (disqualification) tetiklenmeden önce bir CDL sürücüsünün 3 yıllık bir süre içinde kaç ciddi (serious) trafik ihlali işlemesi gerekir?","options":["1 ihlal","2 ihlal","3 ihlal","4 ihlal"],"explanation":"Tek bir ciddi (serious) trafik ihlali iptale (disqualification) neden olmaz. İlk iptal (60 gün), 3 yıl içinde İKİNCİ bir ciddi ihlal ile tetiklenir. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"47":{"q":"Bir CDL sürücüsü, 3 yıllık bir süre içinde İKİ ciddi (serious) trafik ihlalinden mahkûm edilir. İptal (disqualification) süresi nedir?","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde iki ciddi (serious) trafik ihlali, Tennessee'de 60 günlük CDL iptaliyle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"48":{"q":"Bir CDL sürücüsü, 3 yıllık bir süre içinde ÜÇ ciddi (serious) trafik ihlali biriktirir. İptal (disqualification) süresi nedir?","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"3 yıl içinde üç ciddi (serious) trafik ihlali, Tennessee'de 120 günlük CDL iptaliyle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"49":{"q":"Bir Tennessee CDL sahibi için aşırı hız, hangi hızda belirlenen sınırın üzerinde 'ciddi trafik ihlali' (serious traffic violation) sayılır?","options":["10 mph veya daha fazla üzeri","15 mph veya daha fazla üzeri","20 mph veya daha fazla üzeri","25 mph veya daha fazla üzeri"],"explanation":"Belirlenen hız sınırının 15 mph veya daha fazla üzerinde hız yapmak, ciddi bir trafik ihlali (serious traffic violation) olarak sınıflandırılır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"50":{"q":"Aşağıdakilerden hangisi bir Tennessee CDL sürücüsü için büyük (major) bir suç yerine CİDDİ bir trafik ihlali (serious traffic violation) olarak sınıflandırılır?","options":["0.04 veya daha yüksek bir BAC ile bir CMV kullanmak","Dikkatsiz sürüş / çok yakından takip etmek","Bir kaza yerini terk etmek","CMV'yi bir suç (felony) işlemek için kullanmak"],"explanation":"Dikkatsiz sürüş, çok yakından takip etmek ve uygunsuz/düzensiz şerit değiştirmeler ciddi trafik ihlalleridir (serious traffic violations). Listelenen diğer seçenekler, 1 yıllık (veya ömür boyu) iptal (disqualification) taşıyan büyük (major) suçlardır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Tables 1 and 2."},"51":{"q":"Bir CMV kullanırken mesaj atmak, Tennessee CDL kuralları kapsamında aşağıdakilerden hangisi olarak sınıflandırılır?","options":["Büyük bir suç (1 yıllık iptal)","Ciddi bir trafik ihlali","Bir hizmet dışı (out-of-service) emri ihlali","İptale yol açmayan bir ihlal"],"explanation":"Bir CMV kullanırken hem mesaj atmak hem de elde tutulan bir cep telefonu kullanmak ciddi trafik ihlalleridir (serious traffic violations) ve 60 günlük/120 günlük iptallere (disqualifications) doğru sayılabilir. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2; FMCSA 392.80/392.82."},"52":{"q":"Bir CDL sürücüsü, bir CMV kullanırken elde tutulan bir cep telefonu kullanmaktan İKİNCİ bir mahkûmiyet alır ve ikincisi ilkinden sonraki 3 yıl içinde gerçekleşir. Hangi iptal (disqualification) uygulanır?","options":["İptal yok","60 gün","120 gün","1 yıl"],"explanation":"Elde tutulan telefon kullanımı ciddi bir trafik ihlalidir (serious traffic violation). 3 yıl içinde ikinci bir ciddi ihlal 60 günlük bir iptali (disqualification) tetikler. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 2."},"53":{"q":"Bir Tennessee CDL sürücüsü tarafından işlenen demiryolu-karayolu hemzemin geçit ihlalinin İLK mahkûmiyeti için iptal (disqualification) süresi nedir?","options":["30 günden az olmamak üzere","60 günden az olmamak üzere","120 günden az olmamak üzere","1 yıldan az olmamak üzere"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, 60 günden az olmamak üzere bir iptal (disqualification) taşır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3."},"54":{"q":"Bir Tennessee CDL sürücüsü, 3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlalinden mahkûm edilir. Asgari iptal (disqualification) nedir?","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"3 yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, 120 günden az olmamak üzere bir iptalle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3."},"55":{"q":"Bir Tennessee CDL sürücüsü, 3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlalinden mahkûm edilir. Asgari iptal (disqualification) nedir?","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"3 yıl içinde üçüncü bir demiryolu hemzemin geçit ihlali, 1 yıldan az olmamak üzere bir iptalle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 3."},"56":{"q":"Bir Tennessee CDL sürücüsü için bir hizmet dışı (out-of-service) emrinin İLK ihlali (tehlikeli madde veya yolcu taşımayan bir CMV'de) için asgari iptal (disqualification) süresi nedir?","options":["30 gün","90 gün","180 gün","1 yıl"],"explanation":"İlk hizmet dışı (out-of-service) emri ihlali, 180 günden az olmamak üzere (1 yıla kadar) bir iptalle (disqualification) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4."},"57":{"q":"İptale (disqualification) ek olarak, bir Tennessee sürücüsünün İLK hizmet dışı (out-of-service) emri ihlali için karşılaştığı asgari hukuki para cezası nedir?","options":["$1,000","$2,500","$5,000","$10,000"],"explanation":"İlk hizmet dışı (out-of-service) emri ihlali, 180 günlük iptale (disqualification) ek olarak asgari $2,500 hukuki para cezası taşır; ikincisi asgari $5,000 taşır. Kaynak: Tennessee CDL Manual / TN Dept. of Safety; 49 CFR 383.53."},"58":{"q":"Bir Tennessee CDL sürücüsü, 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı (out-of-service) emri ihlali işler (tehlikeli madde dışı). Asgari iptal (disqualification) nedir?","options":["180 gün","1 yıl","2 yıl","5 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı (out-of-service) emri ihlali, 2 yıldan az olmamak üzere bir iptalle (disqualification) (ve asgari $5,000 hukuki para cezasıyla) sonuçlanır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4."},"59":{"q":"Bir sürücü, CMV plakartlı tehlikeli madde taşırken ilk kez bir hizmet dışı (out-of-service) emrini ihlal eder. İptal (disqualification) süresi nedir?","options":["60 günden az olmamak üzere","180 günden az olmamak üzere, 2 yıla kadar","Tam olarak 1 yıl","Ömür boyu"],"explanation":"Plakartlı tehlikeli madde taşırken (veya 16+ yolcu taşırken) ilk hizmet dışı (out-of-service) emri ihlali, 180 günden az olmamak ve 2 yıla kadar olmak üzere artırılmış bir iptal (disqualification) taşır. Kaynak: Tennessee CDL Manual (Disqualifications); 49 CFR 383.51 Table 4."},"60":{"q":"En az dört şeritli bir Tennessee karayolunda, Move Over (Geç Şerit Değiştir) yasası, yanıp sönen ışıkları yanan, durmuş bir acil durum aracının yanından geçen yaklaşan bir sürücünün güvenli olduğunda ne yapmasını gerektirir?","options":["Durmuş aracın bitişiğinde olmayan bir şeride geçmek","Acil durum aracı ayrılana kadar tamamen durmak","Sağ banketten geçerek ilerlemeye devam etmek","Korna çalıp belirtilen hızı korumak"],"explanation":"Tennessee'nin Move Over yasası (T.C.A. 55-8-132), dört veya daha fazla şeritli bir karayolundaki sürücülerin güvenli olduğunda durmuş aracın bitişiğinde OLMAYAN bir şeride geçerek yol vermesini gerektirir; yalnızca şerit değiştirmek imkansız veya güvensiz ise sürücü bunun yerine güvenli bir hıza yavaşlayabilir. Kaynak: T.C.A. 55-8-132."},"61":{"q":"Tennessee'nin Move Over yasası kapsamında, bir CMV sürücüsü yanıp sönen ışıkları yanan, durmuş bir altyapı (utility) veya bakım aracının yanından geçerken güvenli bir şekilde şerit değiştiremiyorsa, sürücü bunun yerine ne yapmalıdır?","options":["Yol üzerinde tamamen durmak","Yol koşullarına uygun güvenli bir hıza yavaşlamak","Tam olarak limitin 25 mph altına yavaşlamak","Karşı bankete çekmek"],"explanation":"T.C.A. 55-8-132 polis, itfaiye, ambulans, altyapı (utility), çekici ve karayolu bakım araçlarını kapsar. Şerit değiştirmek imkansız veya güvensiz ise, sürücü yol koşullarına uygun güvenli bir hıza yavaşlamalıdır; yasa sayısal bir azaltma belirlemez. Kaynak: T.C.A. 55-8-132."},"62":{"q":"Tennessee'nin Move Over yasasını ihlal etmek (durmuş bir acil durum aracı için şerit değiştirmemek veya yavaşlamamak) ne olarak sınıflandırılır?","options":["Hareketsiz bir hukuki ihlal (civil infraction)","Class C felony (ağır suç)","Class B misdemeanor (hafif suç)","Yalnızca basit bir uyarı"],"explanation":"Tennessee'nin Move Over yasasının ihlali, 500 dolara kadar para cezası ile cezalandırılabilen (ve ağırlaştırılmış durumlarda olası hapis cezası içeren) bir Class B misdemeanor'dür. Kaynak: T.C.A. 55-8-132."},"63":{"q":"Tennessee eyaletlerarası karayollarında (interstate) izin verilen maksimum belirtilen hız limiti nedir?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Tennessee, eyaletlerarası karayollarında yasal olarak maksimum 70 mph belirler. Kaynak: T.C.A. 55-8-152."},"64":{"q":"Tennessee yasalarına göre, eyaletlerarası (interstate) veya dört şeritli kontrollü erişimli yollar OLMAYAN karayollarında, bir kamyon için (1,5 ton veya daha fazla anma kapasitesi) genel maksimum hız nedir?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"T.C.A. 55-8-152, eyaletlerarası karayolları ve limitin 65 mph olduğu dört şeritli kontrollü erişimli karayolları dışındaki yollarda kamyonları (1,5 ton veya daha fazla anma kapasitesi) 55 mph ile sınırlar. Kaynak: T.C.A. 55-8-152."},"65":{"q":"Tennessee'de, dört veya daha fazla şeritli kontrollü erişimli bir karayolunun sol (sollama) şeridinde çalışan bir araç için yasal minimum hız nedir?","options":["40 mph","45 mph","55 mph","65 mph"],"explanation":"Tennessee, dört veya daha fazla şeritli kontrollü erişimli bir karayolunun sol şeridinde 55 mph'nin altında çalışmayı yasadışı kılar. Kaynak: T.C.A. 55-8-152."},"66":{"q":"Bir Tennessee CMV sürücüsünün demiryolu geçidinde durması gerektiğinde, araç en yakın raya göre nerede durmalıdır?","options":["50 feet içinde ancak 15 feet'ten az olmamak üzere","25 feet içinde ancak 5 feet'ten az olmamak üzere","100 feet içinde ancak 50 feet'ten az olmamak üzere","Raydan tam olarak 10 feet"],"explanation":"Durması gereken bir sürücü, en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durmalı, ardından ilerlemeden önce bakmalı ve dinlemelidir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 392.10."},"67":{"q":"Aşağıdakilerden hangisi, görünürde tren olmasa bile Tennessee'de bir demiryolu geçidinde HER ZAMAN durmalıdır?","options":["Herhangi bir boş düz platformlu (flatbed) römork","Yolcu taşıyan bir otobüs ve plaka (placard) taşıyan tehlikeli madde aracı","Herhangi bir üç akslı düz kamyon","26.001 pound'un üzerindeki herhangi bir araç"],"explanation":"Demiryolu geçitlerinde durması gereken CMV'ler, yolcu taşıyan otobüsler ve tehlikeli madde plakaları (placard) gösteren araçlardır; çoğu diğer CMV, sinyaller gerektirmedikçe durmak zorunda değildir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 392.10."},"68":{"q":"Bir geçiş sırasında bir Tennessee CMV'sinin herhangi bir kısmı demiryolu rayları üzerindeyken, sürücü aşağıdakilerden hangisini YAPMAMALIDIR?","options":["Her iki eli de direksiyonda tutmak","Rayın her iki yönüne de bakmak","Vites değiştirmek","Sabit bir hız korumak"],"explanation":"Sürücüler, aracın herhangi bir kısmı rayları geçerken durmamalı, vites değiştirmemeli veya şerit değiştirmemelidir, çünkü kaçırılan bir vites aracın raylar üzerinde stop ederek kalmasına neden olabilir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 392.10."},"69":{"q":"Her iki yönde de trafiğin olduğu iki şeritli bir Tennessee yolunda, bir okul otobüsü çocukları bindirmek veya indirmek için durduğunda ve yanıp sönen kırmızı ışıklarını çalıştırdığında bir sürücü ne yapmalıdır?","options":["Yalnızca otobüsün arkasındaki araçlar durmalıdır","Her iki yöndeki araçlar da durmalıdır","15 mph'ye yavaşlayıp dikkatle geçmek","Görünürde çocuk yoksa otobüsü soldan geçmek"],"explanation":"Bölünmemiş bir yolda, her iki yöndeki sürücüler de, yanıp sönen kırmızı ışıkları ve dur kolu (stop arm) gösteren bir okul otobüsü için, bunlar geri çekilene kadar durmalıdır. Kaynak: T.C.A. 55-8-151."},"70":{"q":"Tennessee'de, karşı yönden gelirken durmuş bir okul otobüsüyle karşılaşan bir sürücü, durmaktan yalnızca yolların ne ile ayrıldığı durumda muaftır?","options":["Boyalı bir orta çizgi","İki yönlü sola dönüş (intihar) şeridi","Araç trafiğine uygun olmayan bir ara boşluk veya fiziksel bariyer (ayrı yollar)","En az üç seyir şeridi"],"explanation":"Tennessee'nin istisnası yalnızca ayrı yolları olan bir karayolunda geçerlidir; bu, yönlerin araç trafiğine uygun olmayan bir ara boşluk veya bariyer ile bölündüğü anlamına gelir. Yalnızca boyalı bir çizgi veya orta dönüş şeridi nitelik taşımaz, bu nedenle sürücüler yine de durmalıdır. Kaynak: T.C.A. 55-8-151."},"71":{"q":"Tennessee'de durmuş bir okul otobüsünü yasadışı olarak geçmenin ilk suçu ne olarak sınıflandırılır?","options":["Hareketsiz bir ihlal (non-moving violation)","Class A misdemeanor (hafif suç)","Class C misdemeanor (hafif suç)","Yalnızca hukuki para cezası"],"explanation":"Durmuş bir okul otobüsünü yasadışı olarak geçmek, Tennessee'de bir Class A misdemeanor'dür ve ilk suç için 250 dolardan az ve 1.000 dolardan fazla olmamak üzere para cezası vardır. Kaynak: T.C.A. 55-8-151."},"72":{"q":"Tennessee'de, bir sürücü durmuş bir okul otobüsünü yasadışı olarak geçtiğinde ve bir kişiye çarparak öldürdüğünde, suç hangi seviyeye yükselir?","options":["Class A misdemeanor (hafif suç)","Class E felony (ağır suç)","Class C felony (ağır suç)","Class B misdemeanor (hafif suç)"],"explanation":"Durmuş bir okul otobüsünü yasadışı olarak geçerken bir kişiye çarpmak bir Class E felony'dir; çarpma ölümle sonuçlanırsa, bu bir Class C felony'dir. Kaynak: T.C.A. 55-8-151."},"73":{"q":"Tennessee, TDOT'un kamyon çekicilerini ve yarı römorkları, her yönde kaç şeride sahip eyaletlerarası ve çok şeritli bölünmüş karayollarında belirli şeritlerle sınırlamasına yetki verir?","options":["Bir veya daha fazla","İki veya daha fazla","Üç veya daha fazla","Beş veya daha fazla"],"explanation":"T.C.A. 55-8-195, TDOT'a kamyon çekicilerini ve yarı römorkları, her yönde üç veya daha fazla şeride sahip eyaletlerarası ve çok şeritli bölünmüş karayollarında belirli şeritlere yönlendirme yetkisi verir; ihlal bir Class C misdemeanor'dür (50 dolara kadar para cezası). Kaynak: T.C.A. 55-8-195."},"74":{"q":"Tennessee'nin sol şerit (Slow Poke / Yavaş Sürücü) yasası kapsamında, bir sürücü bir eyaletlerarası veya çok şeritli bölünmüş karayolunun en sol sollama şeridinde ne zaman yasal olarak seyahat edebilir?","options":["Trafik az olduğunda her zaman","Yalnızca sollama yapmayan bir şeritteki bir aracı geçerken veya sollarken","Hız limitine uyulduğu sürece her zaman","Yalnızca gün batımı ile gün doğumu arasında"],"explanation":"Tennessee'nin sol şerit yasası (T.C.A. 55-8-204), sollama şeridini, sollama yapmayan bir şeritteki bir aracı geçmek veya sollamak ile sınırlar; aksi takdirde orada oyalanmak yasaktır. Kaynak: T.C.A. 55-8-204."},"75":{"q":"Bir CMV bir Tennessee banketinde durduğunda, normal iki şeritli, iki yönlü bir yol için en arkadaki uyarı üçgeni nereye yerleştirilmelidir?","options":["Aracın 10 feet arkasına","Aracın 40 feet arkasına","Aracın 100 feet arkasına","Aracın 200 feet arkasına"],"explanation":"Uyarı cihazları 10 dakika içinde yerleştirilmelidir: biri trafik tarafında yaklaşık 10 feet arkaya, biri yaklaşık 100 feet arkaya ve biri yaklaşık 100 feet öne (yaklaşan trafik yönünde). Kaynak: Tennessee CDL Kılavuzu; 49 CFR 392.22."},"76":{"q":"Bir Tennessee CMV sürücüsü, durduktan sonra gerekli acil durum uyarı cihazlarını (üçgenler) ne kadar süre içinde yerleştirmelidir?","options":["10 dakika içinde","30 dakika içinde","Hemen, kabinden çıkmadan önce","1 saat içinde"],"explanation":"Durmuş bir CMV sürücüsü, durduktan sonraki 10 dakika içinde üç uyarı üçgenini yerleştirmelidir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 392.22."},"77":{"q":"Özel bir izin olmadan, Tennessee'de bir ticari aracın ve yükün yasal maksimum genişliği nedir?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 6 inches","10 feet 0 inches"],"explanation":"Tennessee'nin gabari aşımı izni olmadan yasal maksimum genişliği 8 feet 6 inches'tir; yasal yükseklik 13 feet 6 inches'tir. Bunların aşılması bir TDOT özel izni gerektirir. Kaynak: TDOT gabari/ağırlık aşımı izin kuralları; T.C.A. Title 55, Ch. 7."},"78":{"q":"Tennessee gabari aşımı yükü izinleri genellikle hareketi hangi zaman aralığıyla sınırlar?","options":["Yalnızca gün ışığı saatleri (yaklaşık gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar)","Trafikten kaçınmak için yalnızca gece","Pazar günleri dahil herhangi bir 24 saatlik dönem","Yalnızca 09:00 ile 16:00 arasında"],"explanation":"Tennessee gabari aşımı izinleri genellikle Pazartesi'den Cumartesi'ye kadar gün ışığında (yaklaşık gün doğumundan yarım saat önce ile gün batımından yarım saat sonrasına kadar) seyahate izin verir; Pazar günleri veya büyük tatillerde hareket olmaz ve büyük ilçelerde sıkışık saat (rush-hour) yasakları vardır. Kaynak: TDOT gabari/ağırlık aşımı izin kuralları."},"79":{"q":"Tennessee'de I-24 üzerindeki Monteagle Mountain'ın dik doğu yönlü inişinde, frenlerini kaybeden kamyonlar için hangi güvenlik özelliği sağlanır?","options":["Zorunlu bir gişe meydanı","Çakıl dolu kaçak kamyon (runaway truck) rampaları","Zorunlu bir feribot geçişi","Tersinir bir ekspres şerit"],"explanation":"Monteagle Mountain'ın I-24 inişi (yaklaşık %6 eğim), çakıl dolu kaçak kamyon (runaway truck) kaçış rampalarıyla donatılmıştır ve ticari kamyonların inişten önce muayene/fren kontrol istasyonunu kullanması yönlendirilir. Kaynak: TDOT; Tennessee CDL Kılavuzu dağ sürüşü rehberi."},"80":{"q":"Tennessee'de Ticari Sürücü Belgeleri (CDL) düzenlemekten hangi eyalet kurumu sorumludur?","options":["Tennessee Department of Safety and Homeland Security (Tennessee Güvenlik ve İç Güvenlik Bakanlığı)","Tennessee Department of Transportation (TDOT)","Tennessee Department of Motor Vehicles","Tennessee Public Service Commission"],"explanation":"Tennessee'de CDL'ler, Tennessee Department of Safety and Homeland Security (TDOSHS) tarafından Driver Services merkezleri aracılığıyla düzenlenir. Tennessee'nin ayrı bir 'Department of Motor Vehicles'ı yoktur; TDOT karayollarıyla ilgilenir, lisanslamayla değil. Kaynak: Tennessee CDL Kılavuzu; tn.gov/safety Driver Services."},"81":{"q":"Bir Tennessee başvuru sahibi CDL genel bilgi testini ve herhangi bir onay (endorsement) bilgi testini nerede alır?","options":["Department of Safety tarafından işletilen tam hizmet veren bir Driver Services Center'da","FMCSA kayıtlı herhangi bir kamyon sürüş okulunda","Bir Tennessee Department of Transportation bölge ofisinde","Evden e-Services portalı aracılığıyla çevrimiçi olarak"],"explanation":"Tennessee'nin tam hizmet veren Driver Services Center'ları, CDL genel bilgi testini ve herhangi bir onay (endorsement) için bilgi testlerini uygular. Okullar eyalet bilgi testini değil, eğitim (ELDT) sağlar. Kaynak: Tennessee CDL Kılavuzu; tn.gov/safety Driver Services 'How do I obtain a CDL'."},"82":{"q":"Bir Ticari Öğrenci İzni (CLP) düzenlenmeden önce, bir Tennessee başvuru sahibinin ilk olarak ne yapması gerekir?","options":["CDL genel bilgi testini geçmek","Üç bölümlü beceri testini geçmek","Direksiyon başında ELDT saha (range) eğitimini tamamlamak","CLP'yi en az 14 gün elde tutmak"],"explanation":"CLP'yi almak için bir Tennessee başvuru sahibinin CDL genel bilgi testini (artı gerekli onay testlerini) almış ve geçmiş olması gerekir. Beceri testi ve 14 günlük bekleme süresi, CLP düzenlendikten sonra gelir. Kaynak: Tennessee CDL Kılavuzu; tn.gov/safety Driver Services."},"83":{"q":"Bir Tennessee CDL başvuru sahibi Driver Services Center'da hangi belge setini sunmalıdır?","options":["Kimlik kanıtı, Social Security numarası, ABD vatandaşlığı/yasal varlık ve Tennessee ikameti kanıtı","Yalnızca geçerli bir pasaport ve büyük bir kredi kartı","Bir lise diploması ve iki işveren referans mektubu","Yalnızca bir araç ruhsatı ve güncel araç tescili"],"explanation":"Tennessee, kimlik kanıtı, Social Security numarası kanıtı, ABD vatandaşlığı veya yasal daimi ikamet durumu kanıtı ve Tennessee yerleşimini/ikametini kanıtlayan iki belge gerektirir. Kaynak: Tennessee CDL Kılavuzu; tn.gov/safety Driver Services belge gereksinimleri."},"84":{"q":"Bir Tennessee CDL başvuru sahibi, öz-sertifikasyon (self-certification) yeminli beyanını doldururken kaç farklı ticaret kategorisi arasından seçim yapmalıdır?","options":["Dört","İki","Üç","Beş"],"explanation":"Tennessee Öz-Sertifikasyon Yeminli Beyanı (SF-1480) dört seçenek listeler: muaf olmayan eyaletlerarası (non-excepted interstate), muaf eyaletlerarası (excepted interstate), muaf olmayan eyalet içi (non-excepted intrastate) ve muaf eyalet içi (excepted intrastate). Sürücü tam olarak birini paraflar. Kaynak: Tennessee SF-1480 Öz-Sertifikasyon Yeminli Beyanı; tn.gov/safety."},"85":{"q":"Hangi öz-sertifikasyon kategorisi, bir Tennessee CDL sahibinin güncel bir federal DOT tıbbi muayene sertifikası sunmasını gerektirir?","options":["Muaf olmayan eyaletlerarası (non-excepted interstate)","Muaf eyaletlerarası (excepted interstate)","Muaf eyalet içi (excepted intrastate)","Yalnızca çiftlik malzemeleri taşıyan muaf eyaletlerarası (excepted interstate)"],"explanation":"Muaf olmayan eyaletlerarası (non-excepted interstate) olarak öz-sertifika veren bir sürücü, 49 CFR 391.45'e tabidir ve güncel bir tıbbi muayene sertifikası sunmalıdır. Muaf kategorilerin federal bir tıbbi kart sunması gerekmez. Kaynak: Tennessee SF-1480; tn.gov/safety Medical Certification Requirements."},"86":{"q":"Tennessee'de, muaf olmayan eyaletlerarası CDL sahiplerinin güncel tutması gereken federal DOT tıbbi muayene sertifikasının yaygın adı nedir?","options":["Tıbbi kart (DOT kartı)","Tehlikeli madde onay (endorsement) kartı","Selective Service sertifikası","TWIC kartı"],"explanation":"49 CFR 391.45 kapsamındaki tıbbi muayene sertifikası (Form MCSA-5876) yaygın olarak 'tıbbi kart' veya 'DOT kartı' olarak adlandırılır. TWIC ve HazMat onayı (endorsement) ayrı kalemlerdir. Kaynak: Tennessee Medical Certification Requirements; tn.gov/safety."},"87":{"q":"Bir Tennessee CDL sahibi yeni bir Öz-Sertifikasyon Yeminli Beyanını ve güncellenmiş tıbbi sertifikasyonu eyalete nasıl sunabilir?","options":["Department of Safety e-Services portalı aracılığıyla yükleyerek veya bir Driver Services Center'ı ziyaret ederek","Doğrudan FMCSA National Registry'ye posta ile göndererek","Tennessee Department of Transportation'a e-posta ile göndererek","Tıbbi muayene görevlisine vererek; o da ilçe kâtibine (county clerk) dosyalar"],"explanation":"Tennessee CDL sahipleri, Öz-Sertifikasyon Yeminli Beyanını (ve gerektiğinde tıbbi sertifikasyonu), Department of Safety e-Services portalı aracılığıyla yükleyerek veya bir Driver Services Center'da şahsen sunar. Kaynak: tn.gov/safety Medical Certification Requirements."},"88":{"q":"Bir Tennessee CDL sahibi, durumunu güncel tutmak için güncellenmiş tıbbi sertifikasyonu tıbbi kartın son kullanma tarihine göre hangi noktada sunmalıdır?","options":["Mevcut tıbbi sertifikanın son kullanma tarihinden en az beş iş günü önce","Sertifikanın süresi zaten dolduktan sonraki 30 gün içinde","Yalnızca lisans yenilemede sekiz yılda bir","Sertifikanın süresi dolduktan sonraki bir yıl içinde"],"explanation":"Tennessee, CDL sahiplerine, bir derecelendirme düşürmeyi (downgrade) önlemek için mevcut tıbbi sertifikanın süresi dolmadan en az beş (5) iş günü önce güncellenmiş öz-sertifikasyon/tıbbi belgeleri sunmalarını yönlendirir. Kaynak: tn.gov/safety Medical Certification Requirements."},"89":{"q":"TÜM yeni Tennessee CDL başvuru sahipleri Giriş Seviyesi Sürücü Eğitimini (ELDT) ne zaman tamamlamalıdır?","options":["CDL beceri testini almadan önce","Yalnızca CDL zaten düzenlendikten sonra","Beceri testini geçtikten sonraki bir yıl içinde","Yalnızca bir HazMat onayı (endorsement) için başvuruyorsa"],"explanation":"7 Şubat 2022'den bu yana, ilk kez bir Class A/B başvuru sahibinin (ve belirli onay başvuru sahiplerinin) beceri/bilgi testini alabilmesi için, FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan ELDT tamamlanmalıdır. Kaynak: tn.gov/safety ELDT sayfası; 49 CFR Part 380."},"90":{"q":"Eğitimin sayılması için bir Tennessee CDL başvuru sahibinin ELDT sağlayıcısı nerede listelenmiş olmalıdır?","options":["FMCSA Training Provider Registry (TPR) üzerinde","Tennessee Department of Transportation yüklenici listesinde","Tennessee Secretary of State işletme sicilinde","National Highway Traffic Safety Administration tedarikçi listesinde"],"explanation":"ELDT, Federal Motor Carrier Safety Administration'ın Training Provider Registry'sinde (TPR) listelenen bir kuruluş tarafından sağlanmalıdır. Listelenmemiş bir sağlayıcıdan alınan eğitim gereksinimi karşılamaz. Kaynak: tn.gov/safety ELDT; FMCSA TPR."},"91":{"q":"Bir Tennessee CLP düzenlendikten sonra, sahibinin CDL beceri testini alabilmesi için ne kadar beklemesi gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Federal ve Tennessee kuralları, sahibinin CDL beceri testini alabilmesi için CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 383.25."},"92":{"q":"Tennessee CDL beceri testi, sırasıyla hangi üç bölümden oluşur?","options":["Sefer öncesi araç muayenesi, temel araç kontrol becerileri ve yolda sürüş","Görme taraması, bilgi sınavı ve paralel park etme","Hava freni testi, HazMat testi ve gece sürüşü","Yazılı test, uyuşturucu taraması ve yolda sürüş"],"explanation":"Tennessee CDL beceri testi üç bölümden oluşur: sefer öncesi araç muayenesi, temel araç kontrol becerileri testi ve yolda sürüş testi, hepsi bu sırayla. Kaynak: Tennessee CDL Kılavuzu."},"93":{"q":"Bir Tennessee başvuru sahibi CDL beceri testini neyi temsil eden bir araçta alır?","options":["Başvuru sahibinin sürmek için lisans almayı amaçladığı araç sınıfı ve tipi","Eyalet tarafından sağlanan herhangi bir binek otomobil","Aranan lisanstan bir sınıf daha küçük bir araç","Aranan lisanstan bağımsız olarak yalnızca bir Class C düz kamyon"],"explanation":"Beceri testi, CDL'nin arandığı sınıf ve konfigürasyonu temsil eden bir araçta alınmalıdır; kullanılan araç, düzenlenen lisans sınıfını kısıtlayabilir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 383.71/383.133."},"94":{"q":"Tennessee'nin uyguladığı federal standarda göre, bir Ticari Öğrenci İzni (CLP) yenilenmesi veya bilgi testlerinin yeniden alınması gerekmeden önce ne kadar süre geçerlidir?","options":["180 gün, ek 180 gün için bir kez yenilenebilir","30 gün, yenilemeye izin verilmez","Beş yıl, normal bir lisansla eşleşir","90 gün, üç kez yenilenebilir"],"explanation":"Tennessee'nin uyguladığı 49 CFR 383.25'e göre, bir CLP 180 gün geçerlidir ve genel bilgi testini yeniden almaksızın ek 180 gün için bir kez yenilenebilir. Kaynak: Tennessee CDL Kılavuzu; 49 CFR 383.25."},"95":{"q":"Bir Tennessee başvuru sahibinin CLP'sinin süresi CDL alınmadan önce dolarsa, tamamlanan testlere ne olur?","options":["Bilgi ve beceri testleri geçersiz hale gelir ve yeniden alınması gerekir","Yalnızca beceri testi kaybedilir; bilgi sonuçları beş yıl geçerli kalır","Hiçbir şey; sonuçlar bir kez geçildiğinde kalıcıdır","Testler otomatik olarak bir yıl daha geçerli kalır"],"explanation":"CLP'nin süresi tam CDL düzenlenmeden önce dolarsa, başvuru sahibi krediyi kaybeder ve bilgi ile beceri testlerini yeniden almalıdır. Kaynak: Tennessee CDL Kılavuzu; Tennessee Driver Services."},"96":{"q":"Bir yetişkine düzenlenen bir Tennessee Ticari Sürücü Belgesi için standart son kullanma süresi nedir?","options":["Sekiz yıl","Dört yıl","On yıl","İki yıl"],"explanation":"CDL'ler dahil Tennessee sürücü belgeleri genellikle sekiz yıl geçerlidir (Tenn. Code Ann. 55-50-337 uyarınca), ardından yenilenmeleri gerekir. Kaynak: Tenn. Code Ann. 55-50-337; tn.gov/safety Renewing Your License."},"97":{"q":"Tennessee CDL yenilemeleri genellikle nasıl ele alınır?","options":["Bir Driver Services Center'da şahsen, güncel tıbbi sertifikasyon sunularak","Tamamen çevrimiçi olarak, hiçbir belge gerekmeden","Sürücü tarafından herhangi bir işlem yapılmadan otomatik olarak posta ile","Department of Transportation aracılığıyla telefonla"],"explanation":"Tennessee'de CDL yenilemeleri bir Driver Services Center'da şahsen yapılır ve sahibinin yenilemede dosyada güncel tıbbi sertifikasyonu olması gerekir. Kaynak: tn.gov/safety Renewing Your License; Medical Certification Requirements."},"98":{"q":"Bir Tennessee CDL'si için niteliklere sahip 19 yaşındaki bir kişi hangi çalışma kısıtlamasına tabidir?","options":["Yalnızca eyalet içi (Tennessee içinde) çalışmayla kısıtlı","Yalnızca 26.001 pound'un altındaki araçlarla kısıtlı","Kısıtlama yok; tam eyaletlerarası ayrıcalıklar verilir","Yalnızca gündüz sürüşüyle kısıtlı"],"explanation":"Tennessee CDL başvuru sahipleri en az 18 yaşında olmalıdır; 21 yaşından küçük olanlar yalnızca eyalet içi çalışmayla kısıtlıdır. Eyaletlerarası çalışma (ve HazMat) 21 yaş gerektirir. Kaynak: Tennessee CDL Kılavuzu; tn.gov/safety Driver Services."},"99":{"q":"Tennessee CDL başvuru ve test ücretleriyle ilgili olarak, bir çalışma kılavuzu için hangi ifade en doğrudur?","options":["Ücretler Department of Safety tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri başvurmadan önce güncel tutarları teyit etmelidir","Tennessee bir CDL için hiçbir türde ücret almaz","Ücret federal yasayla kalıcı olarak sabitlenmiştir ve asla değişmez","Ücretler yalnızca başvuru sahibinin işvereni tarafından toplanır, asla eyalet tarafından değil"],"explanation":"Tennessee'deki CDL ile ilgili ücretler Department of Safety tarafından belirlenir ve zaman içinde değişebilir; başvuru sahipleri sabit bir tutara güvenmek yerine güncel listeyi bir Driver Services Center'da doğrulamalıdır. Kaynak: tn.gov/safety Driver Services ücret listesi."}},"es":{"0":{"q":"En el sistema de carreteras federales y estatales de Tennessee, ¿cuál es el ancho máximo legal de un vehículo, incluida su carga, sin necesidad de permiso?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"La ley de Tennessee permite que un vehículo o carga tenga hasta 8 pies 6 pulgadas (102 inches) de ancho en el sistema de carreteras federales y estatales; las carreteras 'comunes' están limitadas a 8 pies. Fuente: T.C.A. Section 55-7-202 (Ancho y altura máximos)."},"1":{"q":"¿Cuál es la altura máxima legal, incluida cualquier parte de la carga, para un vehículo en las carreteras de Tennessee sin necesidad de permiso?","options":["13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"Tennessee establece la altura máxima del vehículo (incluida la carga) en 13 pies 6 pulgadas. Una carga más alta requiere un permiso por exceso de altura. Fuente: T.C.A. Section 55-7-202 (Ancho y altura máximos)."},"2":{"q":"¿Cuál es el peso bruto vehicular máximo legal permitido en las carreteras de Tennessee sin un permiso especial?","options":["73,280 libras","80,000 libras","88,000 libras","100,000 libras"],"explanation":"El peso bruto máximo legal de Tennessee es de 80,000 libras, en concordancia con el límite federal para el sistema interestatal. Las cargas que superen este valor requieren un permiso por sobrepeso. Fuente: T.C.A. Section 55-7-203 (Peso máximo por eje o grupo de ejes)."},"3":{"q":"¿Cuál es el peso máximo que un eje sencillo puede transportar legalmente en las carreteras de Tennessee sin un permiso?","options":["18,000 libras","20,000 libras","22,400 libras","23,000 libras"],"explanation":"Tennessee limita un eje sencillo a 20,000 libras. La cifra de 23,000 libras aplica únicamente bajo un permiso especial por sobrepeso, no de forma legal sin él. Fuente: T.C.A. Section 55-7-203."},"4":{"q":"¿Cuál es el peso máximo que un grupo de ejes tándem puede transportar legalmente en las carreteras de Tennessee sin un permiso?","options":["32,000 libras","34,000 libras","40,000 libras","46,000 libras"],"explanation":"Tennessee limita un grupo de ejes tándem a 34,000 libras sin permiso. La cifra de 46,000 libras aplica únicamente bajo un permiso especial por sobrepeso. Fuente: T.C.A. Section 55-7-203."},"5":{"q":"¿Cuál es el ancho máximo legal de un vehículo, incluida su carga, en una carretera 'común' (fuera del sistema federal/estatal) en Tennessee?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","7 pies 6 pulgadas","9 pies 0 pulgadas"],"explanation":"En las carreteras comunes, Tennessee limita el ancho a 8 pies (4 pies a cada lado de la línea central); la tolerancia de 8 pies 6 pulgadas aplica únicamente en el sistema de carreteras federales y estatales. Fuente: T.C.A. Section 55-7-202."},"6":{"q":"Además de los límites por eje y del peso bruto, ¿qué método utiliza Tennessee para determinar el peso máximo permitido en función del espaciamiento entre ejes?","options":["La fórmula federal de puentes (tabla de peso por longitud)","El programa estatal del impuesto por tonelaje","Un tope fijo de 80,000 libras sin importar el espaciamiento","La capacidad de peso bruto combinado especificada por el fabricante"],"explanation":"Tennessee aplica la fórmula federal de puentes (Fórmula B), que relaciona el peso bruto permitido con la cantidad de ejes y la distancia entre ellos, además de los topes por eje sencillo/tándem/bruto. Fuente: T.C.A. Section 55-7-203; fórmula de puentes de la FHWA adoptada por TDOT."},"7":{"q":"Bajo un permiso especial por sobrepeso de Tennessee para una carga no divisible, ¿cuál es el peso máximo permitido en un eje sencillo?","options":["20,000 libras","21,500 libras","23,000 libras","26,000 libras"],"explanation":"Tennessee permite hasta 23,000 libras en un eje sencillo para cargas no divisibles por sobrepeso transportadas bajo permiso (frente al límite legal de 20,000 libras). Fuente: T.C.A. Section 55-7-205 y las reglas de permisos OS/OW de TDOT."},"8":{"q":"Bajo un permiso especial por sobrepeso de Tennessee, ¿cuál es el peso máximo permitido en un grupo de ejes tándem?","options":["34,000 libras","40,000 libras","46,000 libras","50,000 libras"],"explanation":"Tennessee permite hasta 46,000 libras en un grupo de ejes tándem para cargas no divisibles por sobrepeso bajo permiso (frente al límite legal de 34,000 libras). Fuente: T.C.A. Section 55-7-205 y las reglas de permisos OS/OW de TDOT."},"9":{"q":"Bajo un permiso por sobrepeso de Tennessee, ¿cuál es el peso máximo permitido en un grupo tridem (de tres ejes)?","options":["42,000 libras","50,000 libras","60,000 libras","68,000 libras"],"explanation":"Tennessee permite hasta 60,000 libras en un grupo tridem (de tres ejes) para cargas no divisibles por sobrepeso transportadas bajo permiso. Fuente: T.C.A. Section 55-7-205 y las reglas de permisos OS/OW de TDOT."},"10":{"q":"En Tennessee, por lo general se requiere un permiso especial por exceso de dimensiones o sobrepeso únicamente para cargas que son:","options":["Que transportan cualquier material peligroso","No divisibles y que no pueden reducirse razonablemente a los límites legales","Que recorren más de 100 millas dentro del estado","Registradas fuera del estado"],"explanation":"TDOT emite permisos OS/OW para artículos o mercancías no divisibles que no pueden desarmarse o separarse razonablemente para cumplir con los límites legales de tamaño/peso. Una carga que simplemente puede dividirse debe ajustarse a los límites legales. Fuente: Oficina de Permisos por Exceso de Dimensiones/Sobrepeso de TDOT; T.C.A. Section 55-7-205."},"11":{"q":"¿Por cuánto tiempo es válido un permiso estándar de Tennessee por exceso de dimensiones/sobrepeso para un solo viaje?","options":["3 días","10 días","30 días","1 año"],"explanation":"Un permiso OS/OW de Tennessee para un solo viaje es válido por 10 días (los permisos para casas móviles son válidos por 6 días). Fuente: Preguntas frecuentes y reglas de la Oficina de Permisos por Exceso de Dimensiones/Sobrepeso de TDOT."},"12":{"q":"¿Cómo solicita un transportista un permiso por exceso de dimensiones/sobrepeso en Tennessee?","options":["Mediante una llamada telefónica al alguacil local","Electrónicamente a través del sistema en línea TNTRIPS de TDOT","Enviando por correo un formulario en papel a cada condado","Solo en persona en una estación de pesaje"],"explanation":"Los permisos OS/OW de Tennessee se obtienen electrónicamente a través del sistema de permisos en línea TNTRIPS de TDOT; no se aceptan pedidos por teléfono ni por correo electrónico. Fuente: Oficina de Permisos por Exceso de Dimensiones/Sobrepeso de TDOT (TNTRIPS)."},"13":{"q":"Un semirremolque remolcado en el sistema de carreteras federales y estatales de Tennessee, por lo general, no puede exceder qué longitud desde su punto de enganche al tractocamión?","options":["48 pies","52 pies","57 pies","60 pies"],"explanation":"Tennessee permite un semirremolque/remolque remolcado de hasta 52 pies medidos desde el punto de enganche al tractocamión en el sistema de carreteras federales y estatales. Fuente: T.C.A. Section 55-7-201 (Longitud máxima de los vehículos)."},"14":{"q":"En las carreteras estatales no interestatales de Tennessee, ciertos transportistas de mercancías (como camiones madereros, de carbón, de arena y agrícolas) reciben un 'margen de error' de peso de cuánto?","options":["5 por ciento","10 por ciento","15 por ciento","No se permite ningún margen"],"explanation":"Tennessee permite un margen de error del 10 por ciento sobre el peso bruto o por eje real para camiones madereros, de arena, carbón, arcilla, esquisto, fosfato, residuos sólidos, materiales recuperados y camiones agrícolas/de maquinaria en las carreteras estatales, excluyendo el sistema interestatal. Fuente: T.C.A. Section 55-7-203(b)."},"15":{"q":"¿La tolerancia de peso del 10 por ciento para camiones madereros, agrícolas y similares de mercancías en Tennessee aplica en el sistema de carreteras interestatales?","options":["Sí, en todas las carreteras incluidas las interestatales","No, excluye el sistema interestatal","Solo de noche","Solo con un permiso"],"explanation":"La tolerancia de peso del 10 por ciento para mercancías aplica en las carreteras estatales de Tennessee, pero excluye específicamente el sistema interestatal (interestatal con financiamiento federal), donde se hacen cumplir estrictamente los límites federales de 80,000/20,000/34,000. Fuente: T.C.A. Section 55-7-203(b)."},"16":{"q":"Bajo la ley de Tennessee, cierta maquinaria agrícola puede trasladarse para fines agrícolas SIN un permiso cuando se mueve durante las horas de luz diurna, fuera de la interestatal y dentro de qué distancia de su punto de origen?","options":["25 millas","50 millas","75 millas","100 millas"],"explanation":"Tennessee permite que la maquinaria agrícola con exceso de dimensiones/sobrepeso se traslade para fines agrícolas sin un permiso durante las horas de luz diurna, fuera de las interestatales, dentro de las 50 millas del punto de origen. Fuente: T.C.A. Section 55-7-205."},"17":{"q":"Cuando una carga con permiso en Tennessee excede los 10 pies de ancho, ¿qué se requiere específicamente en el vehículo?","options":["Un vehículo piloto/de escolta en ambos extremos en todo momento","Un letrero de 'Oversize Load' en la parte delantera y trasera","Una escolta policial","Circular únicamente entre la medianoche y las 5 a.m."],"explanation":"Tennessee exige que se coloque un letrero de 'Oversize Load' en la parte delantera y trasera de cualquier carga que exceda los 10 pies de ancho. Los requisitos de escolta y otros aumentan a medida que crece el ancho. Fuente: Reglas de Permisos por Exceso de Dimensiones/Sobrepeso de TDOT."},"18":{"q":"¿Cuál es el costo aproximado de un permiso anual por sobrepeso de Tennessee para un vehículo de hasta 100,000 libras de peso bruto?","options":["$50","$150","$750","$3,500"],"explanation":"La tarifa del permiso anual por sobrepeso de TDOT es de $750 para vehículos de hasta 100,000 libras de GVW, con tarifas escalonadas más altas para pesos mayores (por ejemplo, hasta 120,000 lb a una tarifa más alta). Fuente: Programa de tarifas de la Oficina de Permisos por Exceso de Dimensiones/Sobrepeso de TDOT."},"19":{"q":"En Tennessee, el traslado de supercargas, casas flotantes y casas móviles bajo permiso, por lo general, está restringido a qué horarios de circulación?","options":["Solo durante las horas de luz diurna","Solo durante las horas nocturnas","Solo los fines de semana","A cualquier hora, las 24 horas del día"],"explanation":"Tennessee restringe el traslado de supercargas, casas flotantes y casas móviles únicamente a las horas de luz diurna, y las cargas con escolta también deben respetar los toques de queda durante las horas pico metropolitanas. Fuente: Reglas de Permisos por Exceso de Dimensiones/Sobrepeso de TDOT."},"20":{"q":"En Tennessee, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Capacidad de Peso Bruto Combinado (GCWR) de 26,001 libras o más, donde el vehículo remolcado supera las 10,000 libras de GVWR?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Tennessee define que se requiere una CDL Clase A para operar un vehículo combinado con un GCWR superior a 26,000 lbs donde la unidad remolcada excede las 10,000 lbs de GVWR. Fuente: Tenn. Comp. R. & Regs. 1340-01-13-.03; Manual de CDL de Tennessee."},"21":{"q":"¿Qué clase de CDL de Tennessee se requiere para operar un vehículo sencillo con una Capacidad de Peso Bruto Vehicular (GVWR) de 26,001 libras o más, o un vehículo de ese tipo que remolque un remolque que no supere las 10,000 libras de GVWR?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Tennessee define que se requiere una CDL Clase B para un vehículo sencillo de más de 26,000 lbs de GVWR, o un vehículo de ese tipo que remolque una unidad que no exceda las 10,000 lbs de GVWR. Fuente: Tenn. Comp. R. & Regs. 1340-01-13-.03; Manual de CDL de Tennessee."},"22":{"q":"Un conductor de Tennessee opera un vehículo sencillo de menos de 26,001 libras de GVWR que tiene placas de identificación (placards) por materiales peligrosos o está diseñado para transportar 16 o más pasajeros incluido el conductor. ¿Qué clase de CDL aplica?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"La CDL Clase C de Tennessee cubre los vehículos sencillos que no superan las 26,000 lbs de GVWR que deben portar placas de identificación por materiales peligrosos, están diseñados para transportar más de 15 pasajeros (16+ incluido el conductor) o se utilizan como autobús escolar. Fuente: Tenn. Comp. R. & Regs. 1340-01-13-.03."},"23":{"q":"En Tennessee, ¿cuál es la edad mínima para obtener una CDL restringida únicamente a la conducción comercial intraestatal (dentro del estado)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Tennessee permite que los solicitantes que tengan al menos 18 años obtengan una CDL solo para operación intraestatal. Fuente: Manual de CDL de Tennessee; Tennessee Department of Safety and Homeland Security, Servicios al Conductor."},"24":{"q":"En Tennessee, ¿cuál es la edad mínima requerida para conducir un vehículo comercial en el comercio interestatal o para transportar materiales peligrosos?","options":["18 años","19 años","21 años","25 años"],"explanation":"Tennessee requiere que un conductor tenga al menos 21 años para operar en el comercio interestatal o para transportar materiales peligrosos; los conductores de 18 a 20 años están limitados a la operación intraestatal. Fuente: Manual de CDL de Tennessee; 49 CFR 383.3 según se aplica en Tennessee."},"25":{"q":"¿Qué endoso se requiere en Tennessee para operar un vehículo comercial que transporta materiales peligrosos en cantidades que requieren placas de identificación (placards)?","options":["Endoso N","Endoso H","Endoso T","Endoso P"],"explanation":"Tennessee requiere el endoso H (Materiales Peligrosos) para conducir un CMV que transporta cantidades de materiales peligrosos que requieren placas de identificación. Fuente: Manual de CDL de Tennessee; 49 CFR 383.93."},"26":{"q":"Antes de que Tennessee pueda agregar un endoso de Materiales Peligrosos (H) a una CDL, la ley federal exige que el solicitante complete cuál paso adicional?","options":["Una evaluación de amenazas a la seguridad de la TSA con verificación de antecedentes basada en huellas dactilares","Un curso de HazMat en aula de 40 horas en Tennessee","Un examen de la vista en una estación de pesaje del Tennessee DOT","Una prueba de drogas y alcohol administrada por el secretario del condado"],"explanation":"Tennessee no puede emitir un endoso de HazMat hasta que el solicitante apruebe una evaluación de amenazas a la seguridad administrada por la TSA, que incluye una verificación de antecedentes basada en huellas dactilares, conforme a la Ley USA PATRIOT. Fuente: Tennessee Department of Safety and Homeland Security, página de Endoso de HazMat; 49 CFR 1572."},"27":{"q":"¿Qué endoso requiere Tennessee para conducir un vehículo cisterna diseñado para transportar un líquido o gas en un tanque montado de forma permanente con capacidad para transportar 1,000 galones o más?","options":["Endoso H","Endoso N","Endoso T","Endoso S"],"explanation":"Tennessee requiere el endoso N (Cisterna) para vehículos cisterna diseñados para transportar líquidos o gases en un tanque con capacidad de 1,000 galones o más. Fuente: Manual de CDL de Tennessee; 49 CFR 383.93."},"28":{"q":"¿Qué endoso se requiere en Tennessee para remolcar remolques dobles o triples, y a qué clase de CDL está limitado?","options":["Endoso T, disponible solo en Clase A","Endoso T, disponible solo en Clase B","Endoso N, disponible en cualquier clase","Endoso P, disponible solo en Clase C"],"explanation":"Tennessee requiere el endoso T (Dobles/Triples) para remolcar más de un remolque y, dado que tales combinaciones requieren una licencia Clase A, el endoso está disponible solo en Clase A. Fuente: Manual de CDL de Tennessee; Tenn. Comp. R. & Regs. 1340-01-13."},"29":{"q":"¿Qué endoso requiere Tennessee para conducir un vehículo comercial diseñado para transportar 16 o más pasajeros, incluido el conductor?","options":["Endoso S","Endoso P","Endoso N","Endoso H"],"explanation":"Tennessee requiere el endoso P (Pasajeros) para operar un vehículo diseñado para transportar 16 o más personas incluido el conductor. Fuente: Manual de CDL de Tennessee; 49 CFR 383.93."},"30":{"q":"En Tennessee, el endoso de Autobús Escolar (S) requiere que el conductor tenga primero cuál otro endoso?","options":["El endoso H (HazMat)","El endoso N (Cisterna)","El endoso P (Pasajeros)","El endoso T (Dobles/Triples)"],"explanation":"En Tennessee, el endoso S (Autobús Escolar) requiere el endoso P (Pasajeros) como requisito previo, dado que un autobús escolar es un vehículo para transportar pasajeros. Fuente: Manual de CDL de Tennessee; 49 CFR 383.93."},"31":{"q":"Bajo la regla federal aplicada en Tennessee, ¿cuánto tiempo después de que se emite inicialmente un Permiso de Aprendiz Comercial (CLP) debe esperar el titular antes de poder presentar el examen de habilidades de la CDL?","options":["7 días","14 días","30 días","60 días"],"explanation":"Un titular de CLP no puede presentar el examen de habilidades de la CDL durante los primeros 14 días posteriores a la emisión inicial del CLP. Fuente: 49 CFR 383.25 según lo aplica Servicios al Conductor de Tennessee; Manual de CDL de Tennessee."},"32":{"q":"Bajo los estándares federales que sigue Tennessee, ¿por cuánto tiempo como máximo es válido un Permiso de Aprendiz Comercial (CLP) desde su fecha inicial de emisión sin volver a presentar los exámenes de conocimientos?","options":["30 días","90 días","6 meses","1 año"],"explanation":"Un CLP debe ser válido por no más de un año desde la fecha inicial de emisión sin exigir que el titular vuelva a presentar los exámenes de conocimientos; los estados normalmente lo emiten por hasta 180 días con una renovación. Fuente: 49 CFR 383.25; Servicios al Conductor de Tennessee."},"33":{"q":"Al operar un vehículo comercial bajo un Permiso de Aprendiz Comercial (CLP) de Tennessee, ¿qué supervisión se requiere?","options":["Un titular de CDL con la clase y los endosos correspondientes debe estar sentado junto al titular del CLP","No se requiere supervisión si el conductor es mayor de 21 años","Un oficial de la ley debe seguirlo en un vehículo separado","Cualquier conductor con licencia Clase D puede ir en el asiento trasero"],"explanation":"Un titular de CLP solo puede conducir cuando va acompañado de un titular de CDL que tenga la clase y los endosos correspondientes y que esté sentado en el asiento delantero junto al titular del permiso. Fuente: 49 CFR 383.25; Manual de CDL de Tennessee."},"34":{"q":"Al solicitar una CDL o un CLP en Tennessee, ¿cuántas pruebas de residencia en Tennessee debe presentar un solicitante?","options":["Una prueba de residencia","Dos pruebas de residencia","Tres pruebas de residencia","No se requiere prueba de residencia"],"explanation":"Tennessee requiere que los solicitantes presenten dos (2) pruebas de residencia en Tennessee, junto con prueba de identidad/presencia legal y un número de Seguro Social. Fuente: Tennessee Department of Safety and Homeland Security, Documentos Requeridos para Solicitar una CDL."},"35":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CDL de Tennessee para establecer su elegibilidad?","options":["Prueba de identidad/presencia legal, prueba del número de Seguro Social y dos pruebas de residencia en Tennessee","Solo una tarjeta de registro de votante de Tennessee","Un pasaporte y únicamente una factura de servicios públicos","Un acta de nacimiento y un título de vehículo"],"explanation":"Tennessee requiere prueba de identidad y presencia legal (ciudadanía estadounidense o estatus de residente permanente legal), prueba del número de Seguro Social y dos pruebas de residencia en Tennessee. Fuente: Tennessee Department of Safety and Homeland Security, Documentos Requeridos para Solicitar una CDL."},"36":{"q":"¿Qué capacitación deben completar los nuevos solicitantes de Tennessee antes de presentar el examen de habilidades de la CDL para una licencia Clase A o Clase B, o antes de agregar ciertos endosos?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor inscrito en el Registro de Proveedores de Capacitación de la FMCSA","Un curso de manejo defensivo en una universidad comunitaria de Tennessee","Un aprendizaje de cuatro años registrado en el condado","Un programa de acompañamiento de la Patrulla de Caminos de Tennessee"],"explanation":"Tennessee requiere que los nuevos solicitantes completen la Capacitación para Conductores Principiantes (ELDT) impartida por una escuela inscrita en el Registro de Proveedores de Capacitación de la FMCSA antes del examen de habilidades para una Clase A/B o para los endosos H, P o S. Fuente: 49 CFR Part 380 Subpart F; página de CDL de Servicios al Conductor de Tennessee."},"37":{"q":"Al autocertificarse para una CDL de Tennessee, ¿qué categoría describe a un conductor que opera en el comercio interestatal y debe cumplir con el requisito del certificado del examinador médico federal del DOT?","options":["Interestatal Exceptuado (Excepted Interstate)","Interestatal No Exceptuado (Non-Excepted Interstate)","Intraestatal Exceptuado (Excepted Intrastate)","Intraestatal No Exceptuado (Non-Excepted Intrastate)"],"explanation":"Un conductor que se autocertifica como Interestatal No Exceptuado (Non-Excepted Interstate) opera en el comercio interestatal y debe mantener un certificado válido del examinador médico federal del DOT. Fuente: Tennessee Department of Safety and Homeland Security, Requisitos de Certificación Médica; 49 CFR 383.71."},"38":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL de Tennessee respecto al tipo de conducción comercial que realiza?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"Los titulares de CDL de Tennessee deben autocertificarse en una de cuatro categorías: Interestatal No Exceptuado, Interestatal Exceptuado, Intraestatal No Exceptuado e Intraestatal Exceptuado. Fuente: Tennessee Department of Safety and Homeland Security, Requisitos de Certificación Médica; 49 CFR 383.71."},"39":{"q":"Un conductor de Tennessee se autocertifica como Interestatal No Exceptuado. Para mantener válida la CDL, ¿qué debe mantener el conductor archivado ante el estado?","options":["Un certificado vigente del examinador médico federal de un examinador certificado","Una carta notariada de su empleador","Una copia de su diploma de preparatoria","Una calcomanía de inspección vehicular anual"],"explanation":"Los conductores no exceptuados deben obtener y mantener un certificado vigente del examinador médico federal emitido por un examinador médico certificado inscrito en el Registro Nacional de la FMCSA y mantenerlo archivado ante el estado. Fuente: Tennessee Department of Safety and Homeland Security, Requisitos de Certificación Médica; 49 CFR 391.45."},"40":{"q":"En Tennessee, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo comercial (CMV)?","options":["0.02","0.04","0.08","0.10"],"explanation":"Tennessee sigue el estándar federal: operar un CMV con un BAC de 0.04 o más es una infracción mayor. Esto es la mitad del límite de 0.08 para conductores no comerciales. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 1; T.C.A. 55-50-405."},"41":{"q":"Un conductor es declarado culpable por primera vez de operar un CMV con un BAC de 0.04 o más sin transportar materiales peligrosos. ¿Por cuánto tiempo se descalifica la CDL?","options":["60 días","6 meses","1 año","3 años"],"explanation":"Una primera infracción mayor (incluido un BAC de 0.04 o más en un CMV) resulta en una descalificación mínima de la CDL de 1 año en Tennessee. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 1."},"42":{"q":"Un conductor comete una primera infracción mayor por alcohol mientras opera un CMV que portaba placas de identificación (placards) por materiales peligrosos. ¿Cuál es el periodo de descalificación?","options":["1 año","2 años","3 años","5 años"],"explanation":"Cuando una primera infracción mayor ocurre mientras el CMV transporta materiales peligrosos con placas de identificación, la descalificación en Tennessee aumenta de 1 año a 3 años. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 1."},"43":{"q":"Bajo la ley de consentimiento implícito de Tennessee, ¿cuál es la consecuencia para un titular de CDL que se niega a una prueba química/de alcohol en sangre requerida por primera vez?","options":["Solo una advertencia","Pérdida de la CDL por 60 días","Pérdida de la CDL por 1 año","Pérdida de la CDL por 90 días"],"explanation":"Negarse a someterse a una prueba de alcohol se trata como una infracción mayor en Tennessee, lo que resulta en una descalificación mínima de la CDL de 1 año, igual que una primera condena por conducir por encima del límite de BAC. Fuente: Manual de CDL de Tennessee (Descalificaciones); T.C.A. 55-50-405; 49 CFR 383.51."},"44":{"q":"Un titular de CDL es declarado culpable de una SEGUNDA infracción mayor (por ejemplo, una segunda violación de BAC-0.04) durante su carrera como conductor. ¿Cuál es el periodo de descalificación en Tennessee?","options":["3 años","10 años","De por vida","5 años"],"explanation":"Una segunda infracción mayor resulta en una descalificación de la CDL de por vida. Tennessee no ha adoptado la disposición opcional de reinstalación a los 10 años, por lo que la prohibición de por vida es permanente. Fuente: Manual de CDL de Tennessee (Descalificaciones); guía sobre infracciones graves de CDL del Departamento de Seguridad de TN; 49 CFR 383.51 Table 1."},"45":{"q":"Usar un vehículo comercial para cometer un delito grave (felony) que involucre la fabricación, distribución o entrega de una sustancia controlada resulta en qué descalificación en Tennessee?","options":["1 año","3 años","De por vida, sin reinstalación","5 años"],"explanation":"Usar un CMV en la comisión de un delito grave que involucre sustancias controladas conlleva una descalificación de por vida sin posibilidad de reinstalación en Tennessee. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 1."},"46":{"q":"¿Cuántas infracciones de tránsito graves debe cometer un conductor de CDL dentro de un periodo de 3 años antes de que se active la PRIMERA descalificación en Tennessee?","options":["1 infracción","2 infracciones","3 infracciones","4 infracciones"],"explanation":"Una sola infracción de tránsito grave no causa una descalificación. La primera descalificación (60 días) se activa por una SEGUNDA infracción grave dentro de 3 años. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 2."},"47":{"q":"Un conductor de CDL es declarado culpable de DOS infracciones de tránsito graves dentro de un periodo de 3 años. ¿Cuál es el periodo de descalificación?","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años resultan en una descalificación de la CDL de 60 días en Tennessee. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 2."},"48":{"q":"Un conductor de CDL acumula TRES infracciones de tránsito graves dentro de un periodo de 3 años. ¿Cuál es el periodo de descalificación?","options":["60 días","90 días","120 días","180 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años resultan en una descalificación de la CDL de 120 días en Tennessee. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 2."},"49":{"q":"¿A qué velocidad por encima del límite señalizado el exceso de velocidad cuenta como una 'infracción de tránsito grave' para un titular de CDL de Tennessee?","options":["10 mph o más por encima","15 mph o más por encima","20 mph o más por encima","25 mph o más por encima"],"explanation":"Conducir a 15 mph o más por encima del límite de velocidad señalizado se clasifica como una infracción de tránsito grave. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 2."},"50":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE en lugar de una infracción mayor para un conductor de CDL de Tennessee?","options":["Conducir un CMV con un BAC de 0.04 o más","Conducción imprudente / seguir demasiado de cerca","Abandonar el lugar de un accidente","Usar el CMV para cometer un delito grave (felony)"],"explanation":"La conducción imprudente, seguir demasiado de cerca y los cambios de carril indebidos/erráticos son infracciones de tránsito graves. Las demás opciones enumeradas son infracciones mayores que conllevan una descalificación de 1 año (o de por vida). Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Tables 1 and 2."},"51":{"q":"Enviar mensajes de texto mientras se conduce un CMV se clasifica, según las reglas de CDL de Tennessee, como cuál de las siguientes?","options":["Una infracción mayor (descalificación de 1 año)","Una infracción de tránsito grave","Una violación de una orden de fuera de servicio","Una infracción que no genera descalificación"],"explanation":"Tanto enviar mensajes de texto como usar un teléfono móvil de mano mientras se conduce un CMV son infracciones de tránsito graves, que pueden contar para las descalificaciones de 60 días/120 días. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 2; FMCSA 392.80/392.82."},"52":{"q":"Un conductor de CDL recibe una SEGUNDA condena por usar un teléfono celular de mano mientras conduce un CMV, ocurriendo la segunda dentro de los 3 años posteriores a la primera. ¿Qué descalificación aplica?","options":["Ninguna descalificación","60 días","120 días","1 año"],"explanation":"El uso de un teléfono de mano es una infracción de tránsito grave. Una segunda infracción grave dentro de 3 años activa una descalificación de 60 días. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 2."},"53":{"q":"¿Cuál es el periodo de descalificación por una PRIMERA condena por una violación de cruce a nivel entre ferrocarril y carretera por parte de un conductor de CDL de Tennessee?","options":["No menos de 30 días","No menos de 60 días","No menos de 120 días","No menos de 1 año"],"explanation":"Una primera violación de cruce a nivel entre ferrocarril y carretera conlleva una descalificación de no menos de 60 días. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 3."},"54":{"q":"Un conductor de CDL de Tennessee es declarado culpable de una SEGUNDA violación de cruce a nivel entre ferrocarril y carretera dentro de un periodo de 3 años. ¿Cuál es la descalificación mínima?","options":["60 días","90 días","120 días","180 días"],"explanation":"Una segunda violación de cruce a nivel ferroviario dentro de 3 años resulta en una descalificación de no menos de 120 días. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 3."},"55":{"q":"Un conductor de CDL de Tennessee es declarado culpable de una TERCERA violación de cruce a nivel entre ferrocarril y carretera dentro de un periodo de 3 años. ¿Cuál es la descalificación mínima?","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera violación de cruce a nivel ferroviario dentro de 3 años resulta en una descalificación de no menos de 1 año. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 3."},"56":{"q":"¿Cuál es el periodo mínimo de descalificación por una PRIMERA violación de una orden de fuera de servicio (en un CMV que no transporta materiales peligrosos ni pasajeros) para un conductor de CDL de Tennessee?","options":["30 días","90 días","180 días","1 año"],"explanation":"Una primera violación de una orden de fuera de servicio resulta en una descalificación de no menos de 180 días (hasta 1 año). Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 4."},"57":{"q":"Además de la descalificación, ¿cuál es la sanción civil mínima que enfrenta un conductor de Tennessee por una PRIMERA violación de una orden de fuera de servicio?","options":["$1,000","$2,500","$5,000","$10,000"],"explanation":"Una primera violación de una orden de fuera de servicio conlleva una sanción civil mínima de $2,500 además de la descalificación de 180 días; una segunda conlleva un mínimo de $5,000. Fuente: Manual de CDL de Tennessee / Departamento de Seguridad de TN; 49 CFR 383.53."},"58":{"q":"Un conductor de CDL de Tennessee comete una SEGUNDA violación de una orden de fuera de servicio dentro de un periodo de 10 años (sin materiales peligrosos). ¿Cuál es la descalificación mínima?","options":["180 días","1 año","2 años","5 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años resulta en una descalificación de no menos de 2 años (y una sanción civil mínima de $5,000). Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 4."},"59":{"q":"Un conductor viola una orden de fuera de servicio por primera vez mientras el CMV transporta materiales peligrosos con placas de identificación (placards). ¿Cuál es el periodo de descalificación?","options":["No menos de 60 días","No menos de 180 días, hasta 2 años","Exactamente 1 año","De por vida"],"explanation":"Una primera violación de una orden de fuera de servicio mientras se transportan materiales peligrosos con placas de identificación (o se llevan 16+ pasajeros) conlleva una descalificación incrementada de no menos de 180 días y hasta 2 años. Fuente: Manual de CDL de Tennessee (Descalificaciones); 49 CFR 383.51 Table 4."},"60":{"q":"En una carretera de Tennessee con al menos cuatro carriles, la ley Move Over (\"Cámbiate de carril\") exige que un conductor que se aproxima y pasa junto a un vehículo de emergencia detenido que muestra luces intermitentes haga qué cosa cuando sea seguro?","options":["Cambiarse a un carril que no sea contiguo al vehículo detenido","Detenerse por completo hasta que el vehículo de emergencia se retire","Pasarse al acotamiento derecho y continuar de largo","Tocar el claxon y mantener el límite de velocidad indicado"],"explanation":"La ley Move Over de Tennessee (T.C.A. 55-8-132) exige que los conductores en una carretera de cuatro o más carriles cedan el paso cambiándose a un carril que NO sea contiguo al vehículo detenido cuando sea seguro; solo si cambiar de carril es imposible o inseguro, el conductor puede en cambio reducir a una velocidad segura. Fuente: T.C.A. 55-8-132."},"61":{"q":"Bajo la ley Move Over de Tennessee, si un conductor de CMV no puede cambiar de carril de forma segura al pasar junto a un vehículo de servicios públicos o de mantenimiento detenido con luces intermitentes, ¿qué debe hacer el conductor en su lugar?","options":["Detenerse por completo sobre la vía","Reducir la velocidad a una velocidad segura para las condiciones del camino","Reducir la velocidad a exactamente 25 mph por debajo del límite","Pasarse al acotamiento del lado opuesto"],"explanation":"El T.C.A. 55-8-132 abarca vehículos de policía, bomberos, ambulancia, servicios públicos, grúa y mantenimiento de carreteras. Si un cambio de carril es imposible o inseguro, el conductor debe reducir a una velocidad segura para las condiciones del camino; el estatuto no fija una reducción numérica. Fuente: T.C.A. 55-8-132."},"62":{"q":"Violar la ley Move Over de Tennessee (no cambiarse de carril ni reducir la velocidad ante un vehículo de emergencia detenido) se clasifica como qué?","options":["Una infracción civil sin movimiento","Un delito grave de Clase C","Un delito menor de Clase B","Solo una advertencia simple"],"explanation":"Una violación de la ley Move Over de Tennessee es un delito menor de Clase B, sancionable con una multa de hasta $500 (y posible cárcel en casos agravados). Fuente: T.C.A. 55-8-132."},"63":{"q":"¿Cuál es el límite de velocidad máximo indicado permitido en las autopistas interestatales de Tennessee?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Tennessee establece un máximo legal de 70 mph en las autopistas interestatales. Fuente: T.C.A. 55-8-152."},"64":{"q":"Bajo la ley de Tennessee, en carreteras que NO son interestatales ni rutas de acceso controlado de cuatro carriles, ¿cuál es la velocidad máxima general para un camión (capacidad nominal de 1.5 toneladas o más)?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"El T.C.A. 55-8-152 limita a los camiones (capacidad nominal de 1.5 toneladas o más) a 55 mph en carreteras que no sean interestatales ni autopistas de acceso controlado de cuatro carriles, donde el límite es de 65 mph. Fuente: T.C.A. 55-8-152."},"65":{"q":"En Tennessee, ¿cuál es la velocidad mínima legal para un vehículo que circula en el carril izquierdo (de rebase) de una autopista de acceso controlado con cuatro o más carriles?","options":["40 mph","45 mph","55 mph","65 mph"],"explanation":"Tennessee hace ilegal circular a menos de 55 mph en el carril izquierdo de una autopista de acceso controlado con cuatro o más carriles. Fuente: T.C.A. 55-8-152."},"66":{"q":"Cuando un conductor de CMV en Tennessee debe detenerse en un cruce ferroviario, ¿dónde debe detenerse el vehículo respecto al riel más cercano?","options":["A 50 pies como máximo pero no menos de 15 pies","A 25 pies como máximo pero no menos de 5 pies","A 100 pies como máximo pero no menos de 50 pies","Exactamente a 10 pies del riel"],"explanation":"Un conductor que deba detenerse tiene que hacerlo a 50 pies como máximo pero no menos de 15 pies del riel más cercano, y luego mirar y escuchar antes de avanzar. Fuente: Manual de CDL de Tennessee; 49 CFR 392.10."},"67":{"q":"¿Cuál de los siguientes SIEMPRE debe detenerse en un cruce ferroviario en Tennessee, incluso cuando no haya ningún tren a la vista?","options":["Cualquier remolque plataforma vacío","Un autobús que transporta pasajeros y un vehículo con placas de materiales peligrosos","Cualquier camión rígido de tres ejes","Cualquier vehículo de más de 26,001 libras"],"explanation":"Los CMV que deben detenerse en los cruces ferroviarios son los autobuses que transportan pasajeros y los vehículos que muestran placas de materiales peligrosos; la mayoría de los demás CMV no están obligados a detenerse a menos que las señales lo exijan. Fuente: Manual de CDL de Tennessee; 49 CFR 392.10."},"68":{"q":"Mientras cualquier parte de un CMV de Tennessee esté sobre las vías del tren durante un cruce, ¿qué NO debe hacer el conductor?","options":["Mantener ambas manos en el volante","Mirar a ambos lados de la vía","Cambiar de velocidad","Mantener una velocidad constante"],"explanation":"Los conductores no deben detenerse, cambiar de velocidad ni cambiar de carril mientras cualquier parte del vehículo esté cruzando las vías, porque un cambio fallido podría dejar al vehículo varado sobre los rieles. Fuente: Manual de CDL de Tennessee; 49 CFR 392.10."},"69":{"q":"En un camino de dos carriles de Tennessee con tránsito en ambos sentidos, ¿qué debe hacer un conductor cuando un autobús escolar se detiene y activa sus luces rojas intermitentes para subir o bajar niños?","options":["Solo los vehículos detrás del autobús deben detenerse","Los vehículos en ambos sentidos deben detenerse","Reducir a 15 mph y pasar con precaución","Rebasar el autobús por la izquierda si no hay niños a la vista"],"explanation":"En una calzada sin división, los conductores en AMBOS sentidos deben detenerse ante un autobús escolar que muestra luces rojas intermitentes y un brazo de alto hasta que este se retraiga. Fuente: T.C.A. 55-8-151."},"70":{"q":"En Tennessee, un conductor que se cruza con un autobús escolar detenido en sentido contrario queda exento de detenerse únicamente cuando las calzadas están separadas por qué cosa?","options":["Una línea central pintada","Un carril central de vuelta a la izquierda en ambos sentidos (carril \"suicida\")","Un espacio intermedio o barrera física no apta para el tránsito de vehículos (calzadas separadas)","Al menos tres carriles de circulación"],"explanation":"La excepción de Tennessee aplica solo en una carretera con calzadas separadas, lo que significa que los sentidos están divididos por un espacio intermedio o una barrera no apta para el tránsito de vehículos. Una simple línea pintada o un carril central de vuelta NO califican, por lo que los conductores aún deben detenerse. Fuente: T.C.A. 55-8-151."},"71":{"q":"Una primera infracción por rebasar ilegalmente un autobús escolar detenido en Tennessee se clasifica como qué?","options":["Una infracción sin movimiento","Un delito menor de Clase A","Un delito menor de Clase C","Solo una sanción civil"],"explanation":"Rebasar ilegalmente un autobús escolar detenido es un delito menor de Clase A en Tennessee, con una multa no menor de $250 ni mayor de $1,000 por una primera infracción. Fuente: T.C.A. 55-8-151."},"72":{"q":"En Tennessee, cuando un conductor rebasa ilegalmente un autobús escolar detenido y atropella y mata a una persona, ¿a qué nivel asciende el delito?","options":["Un delito menor de Clase A","Un delito grave de Clase E","Un delito grave de Clase C","Un delito menor de Clase B"],"explanation":"Atropellar a una persona al rebasar ilegalmente un autobús escolar detenido es un delito grave de Clase E; si el atropellamiento resulta en muerte, es un delito grave de Clase C. Fuente: T.C.A. 55-8-151."},"73":{"q":"Tennessee autoriza a TDOT a restringir los tractocamiones y semirremolques a carriles específicos en autopistas interestatales y multicarril divididas que tengan cuántos carriles en cada sentido?","options":["Uno o más","Dos o más","Tres o más","Cinco o más"],"explanation":"El T.C.A. 55-8-195 autoriza a TDOT a dirigir los tractocamiones y semirremolques a carriles específicos en autopistas interestatales y multicarril divididas con tres o más carriles en cada sentido; la violación es un delito menor de Clase C (multa de hasta $50). Fuente: T.C.A. 55-8-195."},"74":{"q":"Bajo la ley del carril izquierdo (Slow Poke) de Tennessee, ¿cuándo puede un conductor circular legalmente en el carril de rebase más a la izquierda de una autopista interestatal o multicarril dividida?","options":["Siempre que el tránsito sea ligero","Solo al alcanzar o rebasar un vehículo en un carril que no es de rebase","En cualquier momento mientras se respete el límite de velocidad","Solo entre el atardecer y el amanecer"],"explanation":"La ley del carril izquierdo de Tennessee (T.C.A. 55-8-204) restringe el carril de rebase a alcanzar o rebasar un vehículo en un carril que no es de rebase; permanecer ahí en otras circunstancias está prohibido. Fuente: T.C.A. 55-8-204."},"75":{"q":"Cuando un CMV está detenido en un acotamiento de Tennessee, ¿dónde debe colocarse el triángulo de advertencia más trasero en un camino normal de dos carriles y doble sentido?","options":["A 10 pies detrás del vehículo","A 40 pies detrás del vehículo","A 100 pies detrás del vehículo","A 200 pies detrás del vehículo"],"explanation":"Los dispositivos de advertencia deben colocarse dentro de los 10 minutos: uno a unos 10 pies detrás del lado del tránsito, uno a unos 100 pies detrás y uno a unos 100 pies delante (en la dirección del tránsito que se aproxima). Fuente: Manual de CDL de Tennessee; 49 CFR 392.22."},"76":{"q":"¿Qué tan pronto después de detenerse debe un conductor de CMV en Tennessee colocar los dispositivos de advertencia de emergencia requeridos (triángulos)?","options":["Dentro de 10 minutos","Dentro de 30 minutos","De inmediato, antes de salir de la cabina","Dentro de 1 hora"],"explanation":"Un conductor de CMV detenido debe colocar los tres triángulos de advertencia dentro de los 10 minutos posteriores a detenerse. Fuente: Manual de CDL de Tennessee; 49 CFR 392.22."},"77":{"q":"Sin un permiso especial, ¿cuál es el ancho legal máximo de un vehículo comercial y su carga en Tennessee?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 6 pulgadas","10 pies 0 pulgadas"],"explanation":"El ancho máximo legal de Tennessee sin un permiso de sobredimensión es de 8 pies 6 pulgadas; la altura legal es de 13 pies 6 pulgadas. Exceder estos valores requiere un permiso especial de TDOT. Fuente: reglas de permisos de sobredimensión/sobrepeso de TDOT; T.C.A. Título 55, Cap. 7."},"78":{"q":"Los permisos de carga sobredimensionada de Tennessee generalmente restringen el desplazamiento a qué franja horaria?","options":["Solo horas de luz diurna (aproximadamente media hora antes del amanecer hasta media hora después del atardecer)","Solo de noche, para evitar el tránsito","Cualquier período de 24 horas, incluidos los domingos","Solo entre las 9:00 a.m. y las 4:00 p.m."],"explanation":"Los permisos de sobredimensión de Tennessee generalmente permiten el desplazamiento durante la luz diurna (aproximadamente media hora antes del amanecer hasta media hora después del atardecer), de lunes a sábado, sin desplazamiento los domingos ni en días festivos importantes, y con restricciones en hora pico en los condados grandes. Fuente: reglas de permisos de sobredimensión/sobrepeso de TDOT."},"79":{"q":"En el pronunciado descenso en sentido este de Monteagle Mountain en la I-24 en Tennessee, ¿qué característica de seguridad se proporciona para los camiones que pierden los frenos?","options":["Una caseta de peaje obligatoria","Rampas de escape para camiones desbocados rellenas de grava","Un cruce en transbordador obligatorio","Un carril exprés reversible"],"explanation":"El descenso de la I-24 por Monteagle Mountain (con una pendiente de aproximadamente 6%) está equipado con rampas de escape rellenas de grava para camiones desbocados, y se indica a los camiones comerciales que usen la estación de inspección/revisión de frenos antes de descender. Fuente: TDOT; guía de conducción en montaña del Manual de CDL de Tennessee."},"80":{"q":"¿Qué agencia estatal es responsable de emitir las Licencias de Conducir Comerciales (CDL) en Tennessee?","options":["El Departamento de Seguridad y Seguridad Nacional de Tennessee","El Departamento de Transporte de Tennessee (TDOT)","El Departamento de Vehículos Motorizados de Tennessee","La Comisión de Servicios Públicos de Tennessee"],"explanation":"Las CDL en Tennessee son emitidas por el Departamento de Seguridad y Seguridad Nacional de Tennessee (TDOSHS) a través de sus centros de Driver Services. Tennessee no tiene un 'Departamento de Vehículos Motorizados' separado; TDOT se encarga de las carreteras, no de las licencias. Fuente: Manual de CDL de Tennessee; tn.gov/safety Driver Services."},"81":{"q":"¿Dónde toma un solicitante de Tennessee el examen general de conocimientos de la CDL y cualquier examen de conocimientos de endoso?","options":["En un Driver Services Center de servicio completo operado por el Departamento de Seguridad","En cualquier escuela de manejo de camiones registrada ante la FMCSA","En una oficina de distrito del Departamento de Transporte de Tennessee","En línea a través del portal de e-Services desde casa"],"explanation":"Los Driver Services Centers de servicio completo de Tennessee administran el examen general de conocimientos de la CDL y los exámenes de conocimientos para cualquier endoso. Las escuelas brindan capacitación (ELDT), no el examen estatal de conocimientos. Fuente: Manual de CDL de Tennessee; tn.gov/safety Driver Services 'How do I obtain a CDL'."},"82":{"q":"Antes de que se le emita un Permiso de Aprendiz Comercial (CLP), ¿qué debe hacer primero un solicitante de Tennessee?","options":["Aprobar el examen general de conocimientos de la CDL","Aprobar el examen de habilidades de tres partes","Completar la capacitación práctica de ELDT en pista","Mantener el CLP durante al menos 14 días"],"explanation":"Para obtener el CLP, un solicitante de Tennessee debe haber presentado y aprobado el examen general de conocimientos de la CDL (más los exámenes de endoso requeridos). El examen de habilidades y el período de espera de 14 días vienen después de que se emite el CLP. Fuente: Manual de CDL de Tennessee; tn.gov/safety Driver Services."},"83":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CDL de Tennessee en el Driver Services Center?","options":["Prueba de identidad, número de Seguro Social, ciudadanía estadounidense/presencia legal y residencia en Tennessee","Solo un pasaporte válido y una tarjeta de crédito principal","Un diploma de preparatoria y dos cartas de referencia de empleadores","Solo un título de vehículo y el registro vehicular vigente"],"explanation":"Tennessee exige prueba de identidad, prueba del número de Seguro Social, prueba de ciudadanía estadounidense o estatus de residente permanente legal, y dos documentos que prueben el domicilio/residencia en Tennessee. Fuente: Manual de CDL de Tennessee; requisitos de documentos de tn.gov/safety Driver Services."},"84":{"q":"¿Entre cuántas categorías de comercio distintas debe elegir un solicitante de CDL de Tennessee al completar la declaración jurada de autocertificación?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"La Declaración Jurada de Autocertificación de Tennessee (SF-1480) enumera cuatro opciones: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada e intraestatal exceptuada. El conductor coloca sus iniciales en exactamente una. Fuente: Declaración Jurada de Autocertificación SF-1480 de Tennessee; tn.gov/safety."},"85":{"q":"¿Qué categoría de autocertificación exige que un titular de CDL de Tennessee presente un certificado vigente de examinador médico federal del DOT?","options":["Interestatal no exceptuada","Interestatal exceptuada","Intraestatal exceptuada","Interestatal exceptuada que transporta únicamente insumos agrícolas"],"explanation":"Un conductor que se autocertifica como interestatal no exceptuado está sujeto a 49 CFR 391.45 y debe presentar un certificado vigente de examinador médico. Las categorías exceptuadas no están obligadas a presentar una tarjeta médica federal. Fuente: SF-1480 de Tennessee; Requisitos de Certificación Médica de tn.gov/safety."},"86":{"q":"En Tennessee, ¿cuál es el nombre común del certificado de examinador médico federal del DOT que los titulares de CDL interestatal no exceptuado deben mantener vigente?","options":["La tarjeta médica (tarjeta DOT)","La tarjeta de endoso de materiales peligrosos","El certificado del Servicio Selectivo","La tarjeta TWIC"],"explanation":"El certificado de examinador médico (Formulario MCSA-5876) bajo 49 CFR 391.45 se conoce comúnmente como la 'tarjeta médica' o 'tarjeta DOT'. Un TWIC y el endoso de HazMat son elementos separados. Fuente: Requisitos de Certificación Médica de Tennessee; tn.gov/safety."},"87":{"q":"¿Cómo puede un titular de CDL de Tennessee presentar al estado una nueva Declaración Jurada de Autocertificación y una certificación médica actualizada?","options":["Subiéndola a través del portal e-Services del Departamento de Seguridad o visitando un Driver Services Center","Enviándola por correo directamente al Registro Nacional de la FMCSA","Enviándola por correo electrónico al Departamento de Transporte de Tennessee","Entregándola al examinador médico, quien la presenta ante el secretario del condado"],"explanation":"Los titulares de CDL de Tennessee presentan la Declaración Jurada de Autocertificación (y la certificación médica cuando se requiere) subiéndola a través del portal e-Services del Departamento de Seguridad o en persona en un Driver Services Center. Fuente: Requisitos de Certificación Médica de tn.gov/safety."},"88":{"q":"¿En qué momento, en relación con el vencimiento de la tarjeta médica, debe un titular de CDL de Tennessee presentar la certificación médica actualizada para mantener su estatus vigente?","options":["Al menos cinco días hábiles antes del vencimiento del certificado médico vigente","Dentro de los 30 días posteriores a que el certificado ya haya vencido","Solo una vez cada ocho años en la renovación de la licencia","Dentro de un año después de que el certificado venza"],"explanation":"Tennessee indica a los titulares de CDL que presenten los documentos actualizados de autocertificación/médicos al menos cinco (5) días hábiles antes de que venza el certificado médico vigente para evitar una degradación. Fuente: Requisitos de Certificación Médica de tn.gov/safety."},"89":{"q":"¿Cuándo deben TODOS los nuevos solicitantes de CDL de Tennessee completar la Capacitación para Conductores de Nivel Inicial (ELDT)?","options":["Antes de tomar el examen de habilidades de la CDL","Solo después de que la CDL ya haya sido emitida","Dentro de un año después de aprobar el examen de habilidades","Solo si se solicita un endoso de HazMat"],"explanation":"Desde el 7 de febrero de 2022, la ELDT de un proveedor incluido en el Training Provider Registry de la FMCSA debe completarse antes de que un solicitante de Clase A/B por primera vez (y ciertos solicitantes de endoso) pueda tomar el examen de habilidades/conocimientos. Fuente: página de ELDT de tn.gov/safety; 49 CFR Parte 380."},"90":{"q":"¿Dónde debe estar incluido el proveedor de ELDT de un solicitante de CDL de Tennessee para que la capacitación cuente?","options":["En el Training Provider Registry (TPR) de la FMCSA","En la lista de contratistas del Departamento de Transporte de Tennessee","En el registro de empresas del Secretario de Estado de Tennessee","En la lista de proveedores de la Administración Nacional de Seguridad del Tráfico en las Carreteras"],"explanation":"La ELDT debe ser proporcionada por una entidad incluida en el Training Provider Registry (TPR) de la Administración Federal de Seguridad de Autotransportes. La capacitación de un proveedor no incluido en la lista no satisface el requisito. Fuente: ELDT de tn.gov/safety; TPR de la FMCSA."},"91":{"q":"Después de que se emite un CLP de Tennessee, ¿cuánto tiempo debe esperar el titular antes de poder tomar el examen de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Las reglas federales y de Tennessee exigen que el CLP se mantenga durante un mínimo de 14 días antes de que el titular pueda tomar el examen de habilidades de la CDL. Fuente: Manual de CDL de Tennessee; 49 CFR 383.25."},"92":{"q":"El examen de habilidades de la CDL de Tennessee consta de qué tres partes, en orden?","options":["Inspección del vehículo previa al viaje, habilidades básicas de control del vehículo y conducción en carretera","Examen de la vista, examen de conocimientos y estacionamiento en paralelo","Examen de frenos de aire, examen de HazMat y conducción nocturna","Examen escrito, prueba antidoping y conducción en carretera"],"explanation":"El examen de habilidades de la CDL de Tennessee tiene tres partes: la inspección del vehículo previa al viaje, el examen de habilidades básicas de control del vehículo y el examen de conducción en carretera, todas en ese orden. Fuente: Manual de CDL de Tennessee."},"93":{"q":"Un solicitante de Tennessee toma el examen de habilidades de la CDL en un vehículo que representa qué?","options":["La clase y el tipo de vehículo que el solicitante pretende estar autorizado a conducir","Cualquier automóvil de pasajeros proporcionado por el estado","Un vehículo de una clase más pequeña que la licencia solicitada","Solo un camión rígido de Clase C sin importar la licencia solicitada"],"explanation":"El examen de habilidades debe tomarse en un vehículo representativo de la clase y configuración para la cual se solicita la CDL; el vehículo utilizado puede restringir la clase de licencia emitida. Fuente: Manual de CDL de Tennessee; 49 CFR 383.71/383.133."},"94":{"q":"Bajo el estándar federal que sigue Tennessee, ¿cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) antes de que deba renovarse o se deban volver a tomar los exámenes de conocimientos?","options":["180 días, renovable una vez por 180 días adicionales","30 días, sin renovación permitida","Cinco años, igual que una licencia regular","90 días, renovable hasta tres veces"],"explanation":"Según 49 CFR 383.25, que Tennessee aplica, un CLP es válido por 180 días y puede renovarse una vez por 180 días adicionales sin volver a tomar el examen general de conocimientos. Fuente: Manual de CDL de Tennessee; 49 CFR 383.25."},"95":{"q":"Si el CLP de un solicitante de Tennessee vence antes de obtener la CDL, ¿qué sucede con los exámenes completados?","options":["Los exámenes de conocimientos y de habilidades quedan invalidados y deben volver a tomarse","Solo se pierde el examen de habilidades; los resultados de conocimientos siguen siendo válidos por cinco años","Nada; los resultados son permanentes una vez aprobados","Los exámenes siguen siendo válidos por un año adicional automáticamente"],"explanation":"Si el CLP vence antes de que se emita la CDL completa, el solicitante pierde el crédito y debe volver a tomar los exámenes de conocimientos y de habilidades. Fuente: Manual de CDL de Tennessee; Tennessee Driver Services."},"96":{"q":"¿Cuál es el ciclo de vencimiento estándar para una Licencia de Conducir Comercial de Tennessee emitida a un adulto?","options":["Ocho años","Cuatro años","Diez años","Dos años"],"explanation":"Las licencias de conducir de Tennessee, incluidas las CDL, generalmente son válidas por ocho años (según Tenn. Code Ann. 55-50-337), después de lo cual deben renovarse. Fuente: Tenn. Code Ann. 55-50-337; tn.gov/safety Renewing Your License."},"97":{"q":"¿Cómo se gestionan generalmente las renovaciones de CDL en Tennessee?","options":["En persona en un Driver Services Center, con la certificación médica vigente presentada","Totalmente en línea sin documentos requeridos","Automáticamente por correo sin acción por parte del conductor","Por teléfono a través del Departamento de Transporte"],"explanation":"Las renovaciones de CDL en Tennessee se realizan en persona en un Driver Services Center, y el titular debe tener la certificación médica vigente en el expediente al momento de la renovación. Fuente: tn.gov/safety Renewing Your License; Requisitos de Certificación Médica."},"98":{"q":"Una persona de 19 años que califica para una CDL de Tennessee está sujeta a qué restricción operativa?","options":["Restringida solo a operación intraestatal (dentro de Tennessee)","Restringida solo a vehículos de menos de 26,001 libras","Sin restricción; se otorgan privilegios interestatales completos","Restringida solo a conducción diurna"],"explanation":"Los solicitantes de CDL de Tennessee deben tener al menos 18 años; los menores de 21 están restringidos solo a operación intraestatal. La operación interestatal (y HazMat) requiere tener 21 años. Fuente: Manual de CDL de Tennessee; tn.gov/safety Driver Services."},"99":{"q":"Respecto a las tarifas de solicitud y examen de la CDL de Tennessee, ¿qué afirmación es la más precisa para una guía de estudio?","options":["Las tarifas las establece el Departamento de Seguridad y están sujetas a cambios, por lo que los solicitantes deben confirmar los montos vigentes antes de solicitar","Tennessee no cobra ningún tipo de tarifa por una CDL","La tarifa está fijada permanentemente por la ley federal y nunca cambia","Las tarifas las cobra únicamente el empleador del solicitante, nunca el estado"],"explanation":"Las tarifas relacionadas con la CDL en Tennessee las establece el Departamento de Seguridad y pueden cambiar con el tiempo; los solicitantes deben verificar el tarifario vigente en un Driver Services Center en lugar de basarse en un monto fijo. Fuente: tarifario de tn.gov/safety Driver Services."}},"hi":{"0":{"q":"टेनेसी की संघीय और राज्य राजमार्ग प्रणाली पर, बिना परमिट के किसी वाहन की उसके भार सहित अधिकतम कानूनी चौड़ाई कितनी होती है?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"टेनेसी कानून संघीय और राज्य राजमार्ग प्रणाली पर किसी वाहन या भार की चौड़ाई 8 feet 6 inches (102 inches) तक की अनुमति देता है; 'सामान्य' सड़कें 8 feet तक सीमित हैं। स्रोत: T.C.A. Section 55-7-202 (अधिकतम चौड़ाई और ऊँचाई)।"},"1":{"q":"टेनेसी के राजमार्गों पर बिना परमिट के किसी वाहन की, भार के किसी भी हिस्से सहित, अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"explanation":"टेनेसी अधिकतम वाहन ऊँचाई (भार सहित) को 13 feet 6 inches निर्धारित करता है। इससे अधिक ऊँचे भार के लिए ओवर-हाइट परमिट आवश्यक है। स्रोत: T.C.A. Section 55-7-202 (अधिकतम चौड़ाई और ऊँचाई)।"},"2":{"q":"टेनेसी के राजमार्गों पर बिना किसी विशेष परमिट के अनुमत अधिकतम कानूनी सकल वाहन भार कितना होता है?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"टेनेसी का अधिकतम कानूनी सकल भार 80,000 pounds है, जो इंटरस्टेट प्रणाली के लिए संघीय सीमा के अनुरूप है। इससे अधिक भार के लिए ओवरवेट परमिट आवश्यक है। स्रोत: T.C.A. Section 55-7-203 (प्रति एक्सल या एक्सल समूह अधिकतम भार)।"},"3":{"q":"टेनेसी के राजमार्गों पर बिना परमिट के एक सिंगल एक्सल कानूनी रूप से अधिकतम कितना भार वहन कर सकता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","23,000 pounds"],"explanation":"टेनेसी एक सिंगल एक्सल को 20,000 pounds तक सीमित करता है। 23,000-pound का आँकड़ा केवल किसी विशेष ओवरवेट परमिट के तहत लागू होता है, बिना परमिट के कानूनी रूप से नहीं। स्रोत: T.C.A. Section 55-7-203।"},"4":{"q":"टेनेसी के राजमार्गों पर बिना परमिट के एक टैंडम एक्सल समूह कानूनी रूप से अधिकतम कितना भार वहन कर सकता है?","options":["32,000 pounds","34,000 pounds","40,000 pounds","46,000 pounds"],"explanation":"टेनेसी एक टैंडम एक्सल समूह को बिना परमिट के 34,000 pounds तक सीमित करता है। 46,000-pound का आँकड़ा केवल किसी विशेष ओवरवेट परमिट के तहत लागू होता है। स्रोत: T.C.A. Section 55-7-203।"},"5":{"q":"टेनेसी में किसी 'सामान्य' (गैर-संघीय/राज्य-प्रणाली) सड़क पर किसी वाहन की, उसके भार सहित, अधिकतम कानूनी चौड़ाई कितनी होती है?","options":["8 feet 0 inches","8 feet 6 inches","7 feet 6 inches","9 feet 0 inches"],"explanation":"सामान्य सड़कों पर, टेनेसी चौड़ाई को 8 feet तक सीमित करता है (केंद्र रेखा के प्रत्येक ओर 4 feet); 8-foot-6-inch की छूट केवल संघीय और राज्य राजमार्ग प्रणाली पर लागू होती है। स्रोत: T.C.A. Section 55-7-202।"},"6":{"q":"प्रति-एक्सल और सकल सीमाओं के अलावा, एक्सल अंतराल के आधार पर अधिकतम अनुमेय भार निर्धारित करने के लिए टेनेसी किस विधि का उपयोग करता है?","options":["संघीय ब्रिज फॉर्मूला (भार-से-लंबाई तालिका)","राज्य टनभार कर अनुसूची","अंतराल की परवाह किए बिना एक समान 80,000-pound की सीमा","निर्माता की सकल संयोजन भार रेटिंग"],"explanation":"टेनेसी संघीय ब्रिज फॉर्मूला (Formula B) लागू करता है, जो सिंगल/टैंडम/सकल सीमाओं के अतिरिक्त, अनुमेय सकल भार को एक्सल की संख्या और उनके बीच की दूरी से जोड़ता है। स्रोत: T.C.A. Section 55-7-203; TDOT द्वारा अपनाया गया FHWA ब्रिज फॉर्मूला।"},"7":{"q":"किसी अविभाज्य भार के लिए टेनेसी के विशेष ओवरवेट परमिट के तहत, एक सिंगल एक्सल पर अधिकतम कितना भार अनुमत है?","options":["20,000 pounds","21,500 pounds","23,000 pounds","26,000 pounds"],"explanation":"टेनेसी परमिट के तहत स्थानांतरित किए जाने वाले अविभाज्य ओवरवेट भार के लिए एक सिंगल एक्सल पर 23,000 pounds तक की अनुमति देता है (बनाम 20,000-pound की कानूनी सीमा)। स्रोत: T.C.A. Section 55-7-205 और TDOT OS/OW परमिट नियम।"},"8":{"q":"टेनेसी के विशेष ओवरवेट परमिट के तहत, एक टैंडम एक्सल समूह पर अधिकतम कितना भार अनुमत है?","options":["34,000 pounds","40,000 pounds","46,000 pounds","50,000 pounds"],"explanation":"टेनेसी परमिट के तहत अविभाज्य ओवरवेट भार के लिए एक टैंडम एक्सल समूह पर 46,000 pounds तक की अनुमति देता है (बनाम 34,000-pound की कानूनी सीमा)। स्रोत: T.C.A. Section 55-7-205 और TDOT OS/OW परमिट नियम।"},"9":{"q":"टेनेसी के ओवरवेट परमिट के तहत, एक ट्राइडेम (तीन-एक्सल) समूह पर अधिकतम कितना भार अनुमत है?","options":["42,000 pounds","50,000 pounds","60,000 pounds","68,000 pounds"],"explanation":"टेनेसी परमिट के तहत स्थानांतरित किए जाने वाले अविभाज्य ओवरवेट भार के लिए एक ट्राइडेम (तीन-एक्सल) समूह पर 60,000 pounds तक की अनुमति देता है। स्रोत: T.C.A. Section 55-7-205 और TDOT OS/OW परमिट नियम।"},"10":{"q":"टेनेसी में, एक विशेष ओवरसाइज या ओवरवेट परमिट आमतौर पर केवल उन्हीं भारों के लिए आवश्यक होता है जो:","options":["कोई भी खतरनाक सामग्री ले जा रहे हों","अविभाज्य हों और जिन्हें कानूनी सीमाओं तक उचित रूप से कम नहीं किया जा सकता","राज्य में 100 miles से अधिक यात्रा कर रहे हों","राज्य के बाहर पंजीकृत हों"],"explanation":"TDOT ऐसी अविभाज्य वस्तुओं या सामग्रियों के लिए OS/OW परमिट जारी करता है जिन्हें कानूनी आकार/भार सीमाओं को पूरा करने के लिए उचित रूप से अलग-अलग या विभाजित नहीं किया जा सकता। ऐसे भार को जिसे केवल विभाजित किया जा सकता है, बजाय इसके कानूनी सीमाओं के भीतर लाया जाना चाहिए। स्रोत: TDOT ओवरसाइज/ओवरवेट परमिट कार्यालय; T.C.A. Section 55-7-205।"},"11":{"q":"टेनेसी का एक मानक सिंगल-ट्रिप ओवरसाइज/ओवरवेट परमिट कितने समय के लिए वैध होता है?","options":["3 days","10 days","30 days","1 year"],"explanation":"टेनेसी का एक सिंगल-ट्रिप OS/OW परमिट 10 days के लिए वैध होता है (मोबाइल होम परमिट 6 days के लिए वैध होते हैं)। स्रोत: TDOT ओवरसाइज/ओवरवेट परमिट कार्यालय FAQ और नियम।"},"12":{"q":"टेनेसी में एक कैरियर ओवरसाइज/ओवरवेट परमिट के लिए कैसे आवेदन करता है?","options":["स्थानीय शेरिफ को फोन कॉल करके","TDOT TNTRIPS ऑनलाइन प्रणाली के माध्यम से इलेक्ट्रॉनिक रूप से","प्रत्येक काउंटी को एक कागजी फॉर्म डाक से भेजकर","केवल व्यक्तिगत रूप से किसी वज़न स्टेशन पर"],"explanation":"टेनेसी के OS/OW परमिट TDOT की TNTRIPS ऑनलाइन परमिटिंग प्रणाली के माध्यम से इलेक्ट्रॉनिक रूप से प्राप्त किए जाते हैं; फोन और ईमेल ऑर्डर स्वीकार नहीं किए जाते। स्रोत: TDOT ओवरसाइज/ओवरवेट परमिट कार्यालय (TNTRIPS)।"},"13":{"q":"टेनेसी की संघीय और राज्य राजमार्ग प्रणाली पर एक खींचा जाने वाला सेमीट्रेलर आमतौर पर ट्रैक्टर से जुड़ने के बिंदु से अधिकतम कितनी लंबाई से अधिक नहीं हो सकता?","options":["48 feet","52 feet","57 feet","60 feet"],"explanation":"टेनेसी संघीय और राज्य राजमार्ग प्रणाली पर ट्रैक्टर से जुड़ने के बिंदु से मापे गए एक खींचे जाने वाले सेमीट्रेलर/ट्रेलर को 52 feet तक की अनुमति देता है। स्रोत: T.C.A. Section 55-7-201 (वाहनों की अधिकतम लंबाई)।"},"14":{"q":"टेनेसी के गैर-इंटरस्टेट राज्य राजमार्गों पर, कुछ कमोडिटी ढोने वाले (जैसे लॉगिंग, कोयला, रेत और फार्म ट्रक) को कितनी 'त्रुटि की सीमा' (margin of error) दी जाती है?","options":["5 percent","10 percent","15 percent","कोई सीमा अनुमत नहीं है"],"explanation":"टेनेसी इंटरस्टेट प्रणाली को छोड़कर राज्य राजमार्गों पर लॉगिंग, रेत, कोयला, मिट्टी, शेल, फॉस्फेट, ठोस अपशिष्ट, पुनर्प्राप्त सामग्री, और फार्म/मशीनरी ट्रकों के लिए वास्तविक सकल या एक्सल भार पर 10 percent त्रुटि की सीमा की अनुमति देता है। स्रोत: T.C.A. Section 55-7-203(b)।"},"15":{"q":"क्या टेनेसी में लॉगिंग, फार्म और इसी तरह के कमोडिटी ट्रकों के लिए 10 percent भार सहनशीलता इंटरस्टेट राजमार्ग प्रणाली पर लागू होती है?","options":["हाँ, इंटरस्टेट सहित सभी राजमार्गों पर","नहीं, यह इंटरस्टेट प्रणाली को बाहर रखती है","केवल रात में","केवल परमिट के साथ"],"explanation":"10 percent कमोडिटी भार सहनशीलता टेनेसी राज्य राजमार्गों पर लागू होती है लेकिन विशेष रूप से इंटरस्टेट (संघीय-सहायता इंटरस्टेट) प्रणाली को बाहर रखती है, जहाँ संघीय 80,000/20,000/34,000 सीमाएँ कड़ाई से लागू की जाती हैं। स्रोत: T.C.A. Section 55-7-203(b)।"},"16":{"q":"टेनेसी कानून के तहत, फार्म प्रयोजनों के लिए कुछ फार्म मशीनरी को बिना परमिट के तब स्थानांतरित किया जा सकता है जब इसे दिन के उजाले के घंटों में, इंटरस्टेट से बाहर, और इसके मूल बिंदु से कितनी दूरी के भीतर स्थानांतरित किया जाए?","options":["25 miles","50 miles","75 miles","100 miles"],"explanation":"टेनेसी ओवर-डाइमेंशन/ओवर-वेट फार्म मशीनरी को फार्म प्रयोजनों के लिए बिना परमिट के दिन के उजाले के घंटों में, इंटरस्टेट पर नहीं, मूल बिंदु से 50 miles के भीतर स्थानांतरित करने की अनुमति देता है। स्रोत: T.C.A. Section 55-7-205।"},"17":{"q":"जब टेनेसी में किसी परमिट प्राप्त भार की चौड़ाई 10 feet से अधिक हो, तो वाहन पर विशेष रूप से क्या आवश्यक है?","options":["हर समय दोनों छोर पर एक पायलट/एस्कॉर्ट वाहन","आगे और पीछे एक 'Oversize Load' बैनर","एक पुलिस एस्कॉर्ट","केवल आधी रात से सुबह 5 a.m. के बीच यात्रा"],"explanation":"टेनेसी 10 feet से अधिक चौड़ाई वाले किसी भी भार के आगे और पीछे एक 'Oversize Load' बैनर प्रदर्शित करना आवश्यक करता है। एस्कॉर्ट और अन्य आवश्यकताएँ चौड़ाई के साथ बढ़ती जाती हैं। स्रोत: TDOT ओवरसाइज/ओवरवेट परमिट नियम।"},"18":{"q":"100,000 pounds तक के सकल भार वाले वाहन के लिए टेनेसी के वार्षिक ओवरवेट परमिट की अनुमानित लागत क्या है?","options":["$50","$150","$750","$3,500"],"explanation":"TDOT का वार्षिक ओवरवेट परमिट शुल्क 100,000 pounds GVW तक के वाहनों के लिए $750 है, अधिक भार के लिए उच्चतर स्तरीय शुल्क के साथ (जैसे, उच्चतर दर पर 120,000 lb तक)। स्रोत: TDOT ओवरसाइज/ओवरवेट परमिट कार्यालय शुल्क अनुसूची।"},"19":{"q":"टेनेसी में, परमिट के तहत सुपरलोड, हाउसबोट और मोबाइल होम के आवागमन को आमतौर पर किन यात्रा समयों तक सीमित किया जाता है?","options":["केवल दिन के उजाले के घंटे","केवल रात के घंटे","केवल सप्ताहांत","किसी भी समय, 24 घंटे"],"explanation":"टेनेसी सुपरलोड, हाउसबोट और मोबाइल होम के आवागमन को केवल दिन के उजाले के घंटों तक सीमित करता है, और एस्कॉर्ट किए गए भारों को महानगरीय व्यस्त-समय (रश-आवर) कर्फ्यू का भी पालन करना होता है। स्रोत: TDOT ओवरसाइज/ओवरवेट परमिट नियम।"},"20":{"q":"टेनेसी में, 26,001 pounds या उससे अधिक की सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के संयोजन को चलाने के लिए कौन सा CDL वर्ग आवश्यक है, जहाँ खींचा जा रहा वाहन 10,000 pounds GVWR से अधिक का हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"टेनेसी एक Class A CDL को ऐसे संयोजन वाहन को चलाने के लिए आवश्यक बताता है जिसका GCWR 26,000 lbs से अधिक हो जहाँ खींची गई इकाई 10,000 lbs GVWR से अधिक हो। स्रोत: Tenn. Comp. R. & Regs. 1340-01-13-.03; टेनेसी CDL मैनुअल।"},"21":{"q":"26,001 pounds या उससे अधिक की सकल वाहन भार रेटिंग (GVWR) वाले एक सिंगल वाहन को, या ऐसे वाहन को जो 10,000 pounds GVWR से अधिक न होने वाला ट्रेलर खींच रहा हो, चलाने के लिए कौन सा टेनेसी CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class M"],"explanation":"टेनेसी एक Class B CDL को 26,000 lbs GVWR से अधिक के एक सिंगल वाहन के लिए, या ऐसे वाहन के लिए जो 10,000 lbs GVWR से अधिक न होने वाली इकाई खींच रहा हो, आवश्यक बताता है। स्रोत: Tenn. Comp. R. & Regs. 1340-01-13-.03; टेनेसी CDL मैनुअल।"},"22":{"q":"एक टेनेसी ड्राइवर 26,001 pounds GVWR से कम के एक सिंगल वाहन को चलाता है जिस पर खतरनाक सामग्री के लिए प्लेकार्ड लगा है या जो चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है। कौन सा CDL वर्ग लागू होता है?","options":["Class A","Class B","Class C","Class D"],"explanation":"टेनेसी का Class C CDL ऐसे सिंगल वाहनों को कवर करता है जो 26,000 lbs GVWR से अधिक नहीं हैं और जिन पर खतरनाक सामग्री के लिए प्लेकार्ड लगाना आवश्यक है, जो 15 से अधिक यात्रियों (चालक सहित 16+) को ले जाने के लिए डिज़ाइन किए गए हैं, या जिनका उपयोग स्कूल बस के रूप में किया जाता है। स्रोत: Tenn. Comp. R. & Regs. 1340-01-13-.03।"},"23":{"q":"टेनेसी में, केवल इंट्रास्टेट (राज्य के भीतर) वाणिज्यिक ड्राइविंग तक सीमित CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"टेनेसी कम से कम 18 वर्ष के आवेदकों को केवल इंट्रास्टेट संचालन के लिए CDL प्राप्त करने की अनुमति देता है। स्रोत: टेनेसी CDL मैनुअल; Tennessee Department of Safety and Homeland Security, Driver Services।"},"24":{"q":"टेनेसी में, इंटरस्टेट वाणिज्य में किसी वाणिज्यिक वाहन को चलाने या खतरनाक सामग्री ले जाने के लिए न्यूनतम आवश्यक आयु क्या है?","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"टेनेसी इंटरस्टेट वाणिज्य में संचालन करने या खतरनाक सामग्री ले जाने के लिए ड्राइवर का कम से कम 21 वर्ष का होना आवश्यक करता है; 18-20 वर्ष के ड्राइवर केवल इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: टेनेसी CDL मैनुअल; टेनेसी में लागू 49 CFR 383.3।"},"25":{"q":"ऐसी मात्राओं में खतरनाक सामग्री ले जाने वाले वाणिज्यिक वाहन को चलाने के लिए टेनेसी में कौन सा एंडोर्समेंट आवश्यक है जिनके लिए प्लेकार्ड लगाना आवश्यक हो?","options":["N endorsement","H endorsement","T endorsement","P endorsement"],"explanation":"टेनेसी प्लेकार्ड-योग्य मात्रा में खतरनाक सामग्री ले जाने वाले CMV को चलाने के लिए H (खतरनाक सामग्री) एंडोर्समेंट आवश्यक करता है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.93।"},"26":{"q":"इससे पहले कि टेनेसी किसी CDL में खतरनाक सामग्री (H) एंडोर्समेंट जोड़ सके, संघीय कानून आवेदक को कौन सा अतिरिक्त कदम पूरा करना आवश्यक करता है?","options":["फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच के साथ एक TSA सुरक्षा खतरा आकलन","टेनेसी में 40 घंटे का कक्षा HazMat पाठ्यक्रम","एक टेनेसी DOT वज़न स्टेशन पर एक दृष्टि परीक्षा","काउंटी क्लर्क द्वारा प्रशासित एक दवा और शराब परीक्षण"],"explanation":"टेनेसी तब तक HazMat एंडोर्समेंट जारी नहीं कर सकता जब तक आवेदक USA PATRIOT Act के तहत एक TSA-प्रशासित सुरक्षा खतरा आकलन पास नहीं कर लेता, जिसमें एक फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच शामिल है। स्रोत: Tennessee Department of Safety and Homeland Security, HazMat Endorsement पृष्ठ; 49 CFR 1572।"},"27":{"q":"किसी स्थायी रूप से लगे टैंक में, जो 1,000 गैलन या उससे अधिक ले जाने के लिए रेटेड हो, तरल या गैस ढोने के लिए डिज़ाइन किए गए टैंक वाहन को चलाने के लिए टेनेसी कौन सा एंडोर्समेंट आवश्यक करता है?","options":["H endorsement","N endorsement","T endorsement","S endorsement"],"explanation":"टेनेसी 1,000 गैलन या उससे अधिक रेटेड टैंक में तरल या गैस ले जाने के लिए डिज़ाइन किए गए टैंक वाहनों के लिए N (टैंकर) एंडोर्समेंट आवश्यक करता है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.93।"},"28":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए टेनेसी में कौन सा एंडोर्समेंट आवश्यक है, और यह किस CDL वर्ग तक सीमित है?","options":["T endorsement, केवल Class A पर उपलब्ध","T endorsement, केवल Class B पर उपलब्ध","N endorsement, किसी भी वर्ग पर उपलब्ध","P endorsement, केवल Class C पर उपलब्ध"],"explanation":"टेनेसी एक से अधिक ट्रेलर खींचने के लिए T (डबल्स/ट्रिपल्स) एंडोर्समेंट आवश्यक करता है, और चूँकि ऐसे संयोजनों के लिए Class A लाइसेंस आवश्यक होता है, यह एंडोर्समेंट केवल Class A पर उपलब्ध है। स्रोत: टेनेसी CDL मैनुअल; Tenn. Comp. R. & Regs. 1340-01-13।"},"29":{"q":"चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाणिज्यिक वाहन को चलाने के लिए टेनेसी कौन सा एंडोर्समेंट आवश्यक करता है?","options":["S endorsement","P endorsement","N endorsement","H endorsement"],"explanation":"टेनेसी चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए P (यात्री) एंडोर्समेंट आवश्यक करता है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.93।"},"30":{"q":"टेनेसी में, स्कूल बस (S) एंडोर्समेंट के लिए ड्राइवर को पहले कौन सा अन्य एंडोर्समेंट धारण करना आवश्यक है?","options":["H (HazMat) एंडोर्समेंट","N (टैंकर) एंडोर्समेंट","P (यात्री) एंडोर्समेंट","T (डबल्स/ट्रिपल्स) एंडोर्समेंट"],"explanation":"टेनेसी में, S (स्कूल बस) एंडोर्समेंट के लिए एक पूर्वापेक्षा के रूप में P (यात्री) एंडोर्समेंट आवश्यक है, क्योंकि स्कूल बस एक यात्री-वहन वाहन है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.93।"},"31":{"q":"टेनेसी में लागू संघीय नियम के तहत, एक कमर्शियल लर्नर परमिट (CLP) के प्रारंभिक रूप से जारी होने के बाद धारक को CDL कौशल परीक्षा देने के पात्र होने से पहले कितने समय तक प्रतीक्षा करनी होती है?","options":["7 days","14 days","30 days","60 days"],"explanation":"CLP के प्रारंभिक रूप से जारी होने के बाद पहले 14 days में एक CLP धारक CDL कौशल परीक्षा देने के पात्र नहीं होता। स्रोत: Tennessee Driver Services द्वारा लागू 49 CFR 383.25; टेनेसी CDL मैनुअल।"},"32":{"q":"टेनेसी में अपनाए गए संघीय मानकों के तहत, एक कमर्शियल लर्नर परमिट (CLP) ज्ञान परीक्षाएँ दोबारा दिए बिना अपनी प्रारंभिक जारी होने की तारीख से अधिकतम कितने समय के लिए वैध होता है?","options":["30 days","90 days","6 months","1 year"],"explanation":"एक CLP धारक को ज्ञान परीक्षाएँ दोबारा देने की आवश्यकता के बिना प्रारंभिक जारी होने की तारीख से अधिकतम एक वर्ष के लिए वैध होना चाहिए; राज्य आमतौर पर इसे एक नवीनीकरण के साथ 180 days तक के लिए जारी करते हैं। स्रोत: 49 CFR 383.25; Tennessee Driver Services।"},"33":{"q":"टेनेसी कमर्शियल लर्नर परमिट (CLP) के तहत एक वाणिज्यिक वाहन चलाते समय, किस पर्यवेक्षण की आवश्यकता होती है?","options":["उचित वर्ग और एंडोर्समेंट वाला एक CDL धारक CLP धारक के बगल में बैठा होना चाहिए","यदि ड्राइवर 21 वर्ष से अधिक का है तो कोई पर्यवेक्षण आवश्यक नहीं है","एक कानून प्रवर्तन अधिकारी को एक अलग वाहन में पीछे चलना चाहिए","कोई भी लाइसेंस प्राप्त Class D ड्राइवर पिछली सीट पर बैठ सकता है"],"explanation":"एक CLP धारक केवल तभी गाड़ी चला सकता है जब उसके साथ एक CDL धारक हो जिसके पास उपयुक्त वर्ग और एंडोर्समेंट हों और जो परमिट धारक के बगल में आगे की सीट पर बैठा हो। स्रोत: 49 CFR 383.25; टेनेसी CDL मैनुअल।"},"34":{"q":"टेनेसी में CDL या CLP के लिए आवेदन करते समय, एक आवेदक को टेनेसी निवास के कितने प्रमाण प्रदान करने होते हैं?","options":["निवास का एक प्रमाण","निवास के दो प्रमाण","निवास के तीन प्रमाण","निवास का कोई प्रमाण आवश्यक नहीं है"],"explanation":"टेनेसी आवेदकों को पहचान/वैध उपस्थिति के प्रमाण और एक सामाजिक सुरक्षा नंबर के साथ-साथ टेनेसी निवास के दो (2) प्रमाण प्रस्तुत करना आवश्यक करता है। स्रोत: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL।"},"35":{"q":"पात्रता स्थापित करने के लिए एक टेनेसी CDL आवेदक को दस्तावेज़ों का कौन सा समूह प्रदान करना होता है?","options":["पहचान/वैध उपस्थिति का प्रमाण, सामाजिक सुरक्षा नंबर का प्रमाण, और टेनेसी निवास के दो प्रमाण","केवल एक टेनेसी मतदाता पंजीकरण कार्ड","केवल एक पासपोर्ट और एक यूटिलिटी बिल","एक जन्म प्रमाणपत्र और एक वाहन टाइटल"],"explanation":"टेनेसी पहचान और वैध उपस्थिति का प्रमाण (अमेरिकी नागरिकता या वैध स्थायी निवासी स्थिति), सामाजिक सुरक्षा नंबर का प्रमाण, और टेनेसी निवास के दो प्रमाण आवश्यक करता है। स्रोत: Tennessee Department of Safety and Homeland Security, Required Documents to Apply for a CDL।"},"36":{"q":"नए टेनेसी आवेदकों को Class A या Class B लाइसेंस के लिए CDL कौशल परीक्षा देने से पहले, या कुछ एंडोर्समेंट जोड़ने से पहले, कौन सा प्रशिक्षण पूरा करना आवश्यक है?","options":["FMCSA प्रशिक्षण प्रदाता रजिस्ट्री पर मौजूद किसी प्रदाता से एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT)","एक टेनेसी सामुदायिक कॉलेज में एक रक्षात्मक ड्राइविंग पाठ्यक्रम","काउंटी के साथ दर्ज एक चार-वर्षीय प्रशिक्षुता","एक टेनेसी हाईवे पेट्रोल राइड-अलॉन्ग कार्यक्रम"],"explanation":"टेनेसी नए आवेदकों को Class A/B के लिए या H, P, या S एंडोर्समेंट के लिए कौशल परीक्षा से पहले FMCSA प्रशिक्षण प्रदाता रजिस्ट्री पर सूचीबद्ध किसी स्कूल द्वारा प्रदान की गई एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) पूरी करना आवश्यक करता है। स्रोत: 49 CFR Part 380 Subpart F; Tennessee Driver Services CDL पृष्ठ।"},"37":{"q":"टेनेसी CDL के लिए स्व-प्रमाणन (self-certifying) करते समय, कौन सी श्रेणी ऐसे ड्राइवर का वर्णन करती है जो इंटरस्टेट वाणिज्य में संचालन करता है और जिसे संघीय DOT मेडिकल परीक्षक प्रमाणपत्र की आवश्यकता पूरी करनी होती है?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"एक ड्राइवर जो Non-Excepted Interstate के रूप में स्व-प्रमाणन करता है, वह इंटरस्टेट वाणिज्य में संचालन करता है और उसे एक वैध संघीय DOT मेडिकल परीक्षक प्रमाणपत्र बनाए रखना होता है। स्रोत: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71।"},"38":{"q":"एक टेनेसी CDL आवेदक को वे किस प्रकार की वाणिज्यिक ड्राइविंग करते हैं, इस संबंध में कितनी स्व-प्रमाणन श्रेणियों में से चुनना होता है?","options":["दो","तीन","चार","पाँच"],"explanation":"टेनेसी CDL धारकों को चार श्रेणियों में से एक में स्व-प्रमाणन करना होता है: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। स्रोत: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 383.71।"},"39":{"q":"एक टेनेसी ड्राइवर Non-Excepted Interstate के रूप में स्व-प्रमाणन करता है। CDL को वैध रखने के लिए, ड्राइवर को राज्य के पास क्या फाइल में रखना होता है?","options":["एक प्रमाणित परीक्षक से एक मौजूदा संघीय मेडिकल परीक्षक प्रमाणपत्र","उनके नियोक्ता से एक नोटरीकृत पत्र","उनके हाई स्कूल डिप्लोमा की एक प्रति","एक वार्षिक वाहन निरीक्षण स्टिकर"],"explanation":"नॉन-एक्सेप्टेड ड्राइवरों को FMCSA राष्ट्रीय रजिस्ट्री पर मौजूद एक प्रमाणित मेडिकल परीक्षक से एक मौजूदा संघीय मेडिकल परीक्षक प्रमाणपत्र प्राप्त करना और बनाए रखना होता है तथा इसे राज्य के पास फाइल में रखना होता है। स्रोत: Tennessee Department of Safety and Homeland Security, Medical Certification Requirements; 49 CFR 391.45।"},"40":{"q":"टेनेसी में, अधिकतम कितनी रक्त अल्कोहल सांद्रता (BAC) पर एक व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.02","0.04","0.08","0.10"],"explanation":"टेनेसी संघीय मानक का पालन करता है: 0.04 या उससे अधिक BAC के साथ CMV चलाना एक प्रमुख अपराध है। यह गैर-वाणिज्यिक ड्राइवरों के लिए 0.08 सीमा का आधा है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 1; T.C.A. 55-50-405।"},"41":{"q":"एक ड्राइवर को खतरनाक सामग्री न ले जाते हुए 0.04 या उससे अधिक BAC के साथ CMV चलाने के लिए पहली बार दोषी ठहराया जाता है। CDL कितने समय के लिए अयोग्य घोषित किया जाता है?","options":["60 days","6 months","1 year","3 years"],"explanation":"एक पहला प्रमुख अपराध (जिसमें CMV में 0.04 या उससे अधिक BAC शामिल है) के परिणामस्वरूप टेनेसी में न्यूनतम 1-year CDL अयोग्यता होती है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 1।"},"42":{"q":"एक ड्राइवर ऐसे CMV को चलाते समय पहला प्रमुख अल्कोहल अपराध करता है जिस पर खतरनाक सामग्री के लिए प्लेकार्ड लगा था। अयोग्यता अवधि क्या है?","options":["1 year","2 years","3 years","5 years"],"explanation":"जब एक पहला प्रमुख अपराध तब होता है जब CMV प्लेकार्ड वाली खतरनाक सामग्री ले जा रहा हो, तो टेनेसी अयोग्यता 1 year से बढ़कर 3 years हो जाती है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 1।"},"43":{"q":"टेनेसी के निहित सहमति (implied consent) कानून के तहत, एक CDL धारक के लिए जो पहली बार आवश्यक रासायनिक/रक्त अल्कोहल परीक्षण से इनकार करता है, क्या परिणाम होता है?","options":["केवल एक चेतावनी","60 days के लिए CDL का नुकसान","1 year के लिए CDL का नुकसान","90 days के लिए CDL का नुकसान"],"explanation":"अल्कोहल परीक्षण से इनकार करना टेनेसी में एक प्रमुख अपराध के रूप में माना जाता है, जिसके परिणामस्वरूप न्यूनतम 1-year CDL अयोग्यता होती है, जो BAC सीमा से अधिक पर गाड़ी चलाने के पहले दोषसिद्धि के समान है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); T.C.A. 55-50-405; 49 CFR 383.51।"},"44":{"q":"एक CDL धारक को अपने ड्राइविंग करियर के दौरान एक दूसरे प्रमुख अपराध (उदाहरण के लिए, एक दूसरा BAC-0.04 उल्लंघन) के लिए दोषी ठहराया जाता है। टेनेसी में अयोग्यता अवधि क्या है?","options":["3 years","10 years","आजीवन","5 years"],"explanation":"एक दूसरे प्रमुख अपराध के परिणामस्वरूप आजीवन CDL अयोग्यता होती है। टेनेसी ने वैकल्पिक 10-year पुनर्बहाली प्रावधान को नहीं अपनाया है, इसलिए आजीवन प्रतिबंध स्थायी है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); TN Dept. of Safety CDL serious-offenses मार्गदर्शन; 49 CFR 383.51 Table 1।"},"45":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से संबंधित किसी गंभीर अपराध (felony) को करने के लिए एक वाणिज्यिक मोटर वाहन का उपयोग करने पर टेनेसी में क्या अयोग्यता होती है?","options":["1 year","3 years","आजीवन, बिना किसी पुनर्बहाली के","5 years"],"explanation":"नियंत्रित पदार्थों से संबंधित किसी गंभीर अपराध (felony) में CMV का उपयोग करने पर टेनेसी में बिना पुनर्बहाली की संभावना के आजीवन अयोग्यता होती है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 1।"},"46":{"q":"टेनेसी में पहली अयोग्यता शुरू होने से पहले एक CDL ड्राइवर को 3-year की अवधि के भीतर कितने गंभीर यातायात उल्लंघन करने होते हैं?","options":["1 उल्लंघन","2 उल्लंघन","3 उल्लंघन","4 उल्लंघन"],"explanation":"एक एकल गंभीर यातायात उल्लंघन से अयोग्यता नहीं होती। पहली अयोग्यता (60 days) 3 years के भीतर एक दूसरे गंभीर उल्लंघन से शुरू होती है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 2।"},"47":{"q":"एक CDL ड्राइवर को 3-year की अवधि के भीतर दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["30 days","60 days","120 days","1 year"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप टेनेसी में 60-day CDL अयोग्यता होती है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 2।"},"48":{"q":"एक CDL ड्राइवर 3-year की अवधि के भीतर तीन गंभीर यातायात उल्लंघन जमा करता है। अयोग्यता अवधि क्या है?","options":["60 days","90 days","120 days","180 days"],"explanation":"3 years के भीतर तीन गंभीर यातायात उल्लंघनों के परिणामस्वरूप टेनेसी में 120-day CDL अयोग्यता होती है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 2।"},"49":{"q":"किसी टेनेसी CDL धारक के लिए निर्धारित सीमा से कितनी गति अधिक होने पर अत्यधिक तेज़ गति को एक 'गंभीर यातायात उल्लंघन' माना जाता है?","options":["10 mph या अधिक ऊपर","15 mph या अधिक ऊपर","20 mph या अधिक ऊपर","25 mph या अधिक ऊपर"],"explanation":"निर्धारित गति सीमा से 15 mph या उससे अधिक तेज़ गति को एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया जाता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 2।"},"50":{"q":"किसी टेनेसी CDL ड्राइवर के लिए निम्नलिखित में से किसे एक प्रमुख अपराध के बजाय एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया जाता है?","options":["0.04 या उससे अधिक BAC के साथ CMV चलाना","लापरवाह ड्राइविंग / बहुत पास से चलना","दुर्घटना स्थल से भाग जाना","गंभीर अपराध (felony) करने के लिए CMV का उपयोग करना"],"explanation":"लापरवाह ड्राइविंग, बहुत पास से चलना, और अनुचित/अनियमित लेन परिवर्तन गंभीर यातायात उल्लंघन हैं। सूचीबद्ध अन्य विकल्प प्रमुख अपराध हैं जो 1-year (या आजीवन) अयोग्यता वहन करते हैं। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Tables 1 and 2।"},"51":{"q":"टेनेसी CDL नियमों के तहत CMV चलाते समय टेक्स्टिंग करना निम्नलिखित में से किस रूप में वर्गीकृत किया जाता है?","options":["एक प्रमुख अपराध (1-year अयोग्यता)","एक गंभीर यातायात उल्लंघन","एक आउट-ऑफ-सर्विस ऑर्डर उल्लंघन","एक गैर-अयोग्यकारी उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग करना और हाथ में पकड़े गए मोबाइल टेलीफोन का उपयोग करना दोनों गंभीर यातायात उल्लंघन हैं, जो 60-day/120-day अयोग्यताओं की ओर गिने जा सकते हैं। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 2; FMCSA 392.80/392.82।"},"52":{"q":"एक CDL ड्राइवर को CMV चलाते समय हाथ में पकड़े गए सेल फोन का उपयोग करने के लिए एक दूसरी दोषसिद्धि मिलती है, जो दूसरी पहली के 3 वर्षों के भीतर होती है। कौन सी अयोग्यता लागू होती है?","options":["कोई अयोग्यता नहीं","60 days","120 days","1 year"],"explanation":"हाथ में पकड़े गए फोन का उपयोग एक गंभीर यातायात उल्लंघन है। 3 years के भीतर एक दूसरा गंभीर उल्लंघन एक 60-day अयोग्यता शुरू करता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 2।"},"53":{"q":"किसी टेनेसी CDL ड्राइवर द्वारा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए अयोग्यता अवधि क्या है?","options":["30 days से कम नहीं","60 days से कम नहीं","120 days से कम नहीं","1 year से कम नहीं"],"explanation":"एक पहला रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन 60 days से कम नहीं की अयोग्यता वहन करता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 3।"},"54":{"q":"एक टेनेसी CDL ड्राइवर को 3-year की अवधि के भीतर एक दूसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता क्या है?","options":["60 days","90 days","120 days","180 days"],"explanation":"3 years के भीतर एक दूसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन 120 days से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 3।"},"55":{"q":"एक टेनेसी CDL ड्राइवर को 3-year की अवधि के भीतर एक तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता क्या है?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 years के भीतर एक तीसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन 1 year से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 3।"},"56":{"q":"किसी टेनेसी CDL ड्राइवर के लिए किसी आउट-ऑफ-सर्विस ऑर्डर के पहले उल्लंघन (ऐसे CMV में जो हैज़मैट या यात्री नहीं ले जा रहा) के लिए न्यूनतम अयोग्यता अवधि क्या है?","options":["30 days","90 days","180 days","1 year"],"explanation":"एक पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन 180 days से कम नहीं (1 year तक) की अयोग्यता में परिणत होता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 4।"},"57":{"q":"अयोग्यता के अलावा, किसी टेनेसी ड्राइवर को किसी आउट-ऑफ-सर्विस ऑर्डर के पहले उल्लंघन के लिए न्यूनतम कितना नागरिक दंड (civil penalty) भुगतना पड़ता है?","options":["$1,000","$2,500","$5,000","$10,000"],"explanation":"एक पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन 180-day अयोग्यता के अतिरिक्त न्यूनतम $2,500 का नागरिक दंड वहन करता है; एक दूसरा न्यूनतम $5,000 वहन करता है। स्रोत: टेनेसी CDL मैनुअल / TN Dept. of Safety; 49 CFR 383.53।"},"58":{"q":"एक टेनेसी CDL ड्राइवर 10-year की अवधि के भीतर एक दूसरा आउट-ऑफ-सर्विस ऑर्डर उल्लंघन (गैर-हैज़मैट) करता है। न्यूनतम अयोग्यता क्या है?","options":["180 days","1 year","2 years","5 years"],"explanation":"10 years के भीतर एक दूसरा आउट-ऑफ-सर्विस ऑर्डर उल्लंघन 2 years से कम नहीं की अयोग्यता (और न्यूनतम $5,000 नागरिक दंड) में परिणत होता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 4।"},"59":{"q":"एक ड्राइवर पहली बार किसी आउट-ऑफ-सर्विस ऑर्डर का उल्लंघन तब करता है जब CMV प्लेकार्ड वाली खतरनाक सामग्री ले जा रहा हो। अयोग्यता अवधि क्या है?","options":["60 days से कम नहीं","180 days से कम नहीं, 2 years तक","ठीक 1 year","आजीवन"],"explanation":"प्लेकार्ड वाली हैज़मैट (या 16+ यात्री ले जाते समय) ले जाते समय एक पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन 180 days से कम नहीं और 2 years तक की बढ़ी हुई अयोग्यता वहन करता है। स्रोत: टेनेसी CDL मैनुअल (Disqualifications); 49 CFR 383.51 Table 4।"},"60":{"q":"कम से कम चार लेन वाले टेनेसी राजमार्ग पर, मूव ओवर कानून के अनुसार किसी ऐसे रुके हुए आपातकालीन वाहन के पास से गुजरते समय, जो चमकती हुई बत्तियाँ दिखा रहा हो, सुरक्षित होने पर पास आते हुए चालक को क्या करना आवश्यक है?","options":["ऐसी लेन में बदल जाएँ जो रुके हुए वाहन से सटी हुई न हो","जब तक आपातकालीन वाहन वहाँ से न चला जाए, तब तक पूरी तरह रुके रहें","दाहिने किनारे (शोल्डर) पर चले जाएँ और आगे बढ़ते रहें","हॉर्न बजाएँ और निर्धारित गति बनाए रखें"],"explanation":"टेनेसी का मूव ओवर कानून (T.C.A. 55-8-132) चार या उससे अधिक लेन वाले राजमार्ग पर चालकों से यह अपेक्षा करता है कि सुरक्षित होने पर वे ऐसी लेन में जाकर रास्ता दें जो रुके हुए वाहन से सटी हुई न हो; केवल तभी, जब लेन बदलना असंभव या असुरक्षित हो, चालक इसके बजाय एक सुरक्षित गति तक धीमा हो सकता है। स्रोत: T.C.A. 55-8-132।"},"61":{"q":"टेनेसी के मूव ओवर कानून के अंतर्गत, यदि कोई CMV चालक चमकती बत्तियों वाले किसी रुके हुए यूटिलिटी या रखरखाव वाहन के पास से गुजरते समय सुरक्षित रूप से लेन नहीं बदल सकता, तो उसे इसके बजाय क्या करना चाहिए?","options":["सड़क पर पूरी तरह रुक जाएँ","गति को सड़क की स्थितियों के अनुसार सुरक्षित गति तक घटाएँ","गति को सीमा से ठीक 25 mph नीचे घटाएँ","विपरीत किनारे (शोल्डर) पर चले जाएँ"],"explanation":"T.C.A. 55-8-132 पुलिस, अग्निशमन, एम्बुलेंस, यूटिलिटी, टो और राजमार्ग रखरखाव वाहनों को कवर करता है। यदि लेन बदलना असंभव या असुरक्षित हो, तो चालक को गति को सड़क की स्थितियों के अनुसार सुरक्षित गति तक घटाना चाहिए; यह क़ानून कोई संख्यात्मक कमी निर्धारित नहीं करता। स्रोत: T.C.A. 55-8-132।"},"62":{"q":"टेनेसी के मूव ओवर कानून का उल्लंघन (किसी रुके हुए आपातकालीन वाहन के लिए लेन न बदलना या गति कम न करना) किस श्रेणी में वर्गीकृत किया जाता है?","options":["एक नॉन-मूविंग सिविल उल्लंघन","एक क्लास C फेलनी (गुरुतर अपराध)","एक क्लास B मिसडिमीनर (हल्का अपराध)","केवल एक साधारण चेतावनी"],"explanation":"टेनेसी के मूव ओवर कानून का उल्लंघन एक क्लास B मिसडिमीनर है, जिसके लिए $500 तक का जुर्माना (और गंभीर मामलों में संभावित जेल) हो सकता है। स्रोत: T.C.A. 55-8-132।"},"63":{"q":"टेनेसी के इंटरस्टेट राजमार्गों पर अनुमत अधिकतम निर्धारित गति सीमा क्या है?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"टेनेसी इंटरस्टेट राजमार्गों पर 70 mph की वैधानिक अधिकतम सीमा निर्धारित करता है। स्रोत: T.C.A. 55-8-152।"},"64":{"q":"टेनेसी कानून के अंतर्गत, उन राजमार्गों पर जो इंटरस्टेट या चार-लेन नियंत्रित-पहुँच मार्ग नहीं हैं, किसी ट्रक (1.5-टन रेटेड क्षमता या उससे अधिक) के लिए सामान्य अधिकतम गति क्या है?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"T.C.A. 55-8-152 ट्रकों (1.5-टन रेटेड क्षमता या उससे अधिक) को इंटरस्टेट और चार-लेन नियंत्रित-पहुँच राजमार्गों के अलावा अन्य राजमार्गों पर 55 mph तक सीमित करता है, जबकि उन राजमार्गों पर सीमा 65 mph है। स्रोत: T.C.A. 55-8-152।"},"65":{"q":"टेनेसी में, चार या उससे अधिक लेन वाले नियंत्रित-पहुँच राजमार्ग की बायीं ओर की (पासिंग) लेन में चल रहे किसी वाहन के लिए न्यूनतम वैध गति क्या है?","options":["40 mph","45 mph","55 mph","65 mph"],"explanation":"टेनेसी में चार या उससे अधिक लेन वाले नियंत्रित-पहुँच राजमार्ग की बायीं ओर की लेन में 55 mph से कम गति पर चलना गैरकानूनी है। स्रोत: T.C.A. 55-8-152।"},"66":{"q":"जब किसी टेनेसी CMV चालक को रेलमार्ग क्रॉसिंग पर रुकना आवश्यक होता है, तो वाहन को निकटतम रेल के सापेक्ष कहाँ रोकना चाहिए?","options":["50 फ़ीट के भीतर पर 15 फ़ीट से कम नहीं","25 फ़ीट के भीतर पर 5 फ़ीट से कम नहीं","100 फ़ीट के भीतर पर 50 फ़ीट से कम नहीं","रेल से ठीक 10 फ़ीट पर"],"explanation":"जिस चालक को रुकना आवश्यक है, उसे निकटतम रेल से 50 फ़ीट के भीतर पर 15 फ़ीट से कम नहीं की दूरी पर रुकना चाहिए, फिर आगे बढ़ने से पहले देखना और सुनना चाहिए। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 392.10।"},"67":{"q":"निम्नलिखित में से किसे टेनेसी में रेलमार्ग क्रॉसिंग पर हमेशा रुकना चाहिए, भले ही कोई ट्रेन दिखाई न दे?","options":["कोई भी खाली फ़्लैटबेड ट्रेलर","यात्रियों को ले जा रही एक बस और प्लेकार्ड लगा हुआ खतरनाक-सामग्री वाहन","कोई भी तीन-एक्सल वाला स्ट्रेट ट्रक","26,001 पाउंड से अधिक का कोई भी वाहन"],"explanation":"जिन CMVs को रेलमार्ग क्रॉसिंग पर रुकना आवश्यक है, वे हैं यात्रियों को ले जा रही बसें और खतरनाक-सामग्री के प्लेकार्ड प्रदर्शित करने वाले वाहन; अधिकांश अन्य CMVs को तब तक रुकना आवश्यक नहीं है जब तक संकेत उन्हें ऐसा करने के लिए न कहें। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 392.10।"},"68":{"q":"क्रॉसिंग के दौरान जब टेनेसी CMV का कोई भी हिस्सा रेलमार्ग की पटरियों पर हो, तो चालक को निम्नलिखित में से क्या नहीं करना चाहिए?","options":["दोनों हाथ स्टीयरिंग पर रखें","पटरी के दोनों ओर देखें","गियर बदलें","एक स्थिर गति बनाए रखें"],"explanation":"जब वाहन का कोई भी हिस्सा पटरियों को पार कर रहा हो, तब चालकों को न तो रुकना चाहिए, न गियर बदलना चाहिए, और न ही लेन बदलनी चाहिए, क्योंकि गियर बदलने में चूक हो जाने पर वाहन पटरियों पर रुका रह सकता है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 392.10।"},"69":{"q":"दोनों दिशाओं में यातायात वाली टेनेसी की दो-लेन सड़क पर, जब कोई स्कूल बस रुककर बच्चों को चढ़ाने या उतारने के लिए अपनी लाल चमकती बत्तियाँ चालू करती है, तो चालक को क्या करना चाहिए?","options":["केवल बस के पीछे वाले वाहनों को रुकना चाहिए","दोनों दिशाओं के वाहनों को रुकना चाहिए","15 mph तक धीमा करें और सावधानी से आगे निकलें","यदि कोई बच्चा दिखाई न दे तो बस को बायीं ओर से पार करें"],"explanation":"बिना विभाजन वाली सड़क पर, चमकती लाल बत्तियाँ और स्टॉप आर्म दिखा रही स्कूल बस के लिए दोनों दिशाओं के चालकों को तब तक रुकना चाहिए जब तक स्टॉप आर्म वापस न ले लिया जाए। स्रोत: T.C.A. 55-8-151।"},"70":{"q":"टेनेसी में, विपरीत दिशा से आ रहा कोई चालक किसी रुकी हुई स्कूल बस के सामने आने पर रुकने से केवल तभी छूट प्राप्त है जब सड़कें किसके द्वारा अलग की गई हों?","options":["एक चित्रित (पेंट की हुई) केंद्र रेखा","एक दो-तरफ़ा बायें-मोड़ (suicide) लेन","वाहन यातायात के लिए अनुपयुक्त कोई बीच की जगह या भौतिक अवरोध (अलग-अलग सड़कें)","कम से कम तीन यात्रा लेन"],"explanation":"टेनेसी का अपवाद केवल अलग-अलग सड़कों वाले राजमार्ग पर लागू होता है, अर्थात जहाँ दिशाएँ वाहन यातायात के लिए अनुपयुक्त किसी बीच की जगह या अवरोध द्वारा विभाजित हों। केवल एक पेंट की हुई रेखा या केंद्र मोड़ लेन इसके लिए योग्य नहीं है, इसलिए चालकों को फिर भी रुकना चाहिए। स्रोत: T.C.A. 55-8-151।"},"71":{"q":"टेनेसी में किसी रुकी हुई स्कूल बस को अवैध रूप से पार करने का पहला अपराध किस श्रेणी में वर्गीकृत किया जाता है?","options":["एक नॉन-मूविंग उल्लंघन","एक क्लास A मिसडिमीनर (हल्का अपराध)","एक क्लास C मिसडिमीनर (हल्का अपराध)","केवल एक सिविल दंड"],"explanation":"टेनेसी में किसी रुकी हुई स्कूल बस को अवैध रूप से पार करना एक क्लास A मिसडिमीनर है, जिसके लिए पहले अपराध पर $250 से कम और $1,000 से अधिक नहीं का जुर्माना होता है। स्रोत: T.C.A. 55-8-151।"},"72":{"q":"टेनेसी में, जब कोई चालक किसी रुकी हुई स्कूल बस को अवैध रूप से पार करता है और किसी व्यक्ति को टक्कर मारकर उसकी मृत्यु का कारण बनता है, तो यह अपराध किस स्तर तक बढ़ जाता है?","options":["एक क्लास A मिसडिमीनर (हल्का अपराध)","एक क्लास E फेलनी (गुरुतर अपराध)","एक क्लास C फेलनी (गुरुतर अपराध)","एक क्लास B मिसडिमीनर (हल्का अपराध)"],"explanation":"किसी रुकी हुई स्कूल बस को अवैध रूप से पार करते समय किसी व्यक्ति को टक्कर मारना एक क्लास E फेलनी है; यदि टक्कर के परिणामस्वरूप मृत्यु हो जाती है, तो यह एक क्लास C फेलनी है। स्रोत: T.C.A. 55-8-151।"},"73":{"q":"टेनेसी प्रत्येक दिशा में कितनी लेन वाले इंटरस्टेट और बहुलेन विभाजित राजमार्गों पर ट्रक ट्रैक्टरों और सेमीट्रेलरों को विशिष्ट लेन तक सीमित करने के लिए TDOT को अधिकृत करता है?","options":["एक या उससे अधिक","दो या उससे अधिक","तीन या उससे अधिक","पाँच या उससे अधिक"],"explanation":"T.C.A. 55-8-195 TDOT को यह अधिकार देता है कि वह प्रत्येक दिशा में तीन या उससे अधिक लेन वाले इंटरस्टेट और बहुलेन विभाजित राजमार्गों पर ट्रक ट्रैक्टरों और सेमीट्रेलरों को विशिष्ट लेन में चलने का निर्देश दे; उल्लंघन एक क्लास C मिसडिमीनर है ($50 तक का जुर्माना)। स्रोत: T.C.A. 55-8-195।"},"74":{"q":"टेनेसी के बायीं-लेन (Slow Poke) कानून के अंतर्गत, कोई चालक इंटरस्टेट या बहुलेन विभाजित राजमार्ग की सबसे बायीं पासिंग लेन में कब वैध रूप से चल सकता है?","options":["जब भी यातायात हल्का हो","केवल तभी जब किसी गैर-पासिंग लेन में चल रहे वाहन को आगे निकल रहा हो या पार कर रहा हो","किसी भी समय, बशर्ते गति सीमा का पालन हो","केवल सूर्यास्त और सूर्योदय के बीच"],"explanation":"टेनेसी का बायीं-लेन कानून (T.C.A. 55-8-204) पासिंग लेन के उपयोग को किसी गैर-पासिंग लेन में चल रहे वाहन को आगे निकलने या पार करने तक सीमित करता है; अन्यथा वहाँ टिके रहना निषिद्ध है। स्रोत: T.C.A. 55-8-204।"},"75":{"q":"जब कोई CMV टेनेसी के किसी शोल्डर पर रुका हो, तो एक सामान्य दो-लेन, दो-तरफ़ा सड़क के लिए सबसे पीछे वाला चेतावनी त्रिकोण कहाँ रखा जाना चाहिए?","options":["वाहन से 10 फ़ीट पीछे","वाहन से 40 फ़ीट पीछे","वाहन से 100 फ़ीट पीछे","वाहन से 200 फ़ीट पीछे"],"explanation":"चेतावनी उपकरण 10 मिनट के भीतर लगाए जाने चाहिए: एक यातायात की ओर लगभग 10 फ़ीट पीछे, एक लगभग 100 फ़ीट पीछे, और एक लगभग 100 फ़ीट आगे (पास आते हुए यातायात की दिशा में)। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 392.22।"},"76":{"q":"रुकने के कितनी देर बाद किसी टेनेसी CMV चालक को आवश्यक आपातकालीन चेतावनी उपकरण (त्रिकोण) लगाने चाहिए?","options":["10 मिनट के भीतर","30 मिनट के भीतर","तुरंत, कैब से बाहर निकलने से पहले","1 घंटे के भीतर"],"explanation":"रुके हुए CMV के चालक को रुकने के 10 मिनट के भीतर तीनों चेतावनी त्रिकोण लगाने चाहिए। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 392.22।"},"77":{"q":"किसी विशेष परमिट के बिना, टेनेसी में किसी वाणिज्यिक वाहन और भार की अधिकतम वैध चौड़ाई क्या है?","options":["8 फ़ीट 0 इंच","8 फ़ीट 6 इंच","9 फ़ीट 6 इंच","10 फ़ीट 0 इंच"],"explanation":"ओवरसाइज़ परमिट के बिना टेनेसी की वैध अधिकतम चौड़ाई 8 फ़ीट 6 इंच है; वैध ऊँचाई 13 फ़ीट 6 इंच है। इनसे अधिक होने पर TDOT का एक विशेष परमिट आवश्यक है। स्रोत: TDOT ओवरसाइज़/ओवरवेट परमिट नियम; T.C.A. शीर्षक 55, अध्याय 7।"},"78":{"q":"टेनेसी के ओवरसाइज़-लोड परमिट आमतौर पर आवाजाही को किस समय-अवधि तक सीमित करते हैं?","options":["केवल दिन के उजाले के घंटे (सूर्योदय से लगभग आधे घंटे पहले से सूर्यास्त के लगभग आधे घंटे बाद तक)","केवल रात के समय, यातायात से बचने के लिए","रविवार सहित कोई भी 24-घंटे की अवधि","केवल सुबह 9:00 बजे से शाम 4:00 बजे के बीच"],"explanation":"टेनेसी के ओवरसाइज़ परमिट आमतौर पर सोमवार से शनिवार तक दिन के उजाले के दौरान (सूर्योदय से लगभग आधे घंटे पहले से सूर्यास्त के लगभग आधे घंटे बाद तक) यात्रा की अनुमति देते हैं, रविवार या प्रमुख छुट्टियों पर कोई आवाजाही नहीं, और बड़े काउंटियों में व्यस्त-समय (rush-hour) के लिए कर्फ्यू होते हैं। स्रोत: TDOT ओवरसाइज़/ओवरवेट परमिट नियम।"},"79":{"q":"टेनेसी में I-24 पर मॉन्टीगल पर्वत की पूर्व दिशा की खड़ी उतराई पर, ब्रेक खो देने वाले ट्रकों के लिए कौन-सी सुरक्षा सुविधा प्रदान की जाती है?","options":["एक अनिवार्य टोल प्लाज़ा","बजरी से भरे रनअवे ट्रक रैंप","एक आवश्यक फ़ेरी क्रॉसिंग","एक रिवर्सिबल एक्सप्रेस लेन"],"explanation":"मॉन्टीगल पर्वत की I-24 उतराई (लगभग 6% ढलान) बजरी से भरे रनअवे ट्रक एस्केप रैंप से सुसज्जित है, और वाणिज्यिक ट्रकों को उतरने से पहले निरीक्षण/ब्रेक-जाँच स्टेशन का उपयोग करने का निर्देश दिया जाता है। स्रोत: TDOT; टेनेसी CDL मैनुअल की पर्वतीय-ड्राइविंग मार्गदर्शिका।"},"80":{"q":"टेनेसी में वाणिज्यिक चालक लाइसेंस (CDLs) जारी करने के लिए कौन-सी राज्य एजेंसी ज़िम्मेदार है?","options":["टेनेसी सुरक्षा एवं गृह सुरक्षा विभाग (Tennessee Department of Safety and Homeland Security)","टेनेसी परिवहन विभाग (TDOT)","टेनेसी मोटर वाहन विभाग","टेनेसी लोक सेवा आयोग"],"explanation":"टेनेसी में CDLs, टेनेसी सुरक्षा एवं गृह सुरक्षा विभाग (TDOSHS) द्वारा उसके ड्राइवर सर्विसेज केंद्रों के माध्यम से जारी किए जाते हैं। टेनेसी में कोई अलग 'मोटर वाहन विभाग' नहीं है; TDOT राजमार्गों का काम संभालता है, लाइसेंसिंग का नहीं। स्रोत: टेनेसी CDL मैनुअल; tn.gov/safety ड्राइवर सर्विसेज।"},"81":{"q":"टेनेसी का कोई आवेदक CDL सामान्य ज्ञान परीक्षा और कोई भी एंडोर्समेंट ज्ञान परीक्षा कहाँ देता है?","options":["सुरक्षा विभाग द्वारा संचालित किसी पूर्ण-सेवा ड्राइवर सर्विसेज सेंटर में","किसी भी FMCSA-पंजीकृत ट्रक ड्राइविंग स्कूल में","किसी टेनेसी परिवहन विभाग के ज़िला कार्यालय में","घर से e-Services पोर्टल के माध्यम से ऑनलाइन"],"explanation":"टेनेसी के पूर्ण-सेवा ड्राइवर सर्विसेज केंद्र CDL सामान्य ज्ञान परीक्षा और किसी भी एंडोर्समेंट के लिए ज्ञान परीक्षाएँ आयोजित करते हैं। स्कूल प्रशिक्षण (ELDT) प्रदान करते हैं, राज्य की ज्ञान परीक्षा नहीं। स्रोत: टेनेसी CDL मैनुअल; tn.gov/safety ड्राइवर सर्विसेज 'CDL कैसे प्राप्त करें'।"},"82":{"q":"वाणिज्यिक लर्नर परमिट (CLP) जारी होने से पहले, टेनेसी आवेदक को सबसे पहले क्या करना आवश्यक है?","options":["CDL सामान्य ज्ञान परीक्षा पास करें","तीन-भाग वाली कौशल परीक्षा पास करें","बिहाइंड-द-व्हील ELDT रेंज प्रशिक्षण पूरा करें","CLP को कम से कम 14 दिन तक धारण करें"],"explanation":"CLP प्राप्त करने के लिए टेनेसी आवेदक को CDL सामान्य ज्ञान परीक्षा (और आवश्यक एंडोर्समेंट परीक्षाएँ) देकर पास करनी होती है। कौशल परीक्षा और 14-दिन की प्रतीक्षा अवधि CLP जारी होने के बाद आती है। स्रोत: टेनेसी CDL मैनुअल; tn.gov/safety ड्राइवर सर्विसेज।"},"83":{"q":"टेनेसी CDL आवेदक को ड्राइवर सर्विसेज सेंटर पर दस्तावेज़ों का कौन-सा समूह प्रस्तुत करना आवश्यक है?","options":["पहचान का प्रमाण, सोशल सिक्योरिटी नंबर, U.S. नागरिकता/वैध उपस्थिति, और टेनेसी निवास","केवल एक वैध पासपोर्ट और एक प्रमुख क्रेडिट कार्ड","एक हाई स्कूल डिप्लोमा और दो नियोक्ता संदर्भ पत्र","केवल एक वाहन का टाइटल और वर्तमान वाहन पंजीकरण"],"explanation":"टेनेसी में पहचान का प्रमाण, सोशल सिक्योरिटी नंबर का प्रमाण, U.S. नागरिकता या वैध स्थायी निवासी स्थिति का प्रमाण, और टेनेसी अधिवास/निवास सिद्ध करने वाले दो दस्तावेज़ आवश्यक हैं। स्रोत: टेनेसी CDL मैनुअल; tn.gov/safety ड्राइवर सर्विसेज दस्तावेज़ आवश्यकताएँ।"},"84":{"q":"स्व-प्रमाणन शपथपत्र (self-certification affidavit) भरते समय टेनेसी CDL आवेदक को कितनी अलग-अलग वाणिज्य श्रेणियों में से चुनना आवश्यक है?","options":["चार","दो","तीन","पाँच"],"explanation":"टेनेसी स्व-प्रमाणन शपथपत्र (SF-1480) में चार विकल्प सूचीबद्ध हैं: नॉन-एक्सेप्टेड इंटरस्टेट, एक्सेप्टेड इंटरस्टेट, नॉन-एक्सेप्टेड इंट्रास्टेट, और एक्सेप्टेड इंट्रास्टेट। चालक ठीक एक पर आद्याक्षर (initials) करता है। स्रोत: टेनेसी SF-1480 स्व-प्रमाणन शपथपत्र; tn.gov/safety।"},"85":{"q":"कौन-सी स्व-प्रमाणन श्रेणी के लिए टेनेसी CDL धारक को एक वर्तमान संघीय DOT मेडिकल परीक्षक का प्रमाणपत्र प्रस्तुत करना आवश्यक है?","options":["नॉन-एक्सेप्टेड इंटरस्टेट","एक्सेप्टेड इंटरस्टेट","एक्सेप्टेड इंट्रास्टेट","केवल फ़ार्म आपूर्ति परिवहन करने वाला एक्सेप्टेड इंटरस्टेट"],"explanation":"जो चालक स्वयं को नॉन-एक्सेप्टेड इंटरस्टेट के रूप में प्रमाणित करता है, वह 49 CFR 391.45 के अधीन होता है और उसे एक वर्तमान मेडिकल परीक्षक का प्रमाणपत्र प्रस्तुत करना आवश्यक है। एक्सेप्टेड श्रेणियों को संघीय मेडिकल कार्ड जमा करना आवश्यक नहीं है। स्रोत: टेनेसी SF-1480; tn.gov/safety मेडिकल प्रमाणन आवश्यकताएँ।"},"86":{"q":"टेनेसी में, उस संघीय DOT मेडिकल परीक्षक के प्रमाणपत्र का सामान्य नाम क्या है जिसे नॉन-एक्सेप्टेड इंटरस्टेट CDL धारकों को वर्तमान रखना आवश्यक है?","options":["मेडिकल कार्ड (DOT कार्ड)","खतरनाक सामग्री एंडोर्समेंट कार्ड","सेलेक्टिव सर्विस प्रमाणपत्र","TWIC कार्ड"],"explanation":"49 CFR 391.45 के अंतर्गत मेडिकल परीक्षक का प्रमाणपत्र (Form MCSA-5876) आमतौर पर 'मेडिकल कार्ड' या 'DOT कार्ड' कहलाता है। TWIC और HazMat एंडोर्समेंट अलग चीज़ें हैं। स्रोत: टेनेसी मेडिकल प्रमाणन आवश्यकताएँ; tn.gov/safety।"},"87":{"q":"टेनेसी CDL धारक राज्य को एक नया स्व-प्रमाणन शपथपत्र और अद्यतन मेडिकल प्रमाणन कैसे जमा कर सकता है?","options":["सुरक्षा विभाग के e-Services पोर्टल के माध्यम से अपलोड करके या किसी ड्राइवर सर्विसेज सेंटर पर जाकर","इसे सीधे FMCSA राष्ट्रीय रजिस्ट्री को डाक से भेजकर","इसे टेनेसी परिवहन विभाग को ईमेल करके","इसे मेडिकल परीक्षक को देकर, जो इसे काउंटी क्लर्क के पास दाखिल करता है"],"explanation":"टेनेसी CDL धारक स्व-प्रमाणन शपथपत्र (और आवश्यक होने पर मेडिकल प्रमाणन) को सुरक्षा विभाग के e-Services पोर्टल के माध्यम से अपलोड करके या किसी ड्राइवर सर्विसेज सेंटर पर व्यक्तिगत रूप से जमा करते हैं। स्रोत: tn.gov/safety मेडिकल प्रमाणन आवश्यकताएँ।"},"88":{"q":"मेडिकल कार्ड की समाप्ति के सापेक्ष किस समय पर टेनेसी CDL धारक को अपनी स्थिति वर्तमान बनाए रखने के लिए अद्यतन मेडिकल प्रमाणन जमा करना आवश्यक है?","options":["वर्तमान मेडिकल प्रमाणपत्र की समाप्ति से कम से कम पाँच कार्यदिवस पहले","प्रमाणपत्र पहले ही समाप्त हो जाने के 30 दिनों के भीतर","केवल हर आठ साल में एक बार लाइसेंस नवीनीकरण पर","प्रमाणपत्र समाप्त होने के एक वर्ष के भीतर"],"explanation":"टेनेसी CDL धारकों को निर्देश देता है कि वे डाउनग्रेड से बचने के लिए वर्तमान मेडिकल प्रमाणपत्र की समाप्ति से कम से कम पाँच (5) कार्यदिवस पहले अद्यतन स्व-प्रमाणन/मेडिकल दस्तावेज़ जमा करें। स्रोत: tn.gov/safety मेडिकल प्रमाणन आवश्यकताएँ।"},"89":{"q":"सभी नए टेनेसी CDL आवेदकों को एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) कब पूरी करनी आवश्यक है?","options":["CDL कौशल परीक्षा देने से पहले","केवल CDL पहले ही जारी हो जाने के बाद","कौशल परीक्षा पास करने के एक वर्ष के भीतर","केवल यदि HazMat एंडोर्समेंट के लिए आवेदन कर रहे हों"],"explanation":"7 फ़रवरी 2022 से, किसी पहली बार के क्लास A/B आवेदक (और कुछ एंडोर्समेंट आवेदकों) द्वारा कौशल/ज्ञान परीक्षा देने से पहले FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री में सूचीबद्ध किसी प्रदाता से ELDT पूरी करनी आवश्यक है। स्रोत: tn.gov/safety ELDT पेज; 49 CFR Part 380।"},"90":{"q":"प्रशिक्षण को मान्य गिने जाने के लिए टेनेसी CDL आवेदक के ELDT प्रदाता का कहाँ सूचीबद्ध होना आवश्यक है?","options":["FMCSA ट्रेनिंग प्रोवाइडर रजिस्ट्री (TPR) में","टेनेसी परिवहन विभाग की ठेकेदार सूची में","टेनेसी सचिव-ऑफ़-स्टेट व्यापार रजिस्ट्री में","राष्ट्रीय राजमार्ग यातायात सुरक्षा प्रशासन की विक्रेता सूची में"],"explanation":"ELDT, Federal Motor Carrier Safety Administration की ट्रेनिंग प्रोवाइडर रजिस्ट्री (TPR) में सूचीबद्ध किसी संस्था द्वारा प्रदान की जानी चाहिए। किसी असूचीबद्ध प्रदाता से प्रशिक्षण इस आवश्यकता को पूरा नहीं करता। स्रोत: tn.gov/safety ELDT; FMCSA TPR।"},"91":{"q":"टेनेसी CLP जारी होने के बाद, धारक को CDL कौशल परीक्षा देने की अनुमति मिलने से पहले कितनी देर प्रतीक्षा करनी आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"संघीय और टेनेसी नियमों के अनुसार धारक द्वारा CDL कौशल परीक्षा देने से पहले CLP को कम से कम 14 दिन तक धारण करना आवश्यक है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.25।"},"92":{"q":"टेनेसी CDL कौशल परीक्षा किन तीन भागों से, किस क्रम में, मिलकर बनी होती है?","options":["प्री-ट्रिप वाहन निरीक्षण, बेसिक वाहन नियंत्रण कौशल, और ऑन-रोड ड्राइविंग","दृष्टि जाँच, ज्ञान परीक्षा, और पैरेलल पार्किंग","एयर-ब्रेक परीक्षा, HazMat परीक्षा, और रात्रि ड्राइविंग","लिखित परीक्षा, ड्रग स्क्रीन, और ऑन-रोड ड्राइविंग"],"explanation":"टेनेसी CDL कौशल परीक्षा के तीन भाग हैं: प्री-ट्रिप वाहन निरीक्षण, बेसिक वाहन नियंत्रण कौशल परीक्षा, और ऑन-रोड ड्राइविंग परीक्षा, सभी इसी क्रम में। स्रोत: टेनेसी CDL मैनुअल।"},"93":{"q":"टेनेसी आवेदक CDL कौशल परीक्षा किसका प्रतिनिधित्व करने वाले वाहन में देता है?","options":["उस श्रेणी और प्रकार के वाहन का जिसे चलाने के लिए आवेदक लाइसेंस प्राप्त करना चाहता है","राज्य द्वारा उपलब्ध कराई गई कोई भी यात्री कार","मांगे गए लाइसेंस से एक श्रेणी छोटा वाहन","मांगे गए लाइसेंस की परवाह किए बिना केवल एक क्लास C स्ट्रेट ट्रक"],"explanation":"कौशल परीक्षा उस श्रेणी और विन्यास के प्रतिनिधि वाहन में देनी होती है जिसके लिए CDL मांगा गया है; उपयोग किया गया वाहन जारी की गई लाइसेंस श्रेणी को सीमित कर सकता है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.71/383.133।"},"94":{"q":"जिस संघीय मानक का टेनेसी पालन करता है, उसके अनुसार वाणिज्यिक लर्नर परमिट (CLP) नवीनीकृत किए जाने या ज्ञान परीक्षाएँ दोबारा दिए जाने से पहले कितने समय तक वैध रहता है?","options":["180 दिन, अतिरिक्त 180 दिनों के लिए एक बार नवीनीकरण योग्य","30 दिन, बिना किसी नवीनीकरण के","पाँच वर्ष, एक नियमित लाइसेंस के समान","90 दिन, तीन बार तक नवीनीकरण योग्य"],"explanation":"49 CFR 383.25 के अनुसार, जिसे टेनेसी लागू करता है, एक CLP 180 दिनों के लिए वैध होता है और सामान्य ज्ञान परीक्षा दोबारा दिए बिना अतिरिक्त 180 दिनों के लिए एक बार नवीनीकृत किया जा सकता है। स्रोत: टेनेसी CDL मैनुअल; 49 CFR 383.25।"},"95":{"q":"यदि किसी टेनेसी आवेदक का CLP, CDL प्राप्त होने से पहले समाप्त हो जाता है, तो पूरी की गई परीक्षाओं का क्या होता है?","options":["ज्ञान और कौशल परीक्षाएँ अमान्य हो जाती हैं और दोबारा देनी पड़ती हैं","केवल कौशल परीक्षा रद्द होती है; ज्ञान परिणाम पाँच वर्ष तक वैध रहते हैं","कुछ नहीं; एक बार पास होने पर परिणाम स्थायी होते हैं","परीक्षाएँ स्वतः एक अतिरिक्त वर्ष के लिए वैध रहती हैं"],"explanation":"यदि पूर्ण CDL जारी होने से पहले CLP समाप्त हो जाता है, तो आवेदक का श्रेय (क्रेडिट) समाप्त हो जाता है और उसे ज्ञान और कौशल परीक्षाएँ दोबारा देनी पड़ती हैं। स्रोत: टेनेसी CDL मैनुअल; टेनेसी ड्राइवर सर्विसेज।"},"96":{"q":"किसी वयस्क को जारी किए गए टेनेसी वाणिज्यिक चालक लाइसेंस के लिए मानक समाप्ति चक्र क्या है?","options":["आठ वर्ष","चार वर्ष","दस वर्ष","दो वर्ष"],"explanation":"टेनेसी चालक लाइसेंस, जिनमें CDLs शामिल हैं, आमतौर पर आठ वर्षों के लिए वैध होते हैं (Tenn. Code Ann. 55-50-337 के अनुसार), जिसके बाद उन्हें नवीनीकृत करना आवश्यक है। स्रोत: Tenn. Code Ann. 55-50-337; tn.gov/safety अपना लाइसेंस नवीनीकृत करना।"},"97":{"q":"टेनेसी CDL नवीनीकरण आमतौर पर कैसे संभाले जाते हैं?","options":["किसी ड्राइवर सर्विसेज सेंटर पर व्यक्तिगत रूप से, वर्तमान मेडिकल प्रमाणन प्रस्तुत करते हुए","पूरी तरह ऑनलाइन, बिना किसी दस्तावेज़ की आवश्यकता के","स्वतः डाक द्वारा, चालक की ओर से बिना किसी कार्रवाई के","परिवहन विभाग के माध्यम से फ़ोन द्वारा"],"explanation":"टेनेसी में CDL नवीनीकरण किसी ड्राइवर सर्विसेज सेंटर पर व्यक्तिगत रूप से किए जाते हैं, और नवीनीकरण के समय धारक के पास वर्तमान मेडिकल प्रमाणन फ़ाइल में होना आवश्यक है। स्रोत: tn.gov/safety अपना लाइसेंस नवीनीकृत करना; मेडिकल प्रमाणन आवश्यकताएँ।"},"98":{"q":"एक 19 वर्षीय व्यक्ति, जो टेनेसी CDL के लिए योग्य है, किस परिचालन प्रतिबंध के अधीन है?","options":["केवल इंट्रास्टेट (टेनेसी के भीतर) परिचालन तक सीमित","केवल 26,001 पाउंड से कम वाहनों तक सीमित","कोई प्रतिबंध नहीं; पूर्ण इंटरस्टेट विशेषाधिकार प्रदान किए जाते हैं","केवल दिन के समय ड्राइविंग तक सीमित"],"explanation":"टेनेसी CDL आवेदकों की आयु कम से कम 18 वर्ष होनी चाहिए; 21 वर्ष से कम आयु वालों को केवल इंट्रास्टेट परिचालन तक सीमित किया जाता है। इंटरस्टेट परिचालन (और HazMat) के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: टेनेसी CDL मैनुअल; tn.gov/safety ड्राइवर सर्विसेज।"},"99":{"q":"टेनेसी CDL आवेदन और परीक्षा शुल्क के संबंध में, किसी अध्ययन मार्गदर्शिका के लिए कौन-सा कथन सबसे सटीक है?","options":["शुल्क सुरक्षा विभाग द्वारा निर्धारित किए जाते हैं और बदलने के अधीन हैं, इसलिए आवेदकों को आवेदन करने से पहले वर्तमान राशि की पुष्टि कर लेनी चाहिए","टेनेसी CDL के लिए किसी भी प्रकार का कोई शुल्क नहीं लेता","शुल्क संघीय कानून द्वारा स्थायी रूप से तय है और कभी नहीं बदलता","शुल्क केवल आवेदक के नियोक्ता द्वारा एकत्र किए जाते हैं, राज्य द्वारा कभी नहीं"],"explanation":"टेनेसी में CDL-संबंधी शुल्क सुरक्षा विभाग द्वारा स्थापित किए जाते हैं और समय के साथ बदल सकते हैं; आवेदकों को किसी निश्चित राशि पर निर्भर रहने के बजाय किसी ड्राइवर सर्विसेज सेंटर पर वर्तमान शुल्क-तालिका की पुष्टि कर लेनी चाहिए। स्रोत: tn.gov/safety ड्राइवर सर्विसेज शुल्क-तालिका।"}},"ar":{"0":{"q":"على شبكة الطرق السريعة الفيدرالية وطرق الولاية في تينيسي، ما هو الحد الأقصى القانوني لعرض المركبة بما في ذلك حمولتها، دون تصريح؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"يسمح قانون تينيسي بأن يصل عرض المركبة أو الحمولة إلى 8 أقدام و6 بوصات (102 بوصة) على شبكة الطرق السريعة الفيدرالية وطرق الولاية؛ أما الطرق 'العادية' فتقتصر على 8 أقدام. المصدر: T.C.A. Section 55-7-202 (الحد الأقصى للعرض والارتفاع)."},"1":{"q":"ما هو الحد الأقصى القانوني للارتفاع، بما في ذلك أي جزء من الحمولة، للمركبة على طرق تينيسي السريعة دون تصريح؟","options":["13 قدمًا و0 بوصة","13 قدمًا و6 بوصات","14 قدمًا و0 بوصة","12 قدمًا و6 بوصات"],"explanation":"تحدد تينيسي الحد الأقصى لارتفاع المركبة (بما في ذلك الحمولة) بـ 13 قدمًا و6 بوصات. وتتطلب الحمولة الأعلى من ذلك تصريحًا لتجاوز الارتفاع. المصدر: T.C.A. Section 55-7-202 (الحد الأقصى للعرض والارتفاع)."},"2":{"q":"ما هو الحد الأقصى القانوني للوزن الإجمالي للمركبة المسموح به على طرق تينيسي السريعة دون تصريح خاص؟","options":["73,280 رطلًا","80,000 رطل","88,000 رطل","100,000 رطل"],"explanation":"الحد الأقصى القانوني للوزن الإجمالي في تينيسي هو 80,000 رطل، بما يتوافق مع الحد الفيدرالي لشبكة الطرق السريعة بين الولايات. وتتطلب الحمولات التي تتجاوز ذلك تصريح وزن زائد. المصدر: T.C.A. Section 55-7-203 (الحد الأقصى للوزن لكل محور أو مجموعة محاور)."},"3":{"q":"ما هو الحد الأقصى للوزن الذي يمكن لمحور واحد أن يحمله قانونًا على طرق تينيسي السريعة دون تصريح؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","23,000 رطل"],"explanation":"تقصر تينيسي وزن المحور الواحد على 20,000 رطل. أما رقم 23,000 رطل فينطبق فقط بموجب تصريح خاص للوزن الزائد، وليس قانونيًا بدونه. المصدر: T.C.A. Section 55-7-203."},"4":{"q":"ما هو الحد الأقصى للوزن الذي يمكن لمجموعة محاور مترادفة أن تحمله قانونًا على طرق تينيسي السريعة دون تصريح؟","options":["32,000 رطل","34,000 رطل","40,000 رطل","46,000 رطل"],"explanation":"تقصر تينيسي وزن مجموعة المحاور المترادفة على 34,000 رطل دون تصريح. أما رقم 46,000 رطل فينطبق فقط بموجب تصريح خاص للوزن الزائد. المصدر: T.C.A. Section 55-7-203."},"5":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة، بما في ذلك حمولتها، على طريق 'عادي' (ليس ضمن الشبكة الفيدرالية أو شبكة الولاية) في تينيسي؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","7 أقدام و6 بوصات","9 أقدام و0 بوصة"],"explanation":"على الطرق العادية، تحدد تينيسي العرض بحد أقصى 8 أقدام (4 أقدام على كل جانب من خط المنتصف)؛ أما السماح بـ 8 أقدام و6 بوصات فينطبق فقط على شبكة الطرق السريعة الفيدرالية وطرق الولاية. المصدر: T.C.A. Section 55-7-202."},"6":{"q":"إلى جانب حدود كل محور والحد الإجمالي، ما هي الطريقة التي تستخدمها تينيسي لتحديد الحد الأقصى للوزن المسموح به بناءً على المسافة بين المحاور؟","options":["معادلة الجسر الفيدرالية (جدول الوزن إلى الطول)","جدول ضريبة الحمولة بالأطنان للولاية","حد ثابت قدره 80,000 رطل بغض النظر عن المسافة بين المحاور","تقييم الوزن الإجمالي المركّب من الشركة المصنّعة"],"explanation":"تطبق تينيسي معادلة الجسر الفيدرالية (المعادلة B)، التي تربط الوزن الإجمالي المسموح به بعدد المحاور والمسافة بينها، بالإضافة إلى حدود المحور الواحد والمحاور المترادفة والوزن الإجمالي. المصدر: T.C.A. Section 55-7-203؛ معادلة الجسر الخاصة بـ FHWA التي اعتمدتها TDOT."},"7":{"q":"بموجب تصريح وزن زائد خاص في تينيسي لحمولة غير قابلة للتقسيم، ما هو الحد الأقصى للوزن المسموح به على محور واحد؟","options":["20,000 رطل","21,500 رطل","23,000 رطل","26,000 رطل"],"explanation":"تسمح تينيسي بما يصل إلى 23,000 رطل على المحور الواحد للحمولات الزائدة غير القابلة للتقسيم التي تُنقل بموجب تصريح (مقابل الحد القانوني البالغ 20,000 رطل). المصدر: T.C.A. Section 55-7-205 وقواعد تصاريح OS/OW الخاصة بـ TDOT."},"8":{"q":"بموجب تصريح وزن زائد خاص في تينيسي، ما هو الحد الأقصى للوزن المسموح به على مجموعة محاور مترادفة؟","options":["34,000 رطل","40,000 رطل","46,000 رطل","50,000 رطل"],"explanation":"تسمح تينيسي بما يصل إلى 46,000 رطل على مجموعة المحاور المترادفة للحمولات الزائدة غير القابلة للتقسيم بموجب تصريح (مقابل الحد القانوني البالغ 34,000 رطل). المصدر: T.C.A. Section 55-7-205 وقواعد تصاريح OS/OW الخاصة بـ TDOT."},"9":{"q":"بموجب تصريح وزن زائد في تينيسي، ما هو الحد الأقصى للوزن المسموح به على مجموعة ثلاثية المحاور (tridem)؟","options":["42,000 رطل","50,000 رطل","60,000 رطل","68,000 رطل"],"explanation":"تسمح تينيسي بما يصل إلى 60,000 رطل على المجموعة ثلاثية المحاور (tridem) للحمولات الزائدة غير القابلة للتقسيم التي تُنقل بموجب تصريح. المصدر: T.C.A. Section 55-7-205 وقواعد تصاريح OS/OW الخاصة بـ TDOT."},"10":{"q":"في تينيسي، يُطلب عادةً تصريح خاص للحجم الزائد أو الوزن الزائد فقط للحمولات التي تكون:","options":["تحمل أي مادة خطرة","غير قابلة للتقسيم ولا يمكن تخفيضها بشكل معقول إلى الحدود القانونية","تسافر أكثر من 100 ميل داخل الولاية","مسجلة خارج الولاية"],"explanation":"تصدر TDOT تصاريح OS/OW للأصناف أو السلع غير القابلة للتقسيم التي لا يمكن تفكيكها أو تقسيمها بشكل معقول للوفاء بالحدود القانونية للحجم/الوزن. أما الحمولة التي يمكن تقسيمها ببساطة فيجب جعلها ضمن الحدود القانونية بدلًا من ذلك. المصدر: مكتب تصاريح الحجم الزائد/الوزن الزائد التابع لـ TDOT؛ T.C.A. Section 55-7-205."},"11":{"q":"ما هي مدة صلاحية تصريح الرحلة الواحدة القياسي للحجم الزائد/الوزن الزائد في تينيسي؟","options":["3 أيام","10 أيام","30 يومًا","سنة واحدة"],"explanation":"تصريح OS/OW للرحلة الواحدة في تينيسي صالح لمدة 10 أيام (تصاريح المنازل المتنقلة صالحة لمدة 6 أيام). المصدر: الأسئلة الشائعة والقواعد الخاصة بمكتب تصاريح الحجم الزائد/الوزن الزائد التابع لـ TDOT."},"12":{"q":"كيف يتقدم الناقل بطلب للحصول على تصريح للحجم الزائد/الوزن الزائد في تينيسي؟","options":["عبر مكالمة هاتفية إلى مأمور الشرطة المحلي","إلكترونيًا من خلال نظام TDOT TNTRIPS عبر الإنترنت","بإرسال نموذج ورقي بالبريد إلى كل مقاطعة","فقط في محطة وزن بشكل شخصي"],"explanation":"يتم الحصول على تصاريح OS/OW في تينيسي إلكترونيًا من خلال نظام TNTRIPS عبر الإنترنت التابع لـ TDOT؛ ولا تُقبل الطلبات عبر الهاتف أو البريد الإلكتروني. المصدر: مكتب تصاريح الحجم الزائد/الوزن الزائد التابع لـ TDOT (TNTRIPS)."},"13":{"q":"على شبكة الطرق السريعة الفيدرالية وطرق الولاية في تينيسي، لا يجوز عادةً أن يتجاوز نصف المقطورة المسحوبة أي طول معين مقاسًا من نقطة اتصالها بالجرّار؟","options":["48 قدمًا","52 قدمًا","57 قدمًا","60 قدمًا"],"explanation":"تسمح تينيسي بنصف مقطورة/مقطورة مسحوبة يصل طولها إلى 52 قدمًا مقاسًا من نقطة الاتصال بالجرّار على شبكة الطرق السريعة الفيدرالية وطرق الولاية. المصدر: T.C.A. Section 55-7-201 (الحد الأقصى لطول المركبات)."},"14":{"q":"على طرق الولاية في تينيسي خارج الطرق السريعة بين الولايات، يُمنح بعض ناقلي السلع (مثل شاحنات قطع الأشجار والفحم والرمل والمزارع) 'هامش خطأ' في الوزن بمقدار كم؟","options":["5 بالمئة","10 بالمئة","15 بالمئة","لا يُسمح بأي هامش"],"explanation":"تسمح تينيسي بهامش خطأ قدره 10 بالمئة على الوزن الإجمالي أو وزن المحور الفعلي لشاحنات قطع الأشجار والرمل والفحم والطين والصخر الزيتي والفوسفات والنفايات الصلبة والمواد المستردة وشاحنات المزارع/الآلات على طرق الولاية، باستثناء شبكة الطرق السريعة بين الولايات. المصدر: T.C.A. Section 55-7-203(b)."},"15":{"q":"هل ينطبق هامش الوزن البالغ 10 بالمئة لشاحنات قطع الأشجار والمزارع والشاحنات المماثلة لنقل السلع في تينيسي على شبكة الطرق السريعة بين الولايات؟","options":["نعم، على جميع الطرق بما في ذلك الطرق بين الولايات","لا، فهو يستثني شبكة الطرق السريعة بين الولايات","فقط في الليل","فقط بتصريح"],"explanation":"ينطبق هامش الوزن البالغ 10 بالمئة للسلع على طرق الولاية في تينيسي ولكنه يستثني تحديدًا شبكة الطرق السريعة بين الولايات (شبكة المساعدة الفيدرالية بين الولايات)، حيث تُطبَّق الحدود الفيدرالية 80,000/20,000/34,000 بصرامة. المصدر: T.C.A. Section 55-7-203(b)."},"16":{"q":"بموجب قانون تينيسي، يمكن نقل بعض الآلات الزراعية لأغراض زراعية دون تصريح عندما يتم نقلها خلال ساعات النهار، خارج الطرق السريعة بين الولايات، وضمن أي مسافة من نقطة منشئها؟","options":["25 ميلًا","50 ميلًا","75 ميلًا","100 ميل"],"explanation":"تسمح تينيسي بنقل الآلات الزراعية ذات الأبعاد الزائدة/الوزن الزائد لأغراض زراعية دون تصريح خلال ساعات النهار، وليس على الطرق السريعة بين الولايات، ضمن 50 ميلًا من نقطة المنشأ. المصدر: T.C.A. Section 55-7-205."},"17":{"q":"عندما تتجاوز حمولة مصرّح بها في تينيسي عرض 10 أقدام، ما الذي يُطلب تحديدًا على المركبة؟","options":["مركبة مرافقة/مرشدة على كلا الطرفين في جميع الأوقات","لافتة 'حمولة كبيرة الحجم' على المقدمة والمؤخرة","مرافقة من الشرطة","السفر فقط بين منتصف الليل والساعة 5 صباحًا"],"explanation":"تتطلب تينيسي عرض لافتة 'حمولة كبيرة الحجم' (Oversize Load) على مقدمة ومؤخرة أي حمولة يتجاوز عرضها 10 أقدام. وتزداد متطلبات المرافقة وغيرها مع ازدياد العرض. المصدر: قواعد تصاريح الحجم الزائد/الوزن الزائد التابعة لـ TDOT."},"18":{"q":"ما هي التكلفة التقريبية لتصريح الوزن الزائد السنوي في تينيسي لمركبة يصل وزنها الإجمالي إلى 100,000 رطل؟","options":["$50","$150","$750","$3,500"],"explanation":"رسوم تصريح الوزن الزائد السنوي من TDOT هي $750 للمركبات التي يصل وزنها الإجمالي إلى 100,000 رطل، مع رسوم متدرجة أعلى للأوزان الأكبر (مثلًا، حتى 120,000 رطل بمعدل أعلى). المصدر: جدول رسوم مكتب تصاريح الحجم الزائد/الوزن الزائد التابع لـ TDOT."},"19":{"q":"في تينيسي، يُقتصر عادةً نقل الحمولات الضخمة (superloads) والمنازل العائمة والمنازل المتنقلة بموجب تصريح على أي أوقات سفر؟","options":["ساعات النهار فقط","ساعات الليل فقط","عطلات نهاية الأسبوع فقط","في أي وقت، على مدار 24 ساعة"],"explanation":"تقصر تينيسي نقل الحمولات الضخمة والمنازل العائمة والمنازل المتنقلة على ساعات النهار فقط، ويجب على الحمولات المرافَقة أيضًا الالتزام بقيود ساعات الذروة في المناطق الحضرية. المصدر: قواعد تصاريح الحجم الزائد/الوزن الزائد التابعة لـ TDOT."},"20":{"q":"في تينيسي، ما هي فئة CDL المطلوبة لتشغيل مجموعة من المركبات بتقييم وزن إجمالي مركّب (GCWR) يبلغ 26,001 رطلًا أو أكثر، حيث يتجاوز وزن المركبة المسحوبة 10,000 رطل من تقييم الوزن الإجمالي للمركبة (GVWR)؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف تينيسي رخصة CDL من الفئة A بأنها مطلوبة لتشغيل مركبة مركّبة بتقييم GCWR يتجاوز 26,000 رطل حيث تتجاوز الوحدة المسحوبة 10,000 رطل من تقييم GVWR. المصدر: Tenn. Comp. R. & Regs. 1340-01-13-.03؛ دليل CDL في تينيسي."},"21":{"q":"ما هي فئة CDL في تينيسي المطلوبة لتشغيل مركبة واحدة بتقييم وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطلًا أو أكثر، أو مركبة كهذه تسحب مقطورة لا يتجاوز وزنها 10,000 رطل من تقييم GVWR؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تعرّف تينيسي رخصة CDL من الفئة B بأنها مطلوبة لمركبة واحدة يتجاوز وزنها 26,000 رطل من تقييم GVWR، أو مركبة كهذه تسحب وحدة لا يتجاوز وزنها 10,000 رطل من تقييم GVWR. المصدر: Tenn. Comp. R. & Regs. 1340-01-13-.03؛ دليل CDL في تينيسي."},"22":{"q":"يشغّل سائق في تينيسي مركبة واحدة يقل وزنها عن 26,001 رطلًا من تقييم GVWR وتحمل لافتات للمواد الخطرة أو مصممة لنقل 16 راكبًا أو أكثر بمن فيهم السائق. ما هي فئة CDL التي تنطبق؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تغطي رخصة CDL من الفئة C في تينيسي المركبات الواحدة التي لا يتجاوز وزنها 26,000 رطل من تقييم GVWR والتي يجب أن تحمل لافتات للمواد الخطرة، أو المصممة لنقل أكثر من 15 راكبًا (16 أو أكثر بمن فيهم السائق)، أو المستخدمة كحافلة مدرسية. المصدر: Tenn. Comp. R. & Regs. 1340-01-13-.03."},"23":{"q":"في تينيسي، ما هو الحد الأدنى للعمر للحصول على رخصة CDL مقيدة بالقيادة التجارية داخل الولاية فقط (intrastate)؟","options":["16 عامًا","17 عامًا","18 عامًا","21 عامًا"],"explanation":"تسمح تينيسي للمتقدمين الذين لا تقل أعمارهم عن 18 عامًا بالحصول على رخصة CDL للتشغيل داخل الولاية فقط. المصدر: دليل CDL في تينيسي؛ وزارة السلامة والأمن الداخلي في تينيسي، خدمات السائقين."},"24":{"q":"في تينيسي، ما هو الحد الأدنى للعمر المطلوب لقيادة مركبة تجارية في التجارة بين الولايات أو لنقل المواد الخطرة؟","options":["18 عامًا","19 عامًا","21 عامًا","25 عامًا"],"explanation":"تتطلب تينيسي أن يكون عمر السائق 21 عامًا على الأقل للتشغيل في التجارة بين الولايات أو لنقل المواد الخطرة؛ ويقتصر السائقون الذين تتراوح أعمارهم بين 18 و20 عامًا على التشغيل داخل الولاية. المصدر: دليل CDL في تينيسي؛ 49 CFR 383.3 كما هو مطبق في تينيسي."},"25":{"q":"ما هو التظهير المطلوب في تينيسي لتشغيل مركبة تجارية تنقل مواد خطرة بكميات تتطلب وضع لافتات؟","options":["تظهير N","تظهير H","تظهير T","تظهير P"],"explanation":"تتطلب تينيسي تظهير H (المواد الخطرة) لقيادة مركبة تجارية تحمل كميات من المواد الخطرة تستلزم وضع لافتات. المصدر: دليل CDL في تينيسي؛ 49 CFR 383.93."},"26":{"q":"قبل أن تتمكن تينيسي من إضافة تظهير المواد الخطرة (H) إلى رخصة CDL، يتطلب القانون الفيدرالي من المتقدم إكمال أي خطوة إضافية؟","options":["تقييم تهديد أمني من TSA مع فحص خلفية قائم على البصمات","دورة دراسية للمواد الخطرة مدتها 40 ساعة في تينيسي","فحص بصري في محطة وزن تابعة لـ DOT في تينيسي","اختبار للمخدرات والكحول يجريه كاتب المقاطعة"],"explanation":"لا يجوز لتينيسي إصدار تظهير المواد الخطرة حتى يجتاز المتقدم تقييم تهديد أمني تديره TSA، والذي يتضمن فحص خلفية قائمًا على البصمات، بموجب قانون USA PATRIOT. المصدر: وزارة السلامة والأمن الداخلي في تينيسي، صفحة تظهير المواد الخطرة؛ 49 CFR 1572."},"27":{"q":"ما هو التظهير الذي تتطلبه تينيسي لقيادة مركبة صهريج مصممة لنقل سائل أو غاز في صهريج مثبت بشكل دائم ومصنّف لحمل 1,000 جالون أو أكثر؟","options":["تظهير H","تظهير N","تظهير T","تظهير S"],"explanation":"تتطلب تينيسي تظهير N (الصهاريج) لمركبات الصهاريج المصممة لنقل السوائل أو الغازات في صهريج مصنّف لـ 1,000 جالون أو أكثر. المصدر: دليل CDL في تينيسي؛ 49 CFR 383.93."},"28":{"q":"ما هو التظهير المطلوب في تينيسي لسحب مقطورتين مزدوجتين أو ثلاثيتين، وعلى أي فئة CDL يقتصر؟","options":["تظهير T، متاح على الفئة A فقط","تظهير T، متاح على الفئة B فقط","تظهير N، متاح على أي فئة","تظهير P، متاح على الفئة C فقط"],"explanation":"تتطلب تينيسي تظهير T (المزدوجة/الثلاثية) لسحب أكثر من مقطورة واحدة، ولأن مثل هذه المجموعات تتطلب رخصة من الفئة A، فإن التظهير متاح على الفئة A فقط. المصدر: دليل CDL في تينيسي؛ Tenn. Comp. R. & Regs. 1340-01-13."},"29":{"q":"ما هو التظهير الذي تتطلبه تينيسي لقيادة مركبة تجارية مصممة لنقل 16 راكبًا أو أكثر، بمن فيهم السائق؟","options":["تظهير S","تظهير P","تظهير N","تظهير H"],"explanation":"تتطلب تينيسي تظهير P (الركاب) لتشغيل مركبة مصممة لنقل 16 شخصًا أو أكثر بمن فيهم السائق. المصدر: دليل CDL في تينيسي؛ 49 CFR 383.93."},"30":{"q":"في تينيسي، يتطلب تظهير الحافلة المدرسية (S) أن يحمل السائق أولًا أي تظهير آخر؟","options":["تظهير H (المواد الخطرة)","تظهير N (الصهاريج)","تظهير P (الركاب)","تظهير T (المزدوجة/الثلاثية)"],"explanation":"في تينيسي، يتطلب تظهير S (الحافلة المدرسية) تظهير P (الركاب) كشرط مسبق، لأن الحافلة المدرسية مركبة لنقل الركاب. المصدر: دليل CDL في تينيسي؛ 49 CFR 383.93."},"31":{"q":"بموجب القاعدة الفيدرالية المطبقة في تينيسي، كم من الوقت يجب أن ينتظر حامل تصريح المتعلّم التجاري (CLP) بعد إصداره مبدئيًا قبل أن يكون مؤهلًا لإجراء اختبار مهارات CDL؟","options":["7 أيام","14 يومًا","30 يومًا","60 يومًا"],"explanation":"لا يكون حامل CLP مؤهلًا لإجراء اختبار مهارات CDL خلال أول 14 يومًا بعد إصدار CLP مبدئيًا. المصدر: 49 CFR 383.25 كما هو مطبق من قبل خدمات السائقين في تينيسي؛ دليل CDL في تينيسي."},"32":{"q":"بموجب المعايير الفيدرالية المتبعة في تينيسي، يكون تصريح المتعلّم التجاري (CLP) صالحًا لمدة لا تزيد عن كم من تاريخ إصداره المبدئي دون إعادة اختبارات المعرفة؟","options":["30 يومًا","90 يومًا","6 أشهر","سنة واحدة"],"explanation":"يجب أن يكون CLP صالحًا لمدة لا تزيد عن سنة واحدة من تاريخ الإصدار المبدئي دون اشتراط إعادة حامله لاختبارات المعرفة؛ وعادةً ما تصدره الولايات لمدة تصل إلى 180 يومًا مع تجديد واحد. المصدر: 49 CFR 383.25؛ خدمات السائقين في تينيسي."},"33":{"q":"أثناء تشغيل مركبة تجارية بموجب تصريح المتعلّم التجاري (CLP) في تينيسي، ما هو الإشراف المطلوب؟","options":["يجب أن يجلس حامل CDL بالفئة والتظهيرات المناسبة بجوار حامل CLP","لا يلزم أي إشراف إذا كان عمر السائق يزيد عن 21 عامًا","يجب أن يتبعه ضابط إنفاذ القانون في مركبة منفصلة","يجوز لأي سائق مرخص من الفئة D أن يركب في المقعد الخلفي"],"explanation":"لا يجوز لحامل CLP القيادة إلا بمرافقة حامل CDL الذي لديه الفئة والتظهيرات المناسبة والذي يجلس في المقعد الأمامي بجوار حامل التصريح. المصدر: 49 CFR 383.25؛ دليل CDL في تينيسي."},"34":{"q":"عند التقدم بطلب للحصول على CDL أو CLP في تينيسي، كم عدد إثباتات الإقامة في تينيسي التي يجب على المتقدم تقديمها؟","options":["إثبات إقامة واحد","إثباتان للإقامة","ثلاثة إثباتات للإقامة","لا يلزم إثبات إقامة"],"explanation":"تتطلب تينيسي من المتقدمين تقديم إثباتين (2) للإقامة في تينيسي، إلى جانب إثبات الهوية/الوجود القانوني ورقم الضمان الاجتماعي. المصدر: وزارة السلامة والأمن الداخلي في تينيسي، المستندات المطلوبة للتقدم بطلب CDL."},"35":{"q":"ما هي مجموعة المستندات التي يجب على المتقدم لرخصة CDL في تينيسي تقديمها لإثبات الأهلية؟","options":["إثبات الهوية/الوجود القانوني، وإثبات رقم الضمان الاجتماعي، وإثباتان للإقامة في تينيسي","بطاقة تسجيل الناخبين في تينيسي فقط","جواز سفر وفاتورة خدمات واحدة فقط","شهادة ميلاد وسند ملكية مركبة"],"explanation":"تتطلب تينيسي إثبات الهوية والوجود القانوني (الجنسية الأمريكية أو وضع المقيم الدائم القانوني)، وإثبات رقم الضمان الاجتماعي، وإثباتين للإقامة في تينيسي. المصدر: وزارة السلامة والأمن الداخلي في تينيسي، المستندات المطلوبة للتقدم بطلب CDL."},"36":{"q":"ما هو التدريب الذي يجب على المتقدمين الجدد في تينيسي إكماله قبل إجراء اختبار مهارات CDL لرخصة من الفئة A أو الفئة B، أو قبل إضافة بعض التظهيرات؟","options":["تدريب السائقين المبتدئين (ELDT) من مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA","دورة قيادة دفاعية في كلية مجتمعية في تينيسي","تدريب مهني مدته أربع سنوات مسجل لدى المقاطعة","برنامج مرافقة مع دورية الطرق السريعة في تينيسي"],"explanation":"تتطلب تينيسي من المتقدمين الجدد إكمال تدريب السائقين المبتدئين (ELDT) المقدّم من مدرسة مدرجة في سجل مزودي التدريب التابع لـ FMCSA قبل اختبار المهارات للفئة A/B أو لتظهيرات H أو P أو S. المصدر: 49 CFR Part 380 Subpart F؛ صفحة CDL لخدمات السائقين في تينيسي."},"37":{"q":"عند الإقرار الذاتي لرخصة CDL في تينيسي، ما هي الفئة التي تصف السائق الذي يعمل في التجارة بين الولايات ويجب أن يستوفي اشتراط شهادة الفاحص الطبي الفيدرالي التابع لـ DOT؟","options":["مُستثنى بين الولايات (Excepted Interstate)","غير مُستثنى بين الولايات (Non-Excepted Interstate)","مُستثنى داخل الولاية (Excepted Intrastate)","غير مُستثنى داخل الولاية (Non-Excepted Intrastate)"],"explanation":"السائق الذي يقرّ ذاتيًا بأنه غير مُستثنى بين الولايات (Non-Excepted Interstate) يعمل في التجارة بين الولايات ويجب أن يحتفظ بشهادة فاحص طبي فيدرالي سارية تابعة لـ DOT. المصدر: وزارة السلامة والأمن الداخلي في تينيسي، متطلبات الشهادة الطبية؛ 49 CFR 383.71."},"38":{"q":"كم عدد فئات الإقرار الذاتي التي يجب على المتقدم لرخصة CDL في تينيسي الاختيار من بينها فيما يتعلق بنوع القيادة التجارية التي يقوم بها؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"يجب على حاملي رخصة CDL في تينيسي الإقرار ذاتيًا بإحدى أربع فئات: غير مُستثنى بين الولايات، ومُستثنى بين الولايات، وغير مُستثنى داخل الولاية، ومُستثنى داخل الولاية. المصدر: وزارة السلامة والأمن الداخلي في تينيسي، متطلبات الشهادة الطبية؛ 49 CFR 383.71."},"39":{"q":"يقرّ سائق في تينيسي ذاتيًا بأنه غير مُستثنى بين الولايات (Non-Excepted Interstate). للحفاظ على صلاحية رخصة CDL، ما الذي يجب على السائق الاحتفاظ به في ملفه لدى الولاية؟","options":["شهادة فاحص طبي فيدرالية حالية من فاحص معتمد","خطاب موثّق من صاحب العمل","نسخة من شهادة الثانوية العامة","ملصق فحص سنوي للمركبة"],"explanation":"يجب على السائقين غير المُستثنين الحصول على شهادة فاحص طبي فيدرالية حالية من فاحص طبي معتمد مدرج في السجل الوطني التابع لـ FMCSA والاحتفاظ بها، وإبقاؤها في ملفهم لدى الولاية. المصدر: وزارة السلامة والأمن الداخلي في تينيسي، متطلبات الشهادة الطبية؛ 49 CFR 391.45."},"40":{"q":"في تينيسي، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونًا تشغيل مركبة آلية تجارية (CMV)؟","options":["0.02","0.04","0.08","0.10"],"explanation":"تتبع تينيسي المعيار الفيدرالي: تشغيل مركبة CMV بتركيز BAC قدره 0.04 أو أعلى يُعد مخالفة كبرى. وهذا نصف الحد البالغ 0.08 للسائقين غير التجاريين. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 1؛ T.C.A. 55-50-405."},"41":{"q":"يُدان سائق للمرة الأولى بتشغيل مركبة CMV بتركيز BAC قدره 0.04 أو أعلى بينما لا ينقل مواد خطرة. لكم من الوقت تُلغى أهلية رخصة CDL؟","options":["60 يومًا","6 أشهر","سنة واحدة","3 سنوات"],"explanation":"تؤدي أول مخالفة كبرى (بما في ذلك تركيز BAC قدره 0.04 أو أعلى في مركبة CMV) إلى إلغاء أهلية رخصة CDL لمدة لا تقل عن سنة واحدة في تينيسي. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 1."},"42":{"q":"يرتكب سائق أول مخالفة كحول كبرى أثناء تشغيل مركبة CMV كانت تحمل لافتات للمواد الخطرة. ما هي مدة إلغاء الأهلية؟","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"عندما تقع أول مخالفة كبرى أثناء نقل مركبة CMV لمواد خطرة تحمل لافتات، تزداد مدة إلغاء الأهلية في تينيسي من سنة واحدة إلى 3 سنوات. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 1."},"43":{"q":"بموجب قانون الموافقة الضمنية في تينيسي، ما هي عواقب رفض حامل رخصة CDL إجراء اختبار كيميائي/كحول الدم المطلوب للمرة الأولى؟","options":["تحذير فقط","فقدان رخصة CDL لمدة 60 يومًا","فقدان رخصة CDL لمدة سنة واحدة","فقدان رخصة CDL لمدة 90 يومًا"],"explanation":"يُعامَل رفض الخضوع لاختبار الكحول على أنه مخالفة كبرى في تينيسي، مما يؤدي إلى إلغاء أهلية رخصة CDL لمدة لا تقل عن سنة واحدة، وهي نفس مدة أول إدانة بالقيادة بتجاوز حد BAC. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ T.C.A. 55-50-405؛ 49 CFR 383.51."},"44":{"q":"يُدان حامل رخصة CDL بمخالفة كبرى ثانية (على سبيل المثال، انتهاك ثانٍ لـ BAC-0.04) خلال مسيرته في القيادة. ما هي مدة إلغاء الأهلية في تينيسي؟","options":["3 سنوات","10 سنوات","مدى الحياة","5 سنوات"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى إلغاء أهلية رخصة CDL مدى الحياة. لم تعتمد تينيسي الحكم الاختياري لإعادة الترخيص بعد 10 سنوات، لذا فإن الحظر مدى الحياة دائم. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ إرشادات المخالفات الجسيمة لـ CDL من وزارة السلامة في تينيسي؛ 49 CFR 383.51 Table 1."},"45":{"q":"استخدام مركبة آلية تجارية لارتكاب جناية تنطوي على تصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يؤدي إلى أي إلغاء أهلية في تينيسي؟","options":["سنة واحدة","3 سنوات","مدى الحياة، دون إعادة ترخيص","5 سنوات"],"explanation":"يحمل استخدام مركبة CMV في ارتكاب جناية تنطوي على مواد خاضعة للرقابة إلغاء أهلية مدى الحياة دون إمكانية إعادة الترخيص في تينيسي. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 1."},"46":{"q":"كم عدد مخالفات المرور الجسيمة التي يجب أن يرتكبها سائق CDL خلال فترة 3 سنوات قبل أن يُفعَّل أول إلغاء أهلية في تينيسي؟","options":["مخالفة واحدة","مخالفتان","3 مخالفات","4 مخالفات"],"explanation":"لا تتسبب مخالفة مرور جسيمة واحدة في إلغاء الأهلية. يُفعَّل أول إلغاء أهلية (60 يومًا) بسبب مخالفة جسيمة ثانية خلال 3 سنوات. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 2."},"47":{"q":"يُدان سائق CDL بمخالفتي مرور جسيمتين خلال فترة 3 سنوات. ما هي مدة إلغاء الأهلية؟","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان جسيمتان خلال 3 سنوات إلى إلغاء أهلية رخصة CDL لمدة 60 يومًا في تينيسي. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 2."},"48":{"q":"يجمع سائق CDL ثلاث مخالفات مرور جسيمة خلال فترة 3 سنوات. ما هي مدة إلغاء الأهلية؟","options":["60 يومًا","90 يومًا","120 يومًا","180 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرور جسيمة خلال 3 سنوات إلى إلغاء أهلية رخصة CDL لمدة 120 يومًا في تينيسي. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 2."},"49":{"q":"عند أي سرعة فوق الحد المعلن تُحتسب السرعة المفرطة على أنها 'مخالفة مرور جسيمة' لحامل رخصة CDL في تينيسي؟","options":["10 mph أو أكثر فوق الحد","15 mph أو أكثر فوق الحد","20 mph أو أكثر فوق الحد","25 mph أو أكثر فوق الحد"],"explanation":"تُصنَّف القيادة بسرعة 15 mph أو أكثر فوق حد السرعة المعلن على أنها مخالفة مرور جسيمة. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 2."},"50":{"q":"أي مما يلي يُصنَّف على أنه مخالفة مرور جسيمة وليس مخالفة كبرى لسائق CDL في تينيسي؟","options":["قيادة مركبة CMV بتركيز BAC قدره 0.04 أو أعلى","القيادة المتهورة / السير على مسافة قريبة جدًا","مغادرة مكان الحادث","استخدام مركبة CMV لارتكاب جناية"],"explanation":"تُعد القيادة المتهورة، والسير على مسافة قريبة جدًا، وتغيير المسارات بشكل غير سليم/متقطع مخالفات مرور جسيمة. أما الخيارات الأخرى المدرجة فهي مخالفات كبرى تحمل إلغاء أهلية لمدة سنة واحدة (أو مدى الحياة). المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Tables 1 and 2."},"51":{"q":"تُصنَّف كتابة الرسائل النصية أثناء قيادة مركبة CMV بموجب قواعد CDL في تينيسي على أنها أي مما يلي؟","options":["مخالفة كبرى (إلغاء أهلية لمدة سنة واحدة)","مخالفة مرور جسيمة","مخالفة أمر إخراج من الخدمة","مخالفة غير مُلغية للأهلية"],"explanation":"كلٌّ من كتابة الرسائل النصية واستخدام هاتف محمول باليد أثناء قيادة مركبة CMV مخالفتان مروريتان جسيمتان، يمكن أن تُحتسبا ضمن إلغاءات الأهلية لمدة 60 يومًا/120 يومًا. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 2؛ FMCSA 392.80/392.82."},"52":{"q":"يتلقى سائق CDL إدانة ثانية لاستخدام هاتف محمول باليد أثناء قيادة مركبة CMV، وقد وقعت الثانية خلال 3 سنوات من الأولى. ما هو إلغاء الأهلية الذي ينطبق؟","options":["لا إلغاء للأهلية","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"استخدام الهاتف المحمول باليد مخالفة مرور جسيمة. تؤدي المخالفة الجسيمة الثانية خلال 3 سنوات إلى إلغاء أهلية لمدة 60 يومًا. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 2."},"53":{"q":"ما هي مدة إلغاء الأهلية لأول إدانة بمخالفة معبر سكة حديد-طريق سريع لسائق CDL في تينيسي؟","options":["لا تقل عن 30 يومًا","لا تقل عن 60 يومًا","لا تقل عن 120 يومًا","لا تقل عن سنة واحدة"],"explanation":"تحمل أول مخالفة لمعبر سكة حديد-طريق سريع إلغاء أهلية لا يقل عن 60 يومًا. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 3."},"54":{"q":"يُدان سائق CDL في تينيسي بمخالفة ثانية لمعبر سكة حديد-طريق سريع خلال فترة 3 سنوات. ما هو الحد الأدنى لإلغاء الأهلية؟","options":["60 يومًا","90 يومًا","120 يومًا","180 يومًا"],"explanation":"تؤدي مخالفة ثانية لمعبر سكة حديد خلال 3 سنوات إلى إلغاء أهلية لا يقل عن 120 يومًا. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 3."},"55":{"q":"يُدان سائق CDL في تينيسي بمخالفة ثالثة لمعبر سكة حديد-طريق سريع خلال فترة 3 سنوات. ما هو الحد الأدنى لإلغاء الأهلية؟","options":["120 يومًا","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"تؤدي مخالفة ثالثة لمعبر سكة حديد خلال 3 سنوات إلى إلغاء أهلية لا يقل عن سنة واحدة. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 3."},"56":{"q":"ما هو الحد الأدنى لمدة إلغاء الأهلية لأول مخالفة لأمر إخراج من الخدمة (في مركبة CMV لا تنقل مواد خطرة أو ركابًا) لسائق CDL في تينيسي؟","options":["30 يومًا","90 يومًا","180 يومًا","سنة واحدة"],"explanation":"تؤدي أول مخالفة لأمر إخراج من الخدمة إلى إلغاء أهلية لا يقل عن 180 يومًا (حتى سنة واحدة). المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 4."},"57":{"q":"بالإضافة إلى إلغاء الأهلية، ما هو الحد الأدنى للغرامة المدنية التي يواجهها سائق في تينيسي لأول مخالفة لأمر إخراج من الخدمة؟","options":["$1,000","$2,500","$5,000","$10,000"],"explanation":"تحمل أول مخالفة لأمر إخراج من الخدمة غرامة مدنية لا تقل عن $2,500 بالإضافة إلى إلغاء الأهلية لمدة 180 يومًا؛ وتحمل المخالفة الثانية حدًا أدنى قدره $5,000. المصدر: دليل CDL في تينيسي / وزارة السلامة في تينيسي؛ 49 CFR 383.53."},"58":{"q":"يرتكب سائق CDL في تينيسي مخالفة ثانية لأمر إخراج من الخدمة خلال فترة 10 سنوات (دون مواد خطرة). ما هو الحد الأدنى لإلغاء الأهلية؟","options":["180 يومًا","سنة واحدة","سنتان","5 سنوات"],"explanation":"تؤدي مخالفة ثانية لأمر إخراج من الخدمة خلال 10 سنوات إلى إلغاء أهلية لا يقل عن سنتين (وغرامة مدنية لا تقل عن $5,000). المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 4."},"59":{"q":"ينتهك سائق أمر إخراج من الخدمة للمرة الأولى بينما تنقل مركبة CMV مواد خطرة تحمل لافتات. ما هي مدة إلغاء الأهلية؟","options":["لا تقل عن 60 يومًا","لا تقل عن 180 يومًا، وحتى سنتين","سنة واحدة بالضبط","مدى الحياة"],"explanation":"تحمل أول مخالفة لأمر إخراج من الخدمة أثناء نقل مواد خطرة تحمل لافتات (أو نقل 16 راكبًا أو أكثر) إلغاء أهلية مشددًا لا يقل عن 180 يومًا وحتى سنتين. المصدر: دليل CDL في تينيسي (إلغاء الأهلية)؛ 49 CFR 383.51 Table 4."},"60":{"q":"على طريق سريع في تينيسي يحتوي على أربعة مسارات على الأقل، يُلزِم قانون التنحّي جانبًا (Move Over) السائقَ المقترِب الذي يتجاوز مركبة طوارئ متوقفة تَعرض أضواءً وامضة بأن يفعل ماذا عندما يكون ذلك آمنًا؟","options":["أن ينتقل إلى مسار غير ملاصق للمركبة المتوقفة","أن يتوقف توقفًا تامًا حتى تغادر مركبة الطوارئ","أن ينتقل إلى الكتف الأيمن ويواصل المرور","أن يُطلق بوق المركبة ويحافظ على السرعة المقررة"],"explanation":"يُلزِم قانون التنحّي جانبًا في تينيسي (T.C.A. 55-8-132) السائقين على طريق سريع مكوّن من أربعة مسارات أو أكثر بإفساح الطريق عبر الانتقال إلى مسار غير ملاصق للمركبة المتوقفة عندما يكون ذلك آمنًا؛ وفقط إذا كان تغيير المسار مستحيلًا أو غير آمن جاز للسائق بدلًا من ذلك أن يُبطئ إلى سرعة آمنة. المصدر: T.C.A. 55-8-132."},"61":{"q":"بموجب قانون التنحّي جانبًا في تينيسي، إذا لم يستطع سائق مركبة تجارية (CMV) تغيير المسار بأمان عند تجاوز مركبة مرافق عامة أو مركبة صيانة متوقفة تَعرض أضواءً وامضة، فماذا يجب على السائق أن يفعل بدلًا من ذلك؟","options":["أن يتوقف توقفًا تامًا على الطريق","أن يُخفّض السرعة إلى سرعة آمنة تناسب ظروف الطريق","أن يُخفّض السرعة إلى 25 mph بالضبط دون الحد المسموح","أن ينعطف إلى الكتف المقابل"],"explanation":"يشمل T.C.A. 55-8-132 مركبات الشرطة والإطفاء والإسعاف والمرافق العامة والقطر وصيانة الطرق السريعة. وإذا كان تغيير المسار مستحيلًا أو غير آمن، فيجب على السائق أن يُخفّض السرعة إلى سرعة آمنة تناسب ظروف الطريق؛ ولا يُحدّد القانون نسبة رقمية للتخفيض. المصدر: T.C.A. 55-8-132."},"62":{"q":"يُصنّف انتهاك قانون التنحّي جانبًا في تينيسي (عدم التنحّي أو الإبطاء لمركبة طوارئ متوقفة) على أنه ماذا؟","options":["مخالفة مدنية غير متعلقة بالحركة","جناية من الفئة C","جنحة من الفئة B","مجرد تحذير فقط"],"explanation":"انتهاك قانون التنحّي جانبًا في تينيسي هو جنحة من الفئة B، يُعاقب عليها بغرامة تصل إلى $500 (مع احتمال السجن في الحالات المشددة). المصدر: T.C.A. 55-8-132."},"63":{"q":"ما هو الحد الأقصى المقرر للسرعة المسموح به على الطرق السريعة بين الولايات في تينيسي؟","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"تُحدّد تينيسي حدًّا أقصى قانونيًّا قدره 70 mph على الطرق السريعة بين الولايات. المصدر: T.C.A. 55-8-152."},"64":{"q":"بموجب قانون تينيسي، على الطرق السريعة التي ليست بين الولايات ولا طرقًا ذات أربعة مسارات محكومة الوصول، ما هو الحد الأقصى العام للسرعة لشاحنة (سعة مقننة قدرها 1.5 طن أو أكثر)؟","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"يقصر T.C.A. 55-8-152 سرعة الشاحنات (سعة مقننة قدرها 1.5 طن أو أكثر) على 55 mph على الطرق السريعة غير الطرق بين الولايات والطرق السريعة ذات الأربعة مسارات محكومة الوصول، حيث يكون الحد فيها 65 mph. المصدر: T.C.A. 55-8-152."},"65":{"q":"في تينيسي، ما هو الحد الأدنى القانوني للسرعة لمركبة تسير في المسار الأيسر (مسار التجاوز) من طريق سريع محكوم الوصول يحتوي على أربعة مسارات أو أكثر؟","options":["40 mph","45 mph","55 mph","65 mph"],"explanation":"تجعل تينيسي من غير القانوني السير بسرعة تقل عن 55 mph في المسار الأيسر من طريق سريع محكوم الوصول يحتوي على أربعة مسارات أو أكثر. المصدر: T.C.A. 55-8-152."},"66":{"q":"عندما يُطلب من سائق مركبة تجارية (CMV) في تينيسي التوقف عند مَعبر سكة حديد، أين يجب أن تتوقف المركبة بالنسبة لأقرب قضيب؟","options":["ضمن 50 قدمًا ولكن ليس أقل من 15 قدمًا","ضمن 25 قدمًا ولكن ليس أقل من 5 أقدام","ضمن 100 قدم ولكن ليس أقل من 50 قدمًا","على بُعد 10 أقدام بالضبط من القضيب"],"explanation":"يجب على السائق المُلزَم بالتوقف أن يتوقف ضمن 50 قدمًا ولكن ليس أقل من 15 قدمًا من أقرب قضيب، ثم ينظر ويُنصت قبل المتابعة. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 392.10."},"67":{"q":"أيٌّ مما يلي يجب أن يتوقف دائمًا عند مَعبر سكة حديد في تينيسي، حتى عندما لا يكون أي قطار مرئيًّا؟","options":["أي مقطورة مسطحة فارغة","حافلة تنقل ركابًا ومركبة تحمل لافتات مواد خطرة","أي شاحنة مستقيمة بثلاثة محاور","أي مركبة يزيد وزنها على 26,001 رطلًا"],"explanation":"المركبات التجارية التي يجب أن تتوقف عند معابر السكك الحديدية هي الحافلات التي تنقل ركابًا والمركبات التي تَعرض لافتات المواد الخطرة؛ ومعظم المركبات التجارية الأخرى غير مُلزَمة بالتوقف ما لم تتطلب الإشارات ذلك. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 392.10."},"68":{"q":"أثناء وجود أي جزء من مركبة تجارية (CMV) في تينيسي على قضبان السكة الحديد خلال العبور، يجب على السائق ألا يفعل أيًّا مما يلي؟","options":["أن يُبقي كلتا يديه على المقود","أن ينظر في كلا الاتجاهين على طول القضبان","أن يُبدّل التروس","أن يحافظ على سرعة ثابتة"],"explanation":"يجب على السائقين ألا يتوقفوا أو يُبدّلوا التروس أو يُغيّروا المسار أثناء عبور أي جزء من المركبة للقضبان، لأن فشل تبديل ترس قد يترك المركبة متعطلة على القضبان. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 392.10."},"69":{"q":"على طريق ذي مسارين في تينيسي به حركة مرور في كلا الاتجاهين، ماذا يجب على السائق أن يفعل عندما تتوقف حافلة مدرسية وتُشغّل أضواءها الحمراء الوامضة لتحميل الأطفال أو إنزالهم؟","options":["يجب فقط على المركبات الموجودة خلف الحافلة أن تتوقف","يجب على المركبات في كلا الاتجاهين أن تتوقف","الإبطاء إلى 15 mph والمرور بحذر","تجاوز الحافلة من اليسار إذا لم يكن هناك أطفال مرئيون"],"explanation":"على طريق غير مقسوم، يجب على السائقين في كلا الاتجاهين التوقف لحافلة مدرسية تَعرض أضواءً حمراء وامضة وذراع توقف حتى يتم سحبها. المصدر: T.C.A. 55-8-151."},"70":{"q":"في تينيسي، يُعفى السائق الذي يلتقي بحافلة مدرسية متوقفة قادمًا من الاتجاه المعاكس من التوقف فقط عندما تكون الطرق مفصولة بماذا؟","options":["خط منتصف مرسوم","مسار انعطاف يسار ثنائي الاتجاه (مسار انتحاري)","مساحة فاصلة أو حاجز مادي غير ملائم لحركة المركبات (طرق منفصلة)","ثلاثة مسارات سير على الأقل"],"explanation":"ينطبق الاستثناء في تينيسي فقط على طريق سريع ذي طرق منفصلة، أي أن الاتجاهين مقسومان بمساحة فاصلة أو حاجز غير ملائم لحركة المركبات. ومجرد خط مرسوم أو مسار انعطاف أوسط لا يستوفي الشرط، لذا يجب على السائقين التوقف رغم ذلك. المصدر: T.C.A. 55-8-151."},"71":{"q":"تُصنّف المخالفة الأولى لتجاوز حافلة مدرسية متوقفة بصورة غير قانونية في تينيسي على أنها ماذا؟","options":["مخالفة غير متعلقة بالحركة","جنحة من الفئة A","جنحة من الفئة C","عقوبة مدنية فقط"],"explanation":"تجاوز حافلة مدرسية متوقفة بصورة غير قانونية هو جنحة من الفئة A في تينيسي، بغرامة لا تقل عن $250 ولا تزيد على $1,000 للمخالفة الأولى. المصدر: T.C.A. 55-8-151."},"72":{"q":"في تينيسي، عندما يتجاوز سائق حافلة مدرسية متوقفة بصورة غير قانونية ويصدم شخصًا ويُسبّب وفاته، ترتقي الجريمة إلى أي مستوى؟","options":["جنحة من الفئة A","جناية من الفئة E","جناية من الفئة C","جنحة من الفئة B"],"explanation":"صدم شخص أثناء تجاوز حافلة مدرسية متوقفة بصورة غير قانونية هو جناية من الفئة E؛ وإذا أسفر الصدم عن الوفاة، فإنه جناية من الفئة C. المصدر: T.C.A. 55-8-151."},"73":{"q":"تُخوّل تينيسي وزارة النقل (TDOT) بحصر شاحنات الجرّ والمقطورات نصف ال­مقطورة في مسارات محددة على الطرق السريعة بين الولايات والطرق المقسومة متعددة المسارات التي تحتوي على كم مسارًا في كل اتجاه؟","options":["مسار واحد أو أكثر","مساران أو أكثر","ثلاثة مسارات أو أكثر","خمسة مسارات أو أكثر"],"explanation":"يُخوّل T.C.A. 55-8-195 وزارة النقل (TDOT) بتوجيه شاحنات الجرّ والمقطورات نصف المقطورة إلى مسارات محددة على الطرق السريعة بين الولايات والطرق المقسومة متعددة المسارات التي بها ثلاثة مسارات أو أكثر في كل اتجاه؛ والانتهاك جنحة من الفئة C (غرامة تصل إلى $50). المصدر: T.C.A. 55-8-195."},"74":{"q":"بموجب قانون المسار الأيسر (قانون بطيء السير - Slow Poke) في تينيسي، متى يجوز للسائق قانونيًّا أن يسير في أقصى مسار التجاوز الأيسر من طريق سريع بين الولايات أو طريق مقسوم متعدد المسارات؟","options":["كلما كانت حركة المرور خفيفة","فقط عند تجاوز أو اجتياز مركبة في مسار غير مخصص للتجاوز","في أي وقت طالما يُلتزم بحد السرعة","فقط بين غروب الشمس وشروقها"],"explanation":"يقصر قانون المسار الأيسر في تينيسي (T.C.A. 55-8-204) مسار التجاوز على اجتياز أو تجاوز مركبة في مسار غير مخصص للتجاوز؛ والبقاء فيه بخلاف ذلك محظور. المصدر: T.C.A. 55-8-204."},"75":{"q":"عندما تتوقف مركبة تجارية (CMV) على كتف طريق في تينيسي، أين يجب وضع مثلث التحذير الخلفي على طريق عادي ذي مسارين وباتجاهين؟","options":["على بُعد 10 أقدام خلف المركبة","على بُعد 40 قدمًا خلف المركبة","على بُعد 100 قدم خلف المركبة","على بُعد 200 قدم خلف المركبة"],"explanation":"يجب وضع أجهزة التحذير خلال 10 دقائق: واحد على بُعد نحو 10 أقدام خلف المركبة من جهة حركة المرور، وواحد على بُعد نحو 100 قدم خلفها، وواحد على بُعد نحو 100 قدم أمامها (في اتجاه حركة المرور المقتربة). المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 392.22."},"76":{"q":"بعد كم من الوقت من التوقف يجب على سائق مركبة تجارية (CMV) في تينيسي وضع أجهزة التحذير الطارئة المطلوبة (المثلثات)؟","options":["خلال 10 دقائق","خلال 30 دقيقة","فورًا، قبل الخروج من المقصورة","خلال ساعة واحدة"],"explanation":"يجب على سائق المركبة التجارية المتوقفة وضع مثلثات التحذير الثلاثة خلال 10 دقائق من التوقف. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 392.22."},"77":{"q":"من دون تصريح خاص، ما هو الحد الأقصى القانوني لعرض المركبة التجارية مع الحمولة في تينيسي؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و6 بوصات","10 أقدام و0 بوصة"],"explanation":"الحد الأقصى القانوني للعرض في تينيسي من دون تصريح حمولة كبيرة الحجم هو 8 أقدام و6 بوصات؛ والارتفاع القانوني هو 13 قدمًا و6 بوصات. وتجاوز هذه الحدود يتطلب تصريحًا خاصًّا من TDOT. المصدر: قواعد تصاريح TDOT للحمولات كبيرة الحجم/الزائدة الوزن؛ T.C.A. Title 55, Ch. 7."},"78":{"q":"تَقصُر تصاريح الحمولات كبيرة الحجم في تينيسي الحركة عمومًا على أي نافذة زمنية؟","options":["ساعات النهار فقط (نحو نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها)","الليل فقط، لتجنّب الازدحام","أي فترة 24 ساعة بما في ذلك أيام الأحد","فقط بين الساعة 9:00 صباحًا و4:00 مساءً"],"explanation":"تسمح تصاريح الحمولات كبيرة الحجم في تينيسي عمومًا بالسفر أثناء النهار (نحو نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها)، من الاثنين إلى السبت، دون حركة أيام الأحد أو العطلات الكبرى مع حظر تجوال خلال ساعات الذروة في المقاطعات الكبيرة. المصدر: قواعد تصاريح TDOT للحمولات كبيرة الحجم/الزائدة الوزن."},"79":{"q":"على المنحدر الحاد المتجه شرقًا في جبل مونتيغل على الطريق I-24 في تينيسي، ما ميزة السلامة المتوفرة للشاحنات التي تفقد مكابحها؟","options":["ساحة رسوم مرور إلزامية","منحدرات هروب للشاحنات الجامحة مملوءة بالحصى","عبّارة عبور إلزامية","مسار سريع قابل للعكس"],"explanation":"إن منحدر الطريق I-24 في جبل مونتيغل (بانحدار يبلغ نحو 6%) مزوّد بمنحدرات هروب للشاحنات الجامحة مملوءة بالحصى، وتُوجَّه الشاحنات التجارية لاستخدام محطة الفحص/فحص المكابح قبل النزول. المصدر: TDOT؛ إرشادات القيادة في الجبال بدليل CDL لولاية تينيسي."},"80":{"q":"أيُّ جهة حكومية مسؤولة عن إصدار رخص القيادة التجارية (CDLs) في تينيسي؟","options":["وزارة السلامة والأمن الداخلي بولاية تينيسي","وزارة النقل بولاية تينيسي (TDOT)","إدارة المركبات الآلية بولاية تينيسي","لجنة الخدمات العامة بولاية تينيسي"],"explanation":"تُصدَر رخص CDL في تينيسي عن طريق وزارة السلامة والأمن الداخلي بولاية تينيسي (TDOSHS) من خلال مراكز خدمات السائقين التابعة لها. وليس لدى تينيسي 'إدارة مركبات آلية' منفصلة؛ وتتولى TDOT شؤون الطرق السريعة لا إصدار الرخص. المصدر: دليل CDL لولاية تينيسي؛ tn.gov/safety خدمات السائقين."},"81":{"q":"أين يؤدّي مقدّم الطلب في تينيسي اختبار المعرفة العامة لرخصة CDL وأي اختبارات معرفة للمصادقات (endorsements)؟","options":["في مركز خدمات سائقين متكامل الخدمات تُشغّله وزارة السلامة","في أي مدرسة قيادة شاحنات مسجّلة لدى FMCSA","في مكتب منطقة تابع لوزارة النقل بولاية تينيسي","عبر الإنترنت من المنزل من خلال بوابة الخدمات الإلكترونية"],"explanation":"تُجري مراكز خدمات السائقين متكاملة الخدمات في تينيسي اختبار المعرفة العامة لرخصة CDL واختبارات المعرفة لأي مصادقة. وتُقدّم المدارس التدريب (ELDT)، لا اختبار المعرفة الخاص بالولاية. المصدر: دليل CDL لولاية تينيسي؛ tn.gov/safety خدمات السائقين 'كيف أحصل على CDL'."},"82":{"q":"قبل أن يُصدَر تصريح متعلّم تجاري (CLP)، ما الذي يجب أن يفعله مقدّم الطلب في تينيسي أولًا؟","options":["اجتياز اختبار المعرفة العامة لرخصة CDL","اجتياز اختبار المهارات المكوّن من ثلاثة أجزاء","إكمال تدريب ELDT خلف المقود في الميدان","الاحتفاظ بتصريح CLP لمدة 14 يومًا على الأقل"],"explanation":"للحصول على تصريح CLP يجب أن يكون مقدّم الطلب في تينيسي قد أدّى واجتاز اختبار المعرفة العامة لرخصة CDL (إضافة إلى اختبارات المصادقات المطلوبة). أما اختبار المهارات وفترة الاحتفاظ البالغة 14 يومًا فيأتيان بعد إصدار تصريح CLP. المصدر: دليل CDL لولاية تينيسي؛ tn.gov/safety خدمات السائقين."},"83":{"q":"أيُّ مجموعة من المستندات يجب أن يُقدّمها مقدّم طلب رخصة CDL في تينيسي في مركز خدمات السائقين؟","options":["إثبات الهوية، ورقم الضمان الاجتماعي، والجنسية الأمريكية/الوجود القانوني، والإقامة في تينيسي","جواز سفر ساري المفعول وبطاقة ائتمان رئيسية فقط","شهادة الثانوية العامة وخطابا توصية من جهات عمل","سند ملكية مركبة وتسجيل مركبة حالي فقط"],"explanation":"تتطلب تينيسي إثبات الهوية، وإثبات رقم الضمان الاجتماعي، وإثبات الجنسية الأمريكية أو وضع المقيم الدائم القانوني، ومستندين يُثبتان الإقامة/السكن في تينيسي. المصدر: دليل CDL لولاية تينيسي؛ tn.gov/safety متطلبات مستندات خدمات السائقين."},"84":{"q":"كم عدد فئات التجارة المتمايزة التي يجب على مقدّم طلب رخصة CDL في تينيسي الاختيار من بينها عند استكمال إقرار التصديق الذاتي؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يُدرج إقرار التصديق الذاتي في تينيسي (SF-1480) أربعة خيارات: تجارة بين الولايات غير مُستثناة، وتجارة بين الولايات مُستثناة، وتجارة داخل الولاية غير مُستثناة، وتجارة داخل الولاية مُستثناة. ويُوقّع السائق بالأحرف الأولى على واحد فقط بالضبط. المصدر: إقرار التصديق الذاتي SF-1480 لولاية تينيسي؛ tn.gov/safety."},"85":{"q":"أيُّ فئة من فئات التصديق الذاتي تتطلب من حامل رخصة CDL في تينيسي تقديم شهادة فاحص طبي فيدرالية حالية من DOT؟","options":["تجارة بين الولايات غير مُستثناة","تجارة بين الولايات مُستثناة","تجارة داخل الولاية مُستثناة","تجارة بين الولايات مُستثناة لنقل مستلزمات المزارع فقط"],"explanation":"يخضع السائق الذي يُصدّق ذاتيًّا على أنه ضمن فئة التجارة بين الولايات غير المُستثناة لأحكام 49 CFR 391.45 ويجب عليه تقديم شهادة فاحص طبي حالية. أما الفئات المُستثناة فليست مُلزَمة بتقديم بطاقة طبية فيدرالية. المصدر: SF-1480 لولاية تينيسي؛ tn.gov/safety متطلبات التصديق الطبي."},"86":{"q":"في تينيسي، ما الاسم الشائع لشهادة الفاحص الطبي الفيدرالية من DOT التي يجب على حاملي رخص CDL ضمن التجارة بين الولايات غير المُستثناة إبقاؤها حالية؟","options":["البطاقة الطبية (بطاقة DOT)","بطاقة المصادقة على المواد الخطرة","شهادة الخدمة الانتقائية","بطاقة TWIC"],"explanation":"شهادة الفاحص الطبي (النموذج MCSA-5876) بموجب 49 CFR 391.45 تُسمّى شائعًا 'البطاقة الطبية' أو 'بطاقة DOT'. أما بطاقة TWIC ومصادقة HazMat فهما عنصران منفصلان. المصدر: متطلبات التصديق الطبي لولاية تينيسي؛ tn.gov/safety."},"87":{"q":"كيف يجوز لحامل رخصة CDL في تينيسي أن يُقدّم إقرار تصديق ذاتي جديدًا وتصديقًا طبيًّا محدّثًا إلى الولاية؟","options":["عبر الرفع من خلال بوابة الخدمات الإلكترونية لوزارة السلامة أو بزيارة مركز خدمات السائقين","عبر إرساله بالبريد مباشرة إلى السجل الوطني لـ FMCSA","عبر إرساله بالبريد الإلكتروني إلى وزارة النقل بولاية تينيسي","بإعطائه للفاحص الطبي، الذي يُودِعه لدى كاتب المقاطعة"],"explanation":"يُقدّم حاملو رخص CDL في تينيسي إقرار التصديق الذاتي (والتصديق الطبي عند الطلب) عبر الرفع من خلال بوابة الخدمات الإلكترونية لوزارة السلامة أو شخصيًّا في مركز خدمات السائقين. المصدر: tn.gov/safety متطلبات التصديق الطبي."},"88":{"q":"يجب على حامل رخصة CDL في تينيسي تقديم تصديق طبي محدّث للإبقاء على الوضع حاليًّا عند أي نقطة بالنسبة لتاريخ انتهاء البطاقة الطبية؟","options":["قبل خمسة أيام عمل على الأقل من انتهاء التصديق الطبي الحالي","خلال 30 يومًا بعد أن تكون الشهادة قد انتهت فعلًا","مرة واحدة فقط كل ثماني سنوات عند تجديد الرخصة","خلال سنة واحدة بعد انتهاء الشهادة"],"explanation":"تُوجّه تينيسي حاملي رخص CDL إلى تقديم مستندات التصديق الذاتي/الطبي المحدّثة قبل خمسة (5) أيام عمل على الأقل من انتهاء التصديق الطبي الحالي لتجنّب التخفيض. المصدر: tn.gov/safety متطلبات التصديق الطبي."},"89":{"q":"متى يجب على جميع مقدّمي طلبات رخصة CDL الجدد في تينيسي إكمال تدريب السائقين المبتدئين (ELDT)؟","options":["قبل أداء اختبار مهارات رخصة CDL","فقط بعد أن تكون رخصة CDL قد أُصدِرت فعلًا","خلال سنة واحدة بعد اجتياز اختبار المهارات","فقط عند التقدّم للحصول على مصادقة HazMat"],"explanation":"منذ 7 فبراير 2022، يجب إكمال تدريب ELDT من مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل أن يتمكن مقدّم طلب الفئة A/B لأول مرة (وبعض مقدّمي طلبات المصادقات) من أداء اختبار المهارات/المعرفة. المصدر: tn.gov/safety صفحة ELDT؛ 49 CFR Part 380."},"90":{"q":"أين يجب أن يكون مزوّد تدريب ELDT الخاص بمقدّم طلب رخصة CDL في تينيسي مُدرَجًا حتى يُحتسَب التدريب؟","options":["في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","في قائمة المتعاقدين لوزارة النقل بولاية تينيسي","في سجل الأعمال لدى وزير خارجية ولاية تينيسي","في قائمة موردي الإدارة الوطنية لسلامة المرور على الطرق السريعة"],"explanation":"يجب أن يُقدَّم تدريب ELDT من جهة مُدرَجة في سجل مزوّدي التدريب (TPR) التابع للإدارة الفيدرالية لسلامة ناقلي المركبات. والتدريب من مزوّد غير مُدرَج لا يستوفي المتطلب. المصدر: tn.gov/safety ELDT؛ FMCSA TPR."},"91":{"q":"بعد إصدار تصريح CLP في تينيسي، كم يجب على الحامل أن ينتظر قبل أن يُسمح له بأداء اختبار مهارات رخصة CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"تتطلب القواعد الفيدرالية وقواعد تينيسي الاحتفاظ بتصريح CLP لمدة 14 يومًا كحد أدنى قبل أن يتمكن الحامل من أداء اختبار مهارات رخصة CDL. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 383.25."},"92":{"q":"يتكوّن اختبار مهارات رخصة CDL في تينيسي من أي ثلاثة أجزاء، بالترتيب؟","options":["فحص المركبة قبل الرحلة، ومهارات التحكم الأساسي بالمركبة، والقيادة على الطريق","فحص النظر، واختبار المعرفة، والركن الموازي","اختبار المكابح الهوائية، واختبار HazMat، والقيادة الليلية","اختبار تحريري، وفحص المخدرات، والقيادة على الطريق"],"explanation":"يتكوّن اختبار مهارات رخصة CDL في تينيسي من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار مهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق، كلها بهذا الترتيب. المصدر: دليل CDL لولاية تينيسي."},"93":{"q":"يؤدّي مقدّم الطلب في تينيسي اختبار مهارات رخصة CDL في مركبة تُمثّل ماذا؟","options":["فئة ونوع المركبة التي يعتزم مقدّم الطلب الترخيص لقيادتها","أي سيارة ركاب تُقدّمها الولاية","مركبة أصغر بفئة واحدة من الرخصة المطلوبة","شاحنة مستقيمة من الفئة C فقط بغضّ النظر عن الرخصة المطلوبة"],"explanation":"يجب أداء اختبار المهارات في مركبة تمثيلية من الفئة والتكوين اللذين تُطلب لهما رخصة CDL؛ والمركبة المستخدمة قد تَقصُر فئة الرخصة المُصدَرة. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 383.71/383.133."},"94":{"q":"بموجب المعيار الفيدرالي الذي تتبعه تينيسي، كم مدة صلاحية تصريح المتعلّم التجاري (CLP) قبل وجوب تجديده أو إعادة أداء اختبارات المعرفة؟","options":["180 يومًا، قابلة للتجديد مرة واحدة لمدة 180 يومًا إضافية","30 يومًا، دون السماح بأي تجديد","خمس سنوات، مطابقةً لرخصة عادية","90 يومًا، قابلة للتجديد حتى ثلاث مرات"],"explanation":"وفقًا لـ 49 CFR 383.25، الذي تطبّقه تينيسي، يكون تصريح CLP صالحًا لمدة 180 يومًا ويجوز تجديده مرة واحدة لمدة 180 يومًا إضافية دون إعادة أداء اختبار المعرفة العامة. المصدر: دليل CDL لولاية تينيسي؛ 49 CFR 383.25."},"95":{"q":"إذا انتهت صلاحية تصريح CLP الخاص بمقدّم الطلب في تينيسي قبل الحصول على رخصة CDL، فماذا يحدث للاختبارات المُكتمَلة؟","options":["يصبح اختبارا المعرفة والمهارات لاغيين ويجب إعادة أدائهما","يُفقَد اختبار المهارات فقط؛ وتبقى نتائج المعرفة صالحة لمدة خمس سنوات","لا شيء؛ فالنتائج دائمة بمجرد اجتيازها","تبقى الاختبارات صالحة لمدة سنة إضافية واحدة تلقائيًّا"],"explanation":"إذا انتهت صلاحية تصريح CLP قبل إصدار رخصة CDL الكاملة، يفقد مقدّم الطلب الاعتماد ويجب عليه إعادة أداء اختباري المعرفة والمهارات. المصدر: دليل CDL لولاية تينيسي؛ خدمات السائقين بولاية تينيسي."},"96":{"q":"ما دورة انتهاء الصلاحية القياسية لرخصة قيادة تجارية في تينيسي تُصدَر لشخص بالغ؟","options":["ثماني سنوات","أربع سنوات","عشر سنوات","سنتان"],"explanation":"رخص القيادة في تينيسي، بما في ذلك رخص CDL، تكون صالحة عمومًا لمدة ثماني سنوات (وفقًا لـ Tenn. Code Ann. 55-50-337)، وبعدها يجب تجديدها. المصدر: Tenn. Code Ann. 55-50-337؛ tn.gov/safety تجديد رخصتك."},"97":{"q":"كيف تُعالَج تجديدات رخص CDL في تينيسي عمومًا؟","options":["شخصيًّا في مركز خدمات السائقين، مع تقديم تصديق طبي حالي","بالكامل عبر الإنترنت دون مستندات مطلوبة","تلقائيًّا بالبريد دون أي إجراء من السائق","هاتفيًّا من خلال وزارة النقل"],"explanation":"تتم تجديدات رخص CDL في تينيسي شخصيًّا في مركز خدمات السائقين، ويجب أن يكون لدى الحامل تصديق طبي حالي في الملف عند التجديد. المصدر: tn.gov/safety تجديد رخصتك؛ متطلبات التصديق الطبي."},"98":{"q":"يخضع شخص عمره 19 عامًا ومؤهّل للحصول على رخصة CDL في تينيسي لأي قيد تشغيلي؟","options":["مُقيَّد بالتشغيل داخل الولاية (ضمن تينيسي) فقط","مُقيَّد بالمركبات التي يقل وزنها عن 26,001 رطلًا فقط","لا قيد؛ تُمنح امتيازات كاملة بين الولايات","مُقيَّد بالقيادة النهارية فقط"],"explanation":"يجب أن يكون مقدّمو طلبات رخص CDL في تينيسي بعمر 18 على الأقل؛ ومن هم دون 21 مُقيَّدون بالتشغيل داخل الولاية فقط. ويتطلب التشغيل بين الولايات (وHazMat) بلوغ سن 21. المصدر: دليل CDL لولاية تينيسي؛ tn.gov/safety خدمات السائقين."},"99":{"q":"بخصوص رسوم طلب واختبار رخصة CDL في تينيسي، أيُّ عبارة هي الأدق لدليل دراسي؟","options":["تُحدَّد الرسوم من قِبل وزارة السلامة وهي قابلة للتغيير، لذا ينبغي لمقدّمي الطلبات التحقق من المبالغ الحالية قبل التقديم","لا تفرض تينيسي أي رسوم من أي نوع لرخصة CDL","الرسم مُحدَّد بشكل دائم بموجب القانون الفيدرالي ولا يتغير أبدًا","تُحصَّل الرسوم فقط من قِبل جهة عمل مقدّم الطلب، ولا تُحصَّل أبدًا من قِبل الولاية"],"explanation":"الرسوم المتعلقة برخص CDL في تينيسي تُحدَّد من قِبل وزارة السلامة ويمكن أن تتغير بمرور الوقت؛ وينبغي لمقدّمي الطلبات التحقق من الجدول الحالي في مركز خدمات السائقين بدلًا من الاعتماد على مبلغ ثابت. المصدر: tn.gov/safety جدول رسوم خدمات السائقين."}}};
